import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import { CartItem } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [loading, setLoading] = useState(true);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<any>(null);
  const [bookingService, setBookingService] = useState<any>(null);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
    alert(`${item.name || item.title} added to your luxury bag!`);
  };

  const removeFromCart = (id: string) => {
    setCartItems(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  if (loading) {
    return (
      <div className="h-screen w-screen green-gradient flex flex-col items-center justify-center">
        <div className="relative">
          <div className="w-24 h-24 rounded-full border-2 border-[#F7E7CE]/20 border-t-[#F7E7CE] animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center font-bold text-2xl text-[#F7E7CE] serif">A</div>
        </div>
        <h1 className="mt-8 text-2xl font-bold tracking-[0.3em] text-[#F7E7CE] serif">ANEELA'S</h1>
        <p className="mt-2 text-[#F7E7CE]/60 text-xs animate-pulse italic uppercase tracking-[0.2em]">Perfection in Every Stroke</p>
      </div>
    );
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return <AdminPanel isFullPanel onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }} />;
  }

  const renderScreen = () => {
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={removeFromCart} onUpdateQty={updateQuantity} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={() => { setCartItems([]); setCheckoutItem(null); }} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} />;
      case 'services': return <ServicesScreen onBook={(s) => setBookingService(s)} />;
      case 'store': return <StoreScreen onAddToCart={addToCart} />;
      case 'viral': return <ViralScreen />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} />;
    }
  };

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      <Header onAdminTrigger={handleAdminTrigger} cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} onCartClick={() => setShowCart(true)} />
      <main className="flex-1 pb-24 pt-20 px-4 max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal">
        {renderScreen()}
      </main>
      {!checkoutItem && !bookingService && !showCart && (
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Bell, ShoppingBag, Search } from 'lucide-react';

interface HeaderProps {
  onAdminTrigger?: () => void;
  cartCount: number;
  onCartClick: () => void;
}

const Header: React.FC<HeaderProps> = ({ onAdminTrigger, cartCount, onCartClick }) => {
  const [tapCount, setTapCount] = useState(0);

  const handleLogoTap = () => {
    const newCount = tapCount + 1;
    setTapCount(newCount);
    if (newCount === 6) {
      onAdminTrigger?.();
      setTapCount(0);
    }
    setTimeout(() => setTapCount(0), 3000);
  };

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-[#0A2419]/90 backdrop-blur-xl z-50 flex items-center justify-between px-6 border-b border-[#F7E7CE]/10">
      <div className="flex items-center gap-3 cursor-pointer select-none" onClick={handleLogoTap}>
        <div className="w-9 h-9 rounded-full gold-gradient flex items-center justify-center font-bold text-[#0A2419] shadow-[0_0_15px_rgba(247,231,206,0.3)] serif">A</div>
        <div className="flex flex-col -gap-1">
          <h1 className="text-lg font-bold tracking-tight text-[#F7E7CE] serif leading-none">Aneela's</h1>
          <span className="text-[10px] text-[#F7E7CE]/60 uppercase tracking-[0.2em] font-medium">MakeOver</span>
        </div>
      </div>

      <div className="flex items-center gap-5">
        <button className="text-[#F3F3F3] hover:text-[#F7E7CE] transition-colors">
          <Search size={20} strokeWidth={1.5} />
        </button>
        <button 
          onClick={onCartClick}
          className="text-[#F3F3F3] hover:text-[#F7E7CE] transition-colors relative"
        >
          <ShoppingBag size={20} strokeWidth={1.5} />
          {cartCount > 0 && (
            <span className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-[#F7E7CE] text-[#0A2419] rounded-full text-[9px] font-bold flex items-center justify-center">
              {cartCount}
            </span>
          )}
        </button>
        <button className="text-[#F3F3F3] hover:text-[#F7E7CE] transition-colors relative">
          <Bell size={20} strokeWidth={1.5} />
          <span className="absolute top-0 right-0 w-1.5 h-1.5 bg-[#E1B84F] rounded-full"></span>
        </button>
      </div>
    </header>
  );
};

export default Header;

