import React from 'react';
import { ChevronLeft, Trash2, Plus, Minus, ShoppingBag } from 'lucide-react';
import { CartItem } from '../types';

interface CartScreenProps {
  items: CartItem[];
  onBack: () => void;
  onRemove: (id: string) => void;
  onUpdateQty: (id: string, delta: number) => void;
  onCheckout: () => void;
}

const CartScreen: React.FC<CartScreenProps> = ({ items, onBack, onRemove, onUpdateQty, onCheckout }) => {
  const total = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  if (items.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 animate-in fade-in">
        <div className="w-20 h-20 rounded-full bg-[#124C34] flex items-center justify-center mb-6">
          <ShoppingBag size={40} className="text-[#F7E7CE]/30" />
        </div>
        <h2 className="text-xl font-bold text-[#F7E7CE] serif mb-2">Your Bag is Empty</h2>
        <p className="text-[#F7E7CE]/60 text-sm mb-8">Discover perfection in our boutique.</p>
        <button onClick={onBack} className="btn-royal py-3 px-10 rounded-2xl text-xs">Explore Shop</button>
      </div>
    );
  }

  return (
    <div className="animate-in slide-in-from-right-10 duration-500 pb-10">
      <button onClick={onBack} className="flex items-center gap-2 text-[#F7E7CE]/60 mb-6 hover:text-[#F7E7CE] transition-colors">
        <ChevronLeft size={20} /> <span className="text-xs uppercase tracking-widest font-bold">Back to Studio</span>
      </button>

      <h2 className="text-2xl font-bold text-[#F7E7CE] serif mb-6">Your Luxury Bag</h2>

      <div className="space-y-4 mb-8">
        {items.map((item) => (
          <div key={item.id} className="glass-card p-4 rounded-3xl flex gap-4 border-white/5">
            <img src={item.image} className="w-20 h-20 object-cover rounded-2xl" alt="" />
            <div className="flex-1 flex flex-col justify-between">
              <div className="flex justify-between items-start">
                <div>
                  <h4 className="text-sm font-bold text-[#F3F3F3]">{item.name}</h4>
                  <p className="text-[10px] text-[#F7E7CE]/60 uppercase tracking-tighter mt-0.5">{item.type}</p>
                </div>
                <button onClick={() => onRemove(item.id)} className="text-red-400/60 hover:text-red-400 p-1">
                  <Trash2 size={16} />
                </button>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-[#F7E7CE] font-bold text-sm">Rs. {item.price}</span>
                <div className="flex items-center bg-[#0A2419] rounded-xl border border-white/5 p-1 gap-3">
                  <button onClick={() => onUpdateQty(item.id, -1)} className="w-6 h-6 flex items-center justify-center text-[#F7E7CE]"><Minus size={12} /></button>
                  <span className="text-xs font-bold w-4 text-center">{item.quantity}</span>
                  <button onClick={() => onUpdateQty(item.id, 1)} className="w-6 h-6 flex items-center justify-center text-[#F7E7CE]"><Plus size={12} /></button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="glass-card p-6 rounded-3xl border-[#F7E7CE]/20 bg-gradient-to-br from-[#124C34] to-[#0A2419]">
        <div className="space-y-3 mb-6">
          <div className="flex justify-between text-[#F7E7CE]/60 text-xs">
