            <span>Rs. {total}</span>
          </div>
          <div className="flex justify-between text-[#F7E7CE]/60 text-xs">
            <span>Service/Shipping</span>
            <span>Rs. 250</span>
          </div>
          <div className="flex justify-between text-[#F7E7CE] font-bold text-lg pt-3 border-t border-white/5">
            <span className="serif">Total</span>
            <span>Rs. {total + 250}</span>
