import React, { useState } from 'react';
import { LogIn, LayoutDashboard, Settings, ShoppingBag, Calendar, Video, BookOpen, Plus, Check, X, ArrowUpCircle } from 'lucide-react';

interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('dashboard');

  // Mock State for Admin Actions
  const [bookings, setBookings] = useState([
    { id: 1, name: 'Saba Khan', service: 'Signature Bridal', date: '24 Oct', status: 'Pending' },
    { id: 2, name: 'Amna Zaid', service: 'Walima Elegance', date: '26 Oct', status: 'Pending' },
  ]);
  const [orders, setOrders] = useState([
    { id: 101, name: 'Zoya Ali', item: 'Velvet Palette', total: '4500', status: 'Processing' },
  ]);

  const handleLogin = () => {
    if (password === 'A1234567890a') {
      onLogin?.();
    } else {
      setError('Invalid master credentials');
    }
  };

  const updateStatus = (id: number, type: 'booking' | 'order', status: string) => {
    if (type === 'booking') {
      setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
    } else {
      setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
    }
    alert(`${type} ${id} updated to ${status}`);
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8 animate-in fade-in duration-500">
        <div className="w-20 h-20 rounded-full gold-gradient flex items-center justify-center font-bold text-[#0A2419] text-2xl mb-8 shadow-[0_0_40px_rgba(247,231,206,0.4)] serif">A</div>
        <h2 className="text-2xl font-bold text-[#F7E7CE] mb-2 serif">Master Control</h2>
        <p className="text-[#F7E7CE]/60 text-sm mb-10 text-center italic tracking-widest">ANEELA'S MAKEOVER SECURITY</p>

        <div className="w-full space-y-5 max-w-xs">
          <input 
            type="password" 
            placeholder="Security Token" 
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full bg-[#124C34]/50 border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE] transition-all"
          />
          {error && <p className="text-red-400 text-[10px] text-center uppercase tracking-widest animate-pulse">{error}</p>}
          <button 
            onClick={handleLogin}
            className="w-full btn-royal py-4 rounded-2xl flex items-center justify-center gap-2 shadow-2xl"
          >
            <LogIn size={20} /> Authorize Access
          </button>
          <button onClick={onCancel} className="w-full text-[#F7E7CE]/40 py-2 text-[10px] font-bold uppercase tracking-[0.2em] hover:text-[#F7E7CE] transition-colors">Abort</button>
        </div>
      </div>
    );
  }

  const renderTabContent = () => {
    switch (activeTab) {
      case 'dashboard':
