import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import { CartItem } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [loading, setLoading] = useState(true);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<any>(null);
  const [bookingService, setBookingService] = useState<any>(null);

  // Placeholder for the uploaded logo - assuming 'logo.png' or a similar asset
  const LOGO_URL = "https://i.ibb.co/vz6mD2V/aneela-logo.png"; 

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 2500);
    return () => clearTimeout(timer);
  }, []);

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
    alert(`${item.name || item.title} added to your luxury bag!`);
  };

  const removeFromCart = (id: string) => {
    setCartItems(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  if (loading) {
    return (
      <div className="h-screen w-screen green-gradient flex flex-col items-center justify-center">
        <div className="relative mb-8">
          {/* Animated Spinner Border */}
          <div className="w-32 h-32 rounded-full border-2 border-[#F7E7CE]/10 border-t-[#F7E7CE] animate-spin"></div>
          {/* Logo with Fill Background in the center */}
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center p-4 shadow-[0_0_30px_rgba(247,231,206,0.2)] animate-pulse">
              <img src={LOGO_URL} alt="Logo" className="w-full h-auto object-contain" />
            </div>
          </div>
        </div>
        <h1 className="text-2xl font-bold tracking-[0.3em] text-[#F7E7CE] serif uppercase">ANEELA'S</h1>
        <p className="mt-2 text-[#F7E7CE]/60 text-xs italic uppercase tracking-[0.4em]">Perfection in Every Stroke</p>
      </div>
    );
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel logoUrl={LOGO_URL} onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return <AdminPanel logoUrl={LOGO_URL} isFullPanel onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }} />;
  }

  const renderScreen = () => {
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={removeFromCart} onUpdateQty={updateQuantity} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={() => { setCartItems([]); setCheckoutItem(null); }} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} />;
      case 'services': return <ServicesScreen onBook={(s) => setBookingService(s)} />;
      case 'store': return <StoreScreen onAddToCart={addToCart} />;
      case 'viral': return <ViralScreen />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} />;
    }
  };

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      <Header 
        logoUrl={LOGO_URL}
        onAdminTrigger={handleAdminTrigger} 
        cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} 
        onCartClick={() => setShowCart(true)} 
      />
      <main className="flex-1 pb-24 pt-20 px-4 max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal">
        {renderScreen()}
      </main>
      {!checkoutItem && !bookingService && !showCart && (
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      )}
    </div>
  );
};

export default App;

