interface HeaderProps {
  onAdminTrigger?: () => void;
  cartCount: number;
  onCartClick: () => void;
  logoUrl: string;
}

const Header: React.FC<HeaderProps> = ({ onAdminTrigger, cartCount, onCartClick, logoUrl }) => {
