  }, []);

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
  };

  if (loading) {
    return (
      <div className="h-screen w-screen green-gradient flex flex-col items-center justify-center">
        <div className="relative mb-8">
          <div className="w-32 h-32 rounded-full border-2 border-[#F7E7CE]/10 border-t-[#F7E7CE] animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center p-4 shadow-[0_0_30px_rgba(247,231,206,0.2)]">
              <img src={LOGO_URL} alt="Logo" className="w-full h-auto object-contain" />
            </div>
          </div>
        </div>
        <h1 className="text-2xl font-bold tracking-[0.3em] text-[#F7E7CE] serif uppercase">ANEELA'S</h1>
        <p className="mt-2 text-[#F7E7CE]/60 text-xs italic uppercase tracking-[0.4em]">Perfection in Every Stroke</p>
      </div>
    );
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel logoUrl={LOGO_URL} onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return (
      <AdminPanel 
        logoUrl={LOGO_URL} 
        isFullPanel 
        onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }}
        data={{ services, products, courses, videos, gallery }}
        setters={{ setServices, setProducts, setCourses, setVideos, setGallery }}
      />
    );
  }

  const renderScreen = () => {
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={(id) => setCartItems(p => p.filter(i => i.id !== id))} onUpdateQty={(id, d) => setCartItems(p => p.map(i => i.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={() => { setCartItems([]); setCheckoutItem(null); }} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} />;
    if (selectedServiceDetail) return <ServiceDetailScreen service={selectedServiceDetail} onBack={() => setSelectedServiceDetail(null)} onBook={(s) => { setSelectedServiceDetail(null); setBookingService(s); }} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} />;
      case 'services': return <ServicesScreen services={services} onBook={(s) => setBookingService(s)} onViewDetails={(s) => setSelectedServiceDetail(s)} />;
      case 'store': return <StoreScreen products={products} courses={courses} onAddToCart={addToCart} />;
      case 'viral': return <ViralScreen videos={videos} gallery={gallery} />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen gallery={gallery} />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} />;
    }
  };

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      <Header 
        logoUrl={LOGO_URL}
        onAdminTrigger={handleAdminTrigger} 
        cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} 
        onCartClick={() => setShowCart(true)} 
      />
      <main className="flex-1 pb-24 pt-20 px-4 max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal">
        {renderScreen()}
      </main>
      {!checkoutItem && !bookingService && !showCart && !selectedServiceDetail && (
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { LogIn, LayoutDashboard, Settings, ShoppingBag, Calendar, Video, BookOpen, Check, X, ArrowUpCircle, Trash2, Plus, Edit2, Image } from 'lucide-react';
import { Service, Product, Course, VideoItem, GalleryItem } from '../types';

interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
  logoUrl?: string;
  data?: {
    services: Service[];
    products: Product[];
    courses: Course[];
    videos: VideoItem[];
    gallery: GalleryItem[];
  };
  setters?: {
    setServices: React.Dispatch<React.SetStateAction<Service[]>>;
    setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
    setCourses: React.Dispatch<React.SetStateAction<Course[]>>;
    setVideos: React.Dispatch<React.SetStateAction<VideoItem[]>>;
    setGallery: React.Dispatch<React.SetStateAction<GalleryItem[]>>;
  };
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel, logoUrl, data, setters }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('services');

  const handleLogin = () => {
    if (password === 'A1234567890a') onLogin?.();
    else setError('Invalid credentials');
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8 animate-in fade-in duration-500">
        <div className="w-24 h-24 bg-white rounded-3xl flex items-center justify-center p-4 mb-8 shadow-[0_15px_40px_rgba(0,0,0,0.5)]">
          <img src={logoUrl} alt="Logo" className="w-full h-auto object-contain" />
        </div>
        <h2 className="text-2xl font-bold text-[#F7E7CE] mb-2 serif">Master Control</h2>
        <div className="w-full space-y-5 max-w-xs">
          <input type="password" placeholder="Security Token" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-[#124C34]/50 border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE]" />
          {error && <p className="text-red-400 text-xs text-center">{error}</p>}
          <button onClick={handleLogin} className="w-full btn-royal py-4 rounded-2xl flex items-center justify-center gap-2">Authorize Access</button>
          <button onClick={onCancel} className="w-full text-[#F7E7CE]/40 py-2 text-xs">Abort</button>
        </div>
      </div>
    );
  }

  const renderManager = (title: string, list: any[], onAdd: () => void, onEdit: (item: any) => void, onDelete: (id: string) => void) => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-widest">{title}</h3>
        <button onClick={onAdd} className="bg-[#F7E7CE] text-[#0A2419] p-2 rounded-full shadow-lg"><Plus size={16} /></button>
      </div>
      <div className="space-y-3">
        {list.map((item) => (
          <div key={item.id} className="glass-card p-4 rounded-2xl border-white/5 flex items-center gap-4">
            <img src={item.image || item.thumbnail || item.after} className="w-12 h-12 rounded-xl object-cover" alt="" />
            <div className="flex-1">
              <p className="text-xs font-bold text-[#F3F3F3]">{item.name || item.title}</p>
              <p className="text-[10px] text-[#F7E7CE]/60">ID: {item.id}</p>
