              <button onClick={() => onEdit(item)} className="p-2 text-[#F7E7CE]/60 hover:text-[#F7E7CE]"><Edit2 size={14} /></button>
              <button onClick={() => onDelete(item.id)} className="p-2 text-red-400/60 hover:text-red-400"><Trash2 size={14} /></button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-16 border-b border-[#F7E7CE]/10 flex items-center justify-between px-6 bg-[#124C34]/30 backdrop-blur-xl">
        <div className="flex items-center gap-3">
          <div className="bg-white p-1 rounded-lg"><img src={logoUrl} alt="Logo" className="h-6" /></div>
          <h1 className="font-bold text-[#F7E7CE] text-xs serif uppercase tracking-widest">Admin Control</h1>
        </div>
        <button onClick={onLogout} className="text-red-400 text-[10px] font-bold py-1 px-4 rounded-full border border-red-400/20">LOGOUT</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar">
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-8 py-2">
          {['services', 'products', 'courses', 'reels', 'gallery'].map((t) => (
            <button key={t} onClick={() => setActiveTab(t)} className={`px-5 py-2.5 rounded-2xl text-[10px] font-bold uppercase tracking-widest transition-all ${activeTab === t ? 'bg-[#F7E7CE] text-[#0A2419] shadow-lg' : 'bg-[#124C34]/40 text-[#F7E7CE]/40'}`}>{t}</button>
          ))}
        </div>

        {activeTab === 'services' && renderManager('Salon Services', data?.services || [], () => {
          const name = prompt('Service Name?');
          if (name && setters) setters.setServices(p => [...p, { id: Date.now().toString(), name, description: 'New description', price: 5000, duration: '1h', category: 'Makeup', image: 'https://images.unsplash.com/photo-1594465919760-441fe5908ab0?q=80&w=800&auto=format&fit=crop' }]);
        }, (item) => {
          const newPrice = prompt('New Price?', item.price.toString());
          if (newPrice && setters) setters.setServices(p => p.map(s => s.id === item.id ? {...s, price: Number(newPrice)} : s));
        }, (id) => setters?.setServices(p => p.filter(s => s.id !== id)))}

        {activeTab === 'products' && renderManager('Boutique Products', data?.products || [], () => {
          const name = prompt('Product Name?');
          if (name && setters) setters.setProducts(p => [...p, { id: Date.now().toString(), name, price: 1000, description: 'New product', image: 'https://images.unsplash.com/photo-1512496015851-a90fb38ba796?q=80&w=400&auto=format&fit=crop', category: 'Makeup' }]);
        }, (item) => {
          const newName = prompt('New Name?', item.name);
          if (newName && setters) setters.setProducts(p => p.map(s => s.id === item.id ? {...s, name: newName} : s));
        }, (id) => setters?.setProducts(p => p.filter(s => s.id !== id)))}

        {activeTab === 'reels' && renderManager('Viral Media', data?.videos || [], () => {
          const title = prompt('Reel Title?');
          const url = prompt('Video/Image URL?');
          if (title && setters) setters.setVideos(p => [...p, { id: Date.now().toString(), title, url: url || '', thumbnail: url || '', likes: 0, type: url?.endsWith('.mp4') ? 'video' : 'image' }]);
        }, (item) => {
          const newTitle = prompt('New Title?', item.title);
          if (newTitle && setters) setters.setVideos(p => p.map(s => s.id === item.id ? {...s, title: newTitle} : s));
        }, (id) => setters?.setVideos(p => p.filter(s => s.id !== id)))}

        {activeTab === 'gallery' && renderManager('Gallery Art', data?.gallery || [], () => {
          const title = prompt('Gallery Item Title?');
          if (title && setters) setters.setGallery(p => [...p, { id: Date.now().toString(), title, before: 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=400&h=600&auto=format&fit=crop', after: 'https://images.unsplash.com/photo-1522337360788-8b13dee7a37e?q=80&w=400&h=600&auto=format&fit=crop' }]);
        }, (item) => {}, (id) => setters?.setGallery(p => p.filter(s => s.id !== id)))}

        {activeTab === 'courses' && renderManager('Academy Courses', data?.courses || [], () => {
          const title = prompt('Course Title?');
          if (title && setters) setters.setCourses(p => [...p, { id: Date.now().toString(), title, price: 10000, duration: '1 Month', description: 'Course', image: 'https://images.unsplash.com/photo-1522337660859-02fbefca4702?q=80&w=800&auto=format&fit=crop', level: 'Beginner' }]);
        }, (item) => {}, (id) => setters?.setCourses(p => p.filter(s => s.id !== id)))}
      </div>
    </div>
  );
};

