import { GoogleGenAI, Type } from "@google/genai";

// Fixed: Corrected GoogleGenAI initialization to use named parameter and direct process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMakeupAdvice = async (userDescription: string, photoBase64?: string) => {
  try {
    const model = 'gemini-3-flash-preview';
    const contents = photoBase64 
      ? {
          parts: [
            { text: `Analyze this person's facial features and suggest the best makeup style for a ${userDescription}. Be encouraging and professional as a luxury salon consultant.` },
            { inlineData: { mimeType: 'image/jpeg', data: photoBase64 } }
          ]
        }
      : `Suggest a luxury makeup style for a client looking for: ${userDescription}. Mention specific techniques like contouring or eye shadow shades.`;

    const response = await ai.models.generateContent({
      model,
      contents,
      config: {
        systemInstruction: "You are Aneela, a world-class luxury makeup artist and consultant for 'Aneelas MakeOver'. Your tone is premium, warm, and highly professional. You focus on perfection and 'every stroke' being intentional.",
      }
    });

    return response.text || "I'm having trouble seeing your beauty clearly right now. Let's try again in a moment.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "The beauty consultant is currently busy. Please try again shortly.";
  }
};

export const parseVoiceCommand = async (transcript: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `The user said: "${transcript}". Identify if they want to book a service, see the academy, or view the gallery. Return a simple JSON with 'intent' and 'params'.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            intent: { type: Type.STRING, description: 'One of: BOOK_SERVICE, VIEW_ACADEMY, VIEW_GALLERY, HELP' },
            serviceType: { type: Type.STRING, description: 'The service name if applicable' }
          }
        }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (e) {
    return { intent: 'HELP' };
  }
};

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import ServiceDetailScreen from './screens/ServiceDetailScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import { MOCK_SERVICES, MOCK_PRODUCTS, MOCK_COURSES, MOCK_VIDEOS, MOCK_GALLERY } from './constants';
import { CartItem, Service, Product, Course, VideoItem, GalleryItem } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [loading, setLoading] = useState(true);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<any>(null);
  const [bookingService, setBookingService] = useState<Service | null>(null);
  const [selectedServiceDetail, setSelectedServiceDetail] = useState<Service | null>(null);

  // Editable Collections State
  const [services, setServices] = useState<Service[]>(MOCK_SERVICES);
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [courses, setCourses] = useState<Course[]>(MOCK_COURSES);
  // Fixed: Removed redundant type mapping since MOCK_VIDEOS items now include 'type'
  const [videos, setVideos] = useState<VideoItem[]>(MOCK_VIDEOS);
  const [gallery, setGallery] = useState<GalleryItem[]>(MOCK_GALLERY);

  const LOGO_URL = "https://i.ibb.co/vz6mD2V/aneela-logo.png"; 

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
  };

  if (loading) {
    return (
      <div className="h-screen w-screen green-gradient flex flex-col items-center justify-center">
        <div className="relative mb-8">
          <div className="w-32 h-32 rounded-full border-2 border-[#F7E7CE]/10 border-t-[#F7E7CE] animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center p-4 shadow-[0_0_30px_rgba(247,231,206,0.2)]">
              <img src={LOGO_URL} alt="Logo" className="w-full h-auto object-contain" />
            </div>
          </div>
        </div>
        <h1 className="text-2xl font-bold tracking-[0.3em] text-[#F7E7CE] serif uppercase">ANEELA'S</h1>
        <p className="mt-2 text-[#F7E7CE]/60 text-xs italic uppercase tracking-[0.4em]">Perfection in Every Stroke</p>
      </div>
    );
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel logoUrl={LOGO_URL} onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return (
      <AdminPanel 
        logoUrl={LOGO_URL} 
        isFullPanel 
        onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }}
        data={{ services, products, courses, videos, gallery }}
        setters={{ setServices, setProducts, setCourses, setVideos, setGallery }}
      />
    );
  }

  const renderScreen = () => {
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={(id) => setCartItems(p => p.filter(i => i.id !== id))} onUpdateQty={(id, d) => setCartItems(p => p.map(i => i.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={() => { setCartItems([]); setCheckoutItem(null); }} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} />;
    if (selectedServiceDetail) return <ServiceDetailScreen service={selectedServiceDetail} onBack={() => setSelectedServiceDetail(null)} onBook={(s) => { setSelectedServiceDetail(null); setBookingService(s); }} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} />;
      case 'services': return <ServicesScreen services={services} onBook={(s) => setBookingService(s)} onViewDetails={(s) => setSelectedServiceDetail(s)} />;
      case 'store': return <StoreScreen products={products} courses={courses} onAddToCart={addToCart} />;
      case 'viral': return <ViralScreen videos={videos} gallery={gallery} />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen gallery={gallery} />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} />;
    }
  };

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      <Header 
        logoUrl={LOGO_URL}
        onAdminTrigger={handleAdminTrigger} 
        cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} 
        onCartClick={() => setShowCart(true)} 
      />
      <main className="flex-1 pb-24 pt-20 px-4 max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal">
        {renderScreen()}
      </main>
      {!checkoutItem && !bookingService && !showCart && !selectedServiceDetail && (
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      )}
    </div>
  );
};

export default App;

