                  if (val && setters) {
                    if (type === 'Service') setters.setServices(p => p.map(i => i.id === item.id ? {...i, name: val} : i));
                    if (type === 'Product') setters.setProducts(p => p.map(i => i.id === item.id ? {...i, name: val} : i));
                    if (type === 'Course') setters.setCourses(p => p.map(i => i.id === item.id ? {...i, title: val} : i));
                    if (type === 'Reel') setters.setVideos(p => p.map(i => i.id === item.id ? {...i, title: val} : i));
                    if (type === 'Gallery') setters.setGallery(p => p.map(i => i.id === item.id ? {...i, title: val} : i));
                  }
                }}
                className="p-2.5 bg-white/5 rounded-xl text-[#F7E7CE]/60"
              >
                <Edit2 size={16} />
              </button>
              <button 
                onClick={() => {
                  if (confirm('Delete this artifact?')) {
                    if (type === 'Service') setters?.setServices(p => p.filter(i => i.id !== item.id));
                    if (type === 'Product') setters?.setProducts(p => p.filter(i => i.id !== item.id));
                    if (type === 'Course') setters?.setCourses(p => p.filter(i => i.id !== item.id));
                    if (type === 'Reel') setters?.setVideos(p => p.filter(i => i.id !== item.id));
                    if (type === 'Gallery') setters?.setGallery(p => p.filter(i => i.id !== item.id));
                  }
                }}
                className="p-2.5 bg-red-400/10 rounded-xl text-red-400/60"
              >
                <Trash2 size={16} />
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-20 border-b border-[#F7E7CE]/10 flex items-center justify-between px-8 bg-[#124C34]/30 backdrop-blur-3xl sticky top-0 z-[110]">
        <Logo size="sm" />
        <div className="flex items-center gap-4">
          <span className="text-[10px] text-[#F7E7CE]/40 font-bold uppercase tracking-widest hidden sm:block">Admin Mode Active</span>
          <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 hover:bg-red-400/10 uppercase tracking-[0.2em] transition-all">Sign Out</button>
        </div>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-10">
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-12 py-3">
          {[
            { id: 'bookings', icon: <Calendar size={14} />, label: 'Bookings' },
            { id: 'orders', icon: <ShoppingBag size={14} />, label: 'Orders' },
            { id: 'services', icon: <Edit2 size={14} />, label: 'Services' },
            { id: 'products', icon: <PackageCheck size={14} />, label: 'Inventory' },
            { id: 'courses', icon: <BookOpen size={14} />, label: 'Academy' },
            { id: 'reels', icon: <Video size={14} />, label: 'Reels' },
            { id: 'gallery', icon: <Edit2 size={14} />, label: 'Gallery' },
          ].map((t) => (
            <button 
              key={t.id} 
              onClick={() => setActiveTab(t.id)} 
              className={`px-6 py-3.5 rounded-2xl text-[10px] font-extrabold uppercase tracking-[0.2em] transition-all whitespace-nowrap flex items-center gap-2 ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419] shadow-2xl scale-105' : 'bg-[#124C34]/40 text-[#F7E7CE]/50 border border-white/5'}`}
            >
              {t.icon} {t.label}
            </button>
          ))}
        </div>

        {activeTab === 'bookings' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Client Appointments</h3>
