interface CheckoutScreenProps {
  item: CartItem[];
  onBack: () => void;
  onComplete: (order: Order) => void;
}

const CheckoutScreen: React.FC<CheckoutScreenProps> = ({ item, onBack, onComplete }) => {
  const [method, setMethod] = useState<'EasyPaisa' | 'JazzCash' | 'Stripe'>('EasyPaisa');
