import React, { useState } from 'react';
import { ShoppingBag, Calendar, Video, BookOpen, Plus, Edit2, Trash2, CheckCircle2, XCircle, Truck, PackageCheck, UserCircle2, Image as ImageIcon, Save, X } from 'lucide-react';
import { Service, Product, Course, VideoItem, GalleryItem, Appointment, Order } from '../types';
import Logo from '../components/Logo';

interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
  data?: {
    services: Service[];
    products: Product[];
    courses: Course[];
    videos: VideoItem[];
    gallery: GalleryItem[];
    bookings: Appointment[];
    orders: Order[];
  };
  setters?: {
    setServices: React.Dispatch<React.SetStateAction<Service[]>>;
    setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
    setCourses: React.Dispatch<React.SetStateAction<Course[]>>;
    setVideos: React.Dispatch<React.SetStateAction<VideoItem[]>>;
    setGallery: React.Dispatch<React.SetStateAction<GalleryItem[]>>;
    setBookings: React.Dispatch<React.SetStateAction<Appointment[]>>;
    setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  };
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel, data, setters }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('bookings');

  // Edit State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editBuffer, setEditBuffer] = useState<any>(null);

  const handleLogin = () => {
    if (password === 'A1234567890a') onLogin?.();
    else setError('Security Clearance Failure');
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8">
        <div className="mb-12 animate-royal">
          <Logo size="xl" />
        </div>
        <div className="w-full glass-card p-10 rounded-[3rem] border-[#F7E7CE]/20 shadow-2xl max-w-sm">
          <h2 className="text-xl font-bold text-[#F7E7CE] mb-8 serif text-center uppercase tracking-widest">Command Center Login</h2>
          <div className="space-y-6">
            <input 
              type="password" 
              placeholder="Authorization Key" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full bg-[#0A2419] border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE] transition-all" 
            />
            {error && <p className="text-red-400 text-[10px] text-center uppercase font-bold tracking-[0.2em]">{error}</p>}
            <button onClick={handleLogin} className="w-full btn-royal py-5 rounded-2xl flex items-center justify-center gap-2">Verify Credential</button>
            <button onClick={onCancel} className="w-full text-[#F7E7CE]/30 py-2 text-[10px] font-bold uppercase tracking-[0.3em]">Abort Mission</button>
          </div>
        </div>
      </div>
    );
  }

  const startEditing = (item: any) => {
    setEditingId(item.id);
    setEditBuffer({ ...item });
  };

  const saveEdit = (type: string) => {
    if (!setters || !editBuffer) return;

    const update = (prev: any[]) => prev.map(i => i.id === editingId ? editBuffer : i);

    if (type === 'Service') setters.setServices(update);
    if (type === 'Product') setters.setProducts(update);
    if (type === 'Course') setters.setCourses(update);
    if (type === 'Reel') setters.setVideos(update);
    if (type === 'Gallery') setters.setGallery(update);

    setEditingId(null);
    setEditBuffer(null);
  };

  const addItem = (type: string) => {
    if (!setters) return;
    const id = Date.now().toString();
    const commonImg = "https://images.unsplash.com/photo-1594465919760-441fe5908ab0";

    if (type === 'Service') {
      const name = prompt("Service Name?");
      if (name) setters.setServices(p => [...p, { id, name, description: 'Premium Service', price: 5000, duration: '1h', category: 'Makeup', image: commonImg }]);
    }
    if (type === 'Product') {
      const name = prompt("Product Name?");
      if (name) setters.setProducts(p => [...p, { id, name, price: 1000, description: 'Luxury Item', image: commonImg, category: 'Makeup' }]);
    }
    if (type === 'Course') {
      const title = prompt("Course Title?");
      if (title) setters.setCourses(p => [...p, { id, title, duration: '1 Month', price: 15000, description: 'Masterclass', image: commonImg, level: 'Beginner' }]);
    }
    if (type === 'Reel') {
      const title = prompt("Reel Title?");
      if (title) setters.setVideos(p => [...p, { id, title, url: '#', thumbnail: commonImg, likes: 0, type: 'video' }]);
    }
    if (type === 'Gallery') {
      const title = prompt("Gallery Title?");
      if (title) setters.setGallery(p => [...p, { id, title, before: commonImg, after: commonImg }]);
    }
  };

  const renderGenericList = (title: string, list: any[], type: string) => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif">{title}</h3>
        <button onClick={() => addItem(type)} className="bg-[#F7E7CE] text-[#0A2419] p-3 rounded-full shadow-lg active:scale-90 transition-transform"><Plus size={20} /></button>
      </div>
      <div className="space-y-4">
        {list.map((item) => (
          <div key={item.id} className="glass-card p-5 rounded-[2rem] border-white/5 glow-gold">
            {editingId === item.id ? (
              <div className="space-y-4">
                <input 
                  className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-3 text-xs" 
                  value={editBuffer.name || editBuffer.title} 
                  onChange={(e) => setEditBuffer({...editBuffer, [item.name ? 'name' : 'title']: e.target.value})} 
                  placeholder="Name/Title"
                />
                <div className="flex gap-2">
                  <input 
                    className="flex-1 bg-[#0A2419] border border-white/10 rounded-xl p-3 text-xs" 
                    value={editBuffer.price} 
                    type="number"
                    onChange={(e) => setEditBuffer({...editBuffer, price: Number(e.target.value)})} 
                    placeholder="Price"
                  />
                  <input 
                    className="flex-1 bg-[#0A2419] border border-white/10 rounded-xl p-3 text-xs" 
                    value={editBuffer.category || editBuffer.level || ''} 
                    onChange={(e) => setEditBuffer({...editBuffer, [item.category ? 'category' : 'level']: e.target.value})} 
                    placeholder="Cat/Level"
                  />
                </div>
                <textarea 
                  className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-3 text-xs h-20" 
                  value={editBuffer.description} 
                  onChange={(e) => setEditBuffer({...editBuffer, description: e.target.value})} 
                  placeholder="Description"
                />
                <div className="flex gap-2">
                  <button onClick={() => saveEdit(type)} className="flex-1 bg-green-500 text-white py-3 rounded-xl text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-2"><Save size={14}/> Save</button>
                  <button onClick={() => setEditingId(null)} className="flex-1 bg-red-500 text-white py-3 rounded-xl text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-2"><X size={14}/> Cancel</button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-5">
                <img src={item.image || item.thumbnail || item.after} className="w-16 h-16 rounded-2xl object-cover border border-white/10" alt="" />
                <div className="flex-1">
                  <p className="text-xs font-bold text-white serif tracking-wide">{item.name || item.title}</p>
                  <p className="text-[9px] text-[#F7E7CE]/40 mt-1 uppercase tracking-widest">Rs. {item.price?.toLocaleString() || 'N/A'}</p>
                </div>
                <div className="flex gap-1">
                  <button onClick={() => startEditing(item)} className="p-2.5 bg-white/5 rounded-xl text-[#F7E7CE]/60"><Edit2 size={16} /></button>
                  <button onClick={() => { if(confirm('Delete?')) setters && (type === 'Service' ? setters.setServices(p => p.filter(i => i.id !== item.id)) : type === 'Product' ? setters.setProducts(p => p.filter(i => i.id !== item.id)) : type === 'Course' ? setters.setCourses(p => p.filter(i => i.id !== item.id)) : type === 'Reel' ? setters.setVideos(p => p.filter(i => i.id !== item.id)) : setters.setGallery(p => p.filter(i => i.id !== item.id))) }} className="p-2.5 bg-red-400/10 rounded-xl text-red-400/60"><Trash2 size={16} /></button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-20 border-b border-[#F7E7CE]/10 flex items-center justify-between px-8 bg-[#124C34]/30 backdrop-blur-3xl sticky top-0 z-[110]">
        <Logo size="sm" />
        <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 hover:bg-red-400/10 uppercase tracking-[0.2em]">Sign Out</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-10">
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-12 py-3">
          {[
            { id: 'bookings', icon: <Calendar size={14} />, label: 'Bookings' },
            { id: 'orders', icon: <ShoppingBag size={14} />, label: 'Orders' },
            { id: 'services', icon: <Edit2 size={14} />, label: 'Services' },
            { id: 'products', icon: <PackageCheck size={14} />, label: 'Inventory' },
            { id: 'courses', icon: <BookOpen size={14} />, label: 'Academy' },
            { id: 'reels', icon: <Video size={14} />, label: 'Reels' },
            { id: 'gallery', icon: <ImageIcon size={14} />, label: 'Gallery' },
          ].map((t) => (
            <button 
              key={t.id} 
              onClick={() => {setActiveTab(t.id); setEditingId(null);}} 
              className={`px-6 py-3.5 rounded-2xl text-[10px] font-extrabold uppercase tracking-[0.2em] transition-all whitespace-nowrap flex items-center gap-2 ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419] shadow-2xl scale-105' : 'bg-[#124C34]/40 text-[#F7E7CE]/50 border border-white/5'}`}
            >
              {t.icon} {t.label}
            </button>
          ))}
        </div>

        {activeTab === 'bookings' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Appointments</h3>
            {data?.bookings.map(book => (
              <div key={book.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h4 className="text-lg font-bold text-white serif">{book.serviceName}</h4>
                    <p className="text-[10px] text-[#F7E7CE]/60 mt-1 uppercase tracking-widest">{book.clientName} • {book.phone}</p>
                  </div>
                  <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest ${book.status === 'Accepted' ? 'bg-green-400 text-[#0A2419]' : book.status === 'Rejected' ? 'bg-red-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{book.status}</span>
                </div>
                {book.status === 'Pending' && (
                  <div className="flex gap-3 mt-4">
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Accepted'} : b))} className="flex-1 bg-green-500/20 text-green-400 py-3 rounded-xl text-[10px] font-bold flex items-center justify-center gap-2 uppercase tracking-widest"><CheckCircle2 size={14}/> Accept</button>
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Rejected'} : b))} className="flex-1 bg-red-500/20 text-red-400 py-3 rounded-xl text-[10px] font-bold flex items-center justify-center gap-2 uppercase tracking-widest"><XCircle size={14}/> Reject</button>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Operational Orders</h3>
            {data?.orders.map(order => (
              <div key={order.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-4">
                  <h4 className="text-[10px] font-black text-[#F7E7CE] uppercase tracking-widest">Order #{order.id.slice(-6)}</h4>
                  <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest ${order.status === 'Shipped' ? 'bg-blue-400 text-[#0A2419]' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{order.status}</span>
                </div>
                <p className="text-lg font-bold text-white serif mb-1">{order.clientName}</p>
                <p className="text-[9px] text-white/50 mb-6 italic"><Truck size={12} className="inline mr-1"/> {order.address}</p>
                {order.status === 'Pending' && (
                  <button onClick={() => setters?.setOrders(p => p.map(o => o.id === order.id ? {...o, status: 'Shipped'} : o))} className="w-full btn-royal py-4 rounded-xl text-[10px] flex items-center justify-center gap-2 uppercase tracking-widest">Dispatch Package <Truck size={16}/></button>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'services' && renderGenericList('Salon Services', data?.services || [], 'Service')}
        {activeTab === 'products' && renderGenericList('Cosmetic Boutique', data?.products || [], 'Product')}
        {activeTab === 'courses' && renderGenericList('Artistry Academy', data?.courses || [], 'Course')}
        {activeTab === 'reels' && renderGenericList('Cinematic Reels', data?.videos || [], 'Reel')}
        {activeTab === 'gallery' && renderGenericList('Gallery Archive', data?.gallery || [], 'Gallery')}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import Logo from './components/Logo';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import ServiceDetailScreen from './screens/ServiceDetailScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import { MOCK_SERVICES, MOCK_PRODUCTS, MOCK_COURSES, MOCK_VIDEOS, MOCK_GALLERY } from './constants';
import { CartItem, Service, Product, Course, VideoItem, GalleryItem, Appointment, Order } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [loading, setLoading] = useState(true);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<CartItem[] | null>(null);
  const [bookingService, setBookingService] = useState<Service | null>(null);
  const [selectedServiceDetail, setSelectedServiceDetail] = useState<Service | null>(null);

  // Business Data State
  const [services, setServices] = useState<Service[]>(MOCK_SERVICES);
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [courses, setCourses] = useState<Course[]>(MOCK_COURSES);
  const [videos, setVideos] = useState<VideoItem[]>(MOCK_VIDEOS);
  const [gallery, setGallery] = useState<GalleryItem[]>(MOCK_GALLERY);

  // Operational Data State
  const [bookings, setBookings] = useState<Appointment[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 3000);
    return () => clearTimeout(timer);
  }, []);

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
  };

  const handleBookingConfirm = (appointment: Appointment) => {
    setBookings(prev => [appointment, ...prev]);
  };

  const handleOrderConfirm = (order: Order) => {
    setOrders(prev => [order, ...prev]);
    setCartItems([]);
  };

  if (loading) {
    return (
      <div className="h-screen w-screen bg-[#0A2419] flex flex-col items-center justify-center relative overflow-hidden">
        {/* Cinematic Shimmer Background */}
        <div className="absolute inset-0 opacity-20">
          <div className="absolute top-[-20%] left-[-20%] w-[60%] h-[60%] bg-[#F7E7CE] rounded-full blur-[150px] animate-pulse"></div>
          <div className="absolute bottom-[-20%] right-[-20%] w-[60%] h-[60%] bg-[#F7E7CE] rounded-full blur-[150px] animate-pulse delay-1000"></div>
        </div>

        <div className="relative z-10 transform scale-125 animate-royal">
           <Logo size="xl" />
        </div>

        <div className="mt-24 w-64 h-0.5 bg-white/5 rounded-full overflow-hidden relative">
          <div className="absolute top-0 left-0 h-full gold-gradient animate-[progress_3s_ease-in-out_infinite]" style={{ width: '100%' }}></div>
        </div>

        <div className="mt-10 text-[#F7E7CE] text-[10px] font-bold tracking-[0.8em] uppercase flex flex-col items-center gap-3">
           <span className="animate-pulse">Curating Perfection</span>
           <div className="flex gap-1.5">
             <div className="w-1.5 h-1.5 bg-[#F7E7CE] rounded-full animate-bounce [animation-delay:-0.3s]"></div>
             <div className="w-1.5 h-1.5 bg-[#F7E7CE] rounded-full animate-bounce [animation-delay:-0.15s]"></div>
             <div className="w-1.5 h-1.5 bg-[#F7E7CE] rounded-full animate-bounce"></div>
           </div>
        </div>

        <style>{`
          @keyframes progress {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(100%); }
          }
        `}</style>
      </div>
    );
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return (
      <AdminPanel 
        isFullPanel 
        onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }}
        data={{ services, products, courses, videos, gallery, bookings, orders }}
        setters={{ setServices, setProducts, setCourses, setVideos, setGallery, setBookings, setOrders }}
      />
    );
  }

  const renderScreen = () => {
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={(id) => setCartItems(p => p.filter(i => i.id !== id))} onUpdateQty={(id, d) => setCartItems(p => p.map(i => i.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={handleOrderConfirm} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} onConfirm={handleBookingConfirm} />;
    if (selectedServiceDetail) return <ServiceDetailScreen service={selectedServiceDetail} onBack={() => setSelectedServiceDetail(null)} onBook={(s) => { setSelectedServiceDetail(null); setBookingService(s); }} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} />;
      case 'services': return <ServicesScreen services={services} onBook={(s) => setBookingService(s)} onViewDetails={(s) => setSelectedServiceDetail(s)} />;
      case 'store': return <StoreScreen products={products} courses={courses} onAddToCart={addToCart} />;
      case 'viral': return <ViralScreen videos={videos} gallery={gallery} />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen gallery={gallery} />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} />;
    }
  };

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      <Header 
        onAdminTrigger={handleAdminTrigger} 
        cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} 
        onCartClick={() => setShowCart(true)} 
      />
      <main className="flex-1 pb-24 pt-20 px-4 max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal">
        {renderScreen()}
      </main>
      {!checkoutItem && !bookingService && !showCart && !selectedServiceDetail && (
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { ShoppingBag, Calendar, Video, BookOpen, Plus, Edit2, Trash2, CheckCircle2, XCircle, Truck, PackageCheck, Image as ImageIcon, Save, X, Camera, Upload } from 'lucide-react';
import { Service, Product, Course, VideoItem, GalleryItem, Appointment, Order } from '../types';
import Logo from '../components/Logo';

interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
  data?: {
    services: Service[];
    products: Product[];
    courses: Course[];
    videos: VideoItem[];
    gallery: GalleryItem[];
    bookings: Appointment[];
    orders: Order[];
  };
  setters?: {
    setServices: React.Dispatch<React.SetStateAction<Service[]>>;
    setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
    setCourses: React.Dispatch<React.SetStateAction<Course[]>>;
    setVideos: React.Dispatch<React.SetStateAction<VideoItem[]>>;
    setGallery: React.Dispatch<React.SetStateAction<GalleryItem[]>>;
    setBookings: React.Dispatch<React.SetStateAction<Appointment[]>>;
    setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  };
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel, data, setters }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('bookings');

  // Edit State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editBuffer, setEditBuffer] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleLogin = () => {
    if (password === 'A1234567890a') onLogin?.();
    else setError('Security Clearance Failure');
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8">
        <div className="mb-12 animate-royal">
          <Logo size="xl" />
        </div>
        <div className="w-full glass-card p-10 rounded-[3rem] border-[#F7E7CE]/20 shadow-2xl max-w-sm">
          <h2 className="text-xl font-bold text-[#F7E7CE] mb-8 serif text-center uppercase tracking-widest">Command Center Login</h2>
          <div className="space-y-6">
            <input 
              type="password" 
              placeholder="Authorization Key" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full bg-[#0A2419] border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE] transition-all" 
            />
            {error && <p className="text-red-400 text-[10px] text-center uppercase font-bold tracking-[0.2em]">{error}</p>}
            <button onClick={handleLogin} className="w-full btn-royal py-5 rounded-2xl flex items-center justify-center gap-2">Verify Credential</button>
            <button onClick={onCancel} className="w-full text-[#F7E7CE]/30 py-2 text-[10px] font-bold uppercase tracking-[0.3em]">Abort Mission</button>
          </div>
        </div>
      </div>
    );
  }

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editBuffer) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        // Determine which image field to update based on the tab
        const imageKey = activeTab === 'gallery' ? 'after' : (activeTab === 'reels' ? 'thumbnail' : 'image');
        setEditBuffer({ ...editBuffer, [imageKey]: base64String });
      };
      reader.readAsDataURL(file);
    }
  };

  const startEditing = (item: any) => {
    setEditingId(item.id);
    setEditBuffer({ ...item });
  };

  const saveEdit = () => {
    if (!setters || !editBuffer) return;

    const update = (prev: any[]) => prev.map(i => i.id === editingId ? editBuffer : i);

    if (activeTab === 'services') setters.setServices(update);
    if (activeTab === 'products') setters.setProducts(update);
    if (activeTab === 'courses') setters.setCourses(update);
    if (activeTab === 'reels') setters.setVideos(update);
    if (activeTab === 'gallery') setters.setGallery(update);

    setEditingId(null);
    setEditBuffer(null);
  };

  const deleteItem = (id: string) => {
    if (!setters || !confirm('Permanently remove this entry?')) return;

    if (activeTab === 'services') setters.setServices(p => p.filter(i => i.id !== id));
    if (activeTab === 'products') setters.setProducts(p => p.filter(i => i.id !== id));
    if (activeTab === 'courses') setters.setCourses(p => p.filter(i => i.id !== id));
    if (activeTab === 'reels') setters.setVideos(p => p.filter(i => i.id !== id));
    if (activeTab === 'gallery') setters.setGallery(p => p.filter(i => i.id !== id));
  };

  const addNewItem = () => {
    if (!setters) return;
    const id = Date.now().toString();
    const defaultImg = "https://images.unsplash.com/photo-1594465919760-441fe5908ab0";

    if (activeTab === 'services') setters.setServices(p => [{ id, name: 'New Service', description: 'Description', price: 0, duration: '1h', category: 'Makeup', image: defaultImg }, ...p]);
    if (activeTab === 'products') setters.setProducts(p => [{ id, name: 'New Product', price: 0, description: 'Luxury Item', image: defaultImg, category: 'Makeup' }, ...p]);
    if (activeTab === 'courses') setters.setCourses(p => [{ id, title: 'New Course', duration: '1 Month', price: 0, description: 'Training', image: defaultImg, level: 'Beginner' }, ...p]);
    if (activeTab === 'reels') setters.setVideos(p => [{ id, title: 'New Reel', url: '#', thumbnail: defaultImg, likes: 0, type: 'video' }, ...p]);
    if (activeTab === 'gallery') setters.setGallery(p => [{ id, title: 'New Gallery Item', before: defaultImg, after: defaultImg }, ...p]);

    // Auto start editing the new item
    const newItemId = id;
    setTimeout(() => {
        const list = activeTab === 'services' ? data?.services : activeTab === 'products' ? data?.products : activeTab === 'courses' ? data?.courses : activeTab === 'reels' ? data?.videos : data?.gallery;
        const found = list?.find(i => i.id === newItemId);
        if (found) startEditing(found);
    }, 100);
  };

  const renderEditableList = (title: string, list: any[]) => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif">{title}</h3>
        <button onClick={addNewItem} className="bg-[#F7E7CE] text-[#0A2419] p-3 rounded-full shadow-lg active:scale-90 transition-transform"><Plus size={20} /></button>
      </div>
      <div className="space-y-4">
        {list.map((item) => (
          <div key={item.id} className="glass-card p-5 rounded-[2.5rem] border-white/5 glow-gold overflow-hidden">
            {editingId === item.id ? (
              <div className="space-y-5">
                <div className="relative group w-full h-40 rounded-2xl overflow-hidden border border-white/10">
                   <img src={editBuffer.image || editBuffer.thumbnail || editBuffer.after} className="w-full h-full object-cover opacity-50" alt="" />
                   <button 
                     onClick={() => fileInputRef.current?.click()}
                     className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[#F7E7CE] font-bold text-[10px] uppercase tracking-widest"
                   >
                     <Camera size={24} /> Change Photo
                   </button>
                   <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={handleImageUpload} />
                </div>

                <div className="space-y-3">
                  <label className="text-[9px] font-black text-[#F7E7CE]/40 uppercase tracking-widest block ml-2">Title / Name</label>
                  <input 
                    className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white outline-none focus:border-[#F7E7CE]/40" 
                    value={editBuffer.name || editBuffer.title} 
                    onChange={(e) => setEditBuffer({...editBuffer, [item.name ? 'name' : 'title']: e.target.value})} 
                  />
                </div>

                {(activeTab === 'services' || activeTab === 'products' || activeTab === 'courses') && (
                  <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-2">
                       <label className="text-[9px] font-black text-[#F7E7CE]/40 uppercase tracking-widest block ml-2">Price (Rs)</label>
                       <input 
                        className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" 
                        value={editBuffer.price} 
                        type="number"
                        onChange={(e) => setEditBuffer({...editBuffer, price: Number(e.target.value)})} 
                      />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[9px] font-black text-[#F7E7CE]/40 uppercase tracking-widest block ml-2">Category / Level</label>
                       <input 
                        className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" 
                        value={editBuffer.category || editBuffer.level || ''} 
                        onChange={(e) => setEditBuffer({...editBuffer, [item.category ? 'category' : 'level']: e.target.value})} 
                      />
                    </div>
                  </div>
                )}

                <div className="space-y-2">
                  <label className="text-[9px] font-black text-[#F7E7CE]/40 uppercase tracking-widest block ml-2">Description</label>
                  <textarea 
                    className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white h-24 resize-none" 
                    value={editBuffer.description} 
                    onChange={(e) => setEditBuffer({...editBuffer, description: e.target.value})} 
                  />
                </div>

                <div className="flex gap-3 pt-2">
                  <button onClick={saveEdit} className="flex-1 bg-green-500 text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-lg"><Save size={14}/> Apply Changes</button>
                  <button onClick={() => setEditingId(null)} className="flex-1 bg-white/5 text-white/50 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><X size={14}/> Discard</button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-5">
                <div className="relative">
                  <img src={item.image || item.thumbnail || item.after} className="w-16 h-16 rounded-2xl object-cover border border-white/10 shadow-lg" alt="" />
                  {item.level && <span className="absolute -top-2 -right-2 bg-[#F7E7CE] text-[#0A2419] text-[7px] font-black px-1.5 py-0.5 rounded-full">{item.level}</span>}
                </div>
                <div className="flex-1">
                  <p className="text-xs font-bold text-white serif tracking-wide line-clamp-1">{item.name || item.title}</p>
                  <div className="flex items-center gap-3 mt-1.5">
                    {item.price !== undefined && <p className="text-[9px] text-[#F7E7CE] font-black tracking-widest">Rs. {item.price.toLocaleString()}</p>}
                    <p className="text-[8px] text-white/30 uppercase tracking-tighter">{item.category || item.duration || 'Archive'}</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => startEditing(item)} className="p-3 bg-white/5 rounded-2xl text-[#F7E7CE]/60 hover:text-[#F7E7CE] hover:bg-white/10 transition-all"><Edit2 size={16} /></button>
                  <button onClick={() => deleteItem(item.id)} className="p-3 bg-red-400/5 rounded-2xl text-red-400/60 hover:text-red-400 hover:bg-red-400/10 transition-all"><Trash2 size={16} /></button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-20 border-b border-[#F7E7CE]/10 flex items-center justify-between px-8 bg-[#124C34]/30 backdrop-blur-3xl sticky top-0 z-[110]">
        <Logo size="sm" />
        <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 hover:bg-red-400/10 uppercase tracking-[0.2em] transition-all">End Session</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-10">
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-12 py-3">
          {[
            { id: 'bookings', icon: <Calendar size={14} />, label: 'Bookings' },
            { id: 'orders', icon: <ShoppingBag size={14} />, label: 'Orders' },
            { id: 'services', icon: <Edit2 size={14} />, label: 'Services' },
            { id: 'products', icon: <PackageCheck size={14} />, label: 'Inventory' },
            { id: 'courses', icon: <BookOpen size={14} />, label: 'Academy' },
            { id: 'reels', icon: <Video size={14} />, label: 'Reels' },
            { id: 'gallery', icon: <ImageIcon size={14} />, label: 'Gallery' },
          ].map((t) => (
            <button 
              key={t.id} 
              onClick={() => {setActiveTab(t.id); setEditingId(null);}} 
              className={`px-6 py-4 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] transition-all whitespace-nowrap flex items-center gap-2.5 ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419] shadow-2xl scale-105' : 'bg-[#124C34]/40 text-[#F7E7CE]/40 border border-white/5'}`}
            >
              {t.icon} {t.label}
            </button>
          ))}
        </div>

        {activeTab === 'bookings' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Appointments Waiting</h3>
            {data?.bookings.length === 0 && <div className="py-20 text-center text-white/20 italic">No appointments booked yet.</div>}
            {data?.bookings.map(book => (
              <div key={book.id} className="glass-card p-7 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h4 className="text-lg font-bold text-white serif tracking-wide">{book.serviceName}</h4>
                    <p className="text-[10px] text-[#F7E7CE]/70 mt-1 uppercase tracking-widest font-black">{book.clientName} • {book.phone}</p>
                  </div>
                  <span className={`text-[8px] font-black px-4 py-2 rounded-full uppercase tracking-widest ${book.status === 'Accepted' ? 'bg-green-400 text-[#0A2419]' : book.status === 'Rejected' ? 'bg-red-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{book.status}</span>
                </div>
                {book.status === 'Pending' && (
                  <div className="flex gap-3">
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Accepted'} : b))} className="flex-1 bg-green-500/20 text-green-400 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest border border-green-500/10 flex items-center justify-center gap-2"><CheckCircle2 size={14}/> Accept</button>
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Rejected'} : b))} className="flex-1 bg-red-500/20 text-red-400 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest border border-red-500/10 flex items-center justify-center gap-2"><XCircle size={14}/> Reject</button>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Inventory Orders</h3>
            {data?.orders.length === 0 && <div className="py-20 text-center text-white/20 italic">No orders received yet.</div>}
            {data?.orders.map(order => (
              <div key={order.id} className="glass-card p-7 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-5">
                  <h4 className="text-[10px] font-black text-[#F7E7CE] uppercase tracking-widest">Order ID: {order.id.slice(-8)}</h4>
                  <span className={`text-[8px] font-black px-4 py-2 rounded-full uppercase tracking-widest ${order.status === 'Shipped' ? 'bg-blue-400 text-[#0A2419]' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{order.status}</span>
                </div>
                <p className="text-xl font-bold text-white serif mb-1">{order.clientName}</p>
                <div className="bg-black/20 p-4 rounded-2xl mb-6 border border-white/5">
                   <p className="text-[9px] text-white/50 mb-3 flex items-start gap-2 italic uppercase tracking-wider"><Truck size={12}/> {order.address}</p>
                   <div className="space-y-2">
                     {order.items.map((it, idx) => (
                       <div key={idx} className="flex justify-between text-[10px] text-white/80 font-bold">
                         <span>{it.quantity}x {it.name}</span>
                         <span className="text-[#F7E7CE]">Rs. {it.price * it.quantity}</span>
                       </div>
                     ))}
                   </div>
                </div>
                {order.status === 'Pending' && (
                  <button onClick={() => setters?.setOrders(p => p.map(o => o.id === order.id ? {...o, status: 'Shipped'} : o))} className="w-full btn-royal py-5 rounded-2xl text-[10px] flex items-center justify-center gap-3 uppercase tracking-widest shadow-xl">Process & Ship <Truck size={18}/></button>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'services' && renderEditableList('Luxury Services', data?.services || [])}
        {activeTab === 'products' && renderEditableList('Store Inventory', data?.products || [])}
        {activeTab === 'courses' && renderEditableList('Artistry Academy', data?.courses || [])}
        {activeTab === 'reels' && renderEditableList('Cinematic Reels', data?.videos || [])}
        {activeTab === 'gallery' && renderEditableList('Portfolio Gallery', data?.gallery || [])}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useRef } from 'react';
import { ShoppingBag, Calendar, Video, BookOpen, Plus, Edit2, Trash2, CheckCircle2, XCircle, Truck, PackageCheck, Image as ImageIcon, Save, X, Camera, Play, Film } from 'lucide-react';
import { Service, Product, Course, VideoItem, GalleryItem, Appointment, Order } from '../types';
import Logo from '../components/Logo';

interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
  data?: {
    services: Service[];
    products: Product[];
    courses: Course[];
    videos: VideoItem[];
    gallery: GalleryItem[];
    bookings: Appointment[];
    orders: Order[];
  };
  setters?: {
    setServices: React.Dispatch<React.SetStateAction<Service[]>>;
    setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
    setCourses: React.Dispatch<React.SetStateAction<Course[]>>;
    setVideos: React.Dispatch<React.SetStateAction<VideoItem[]>>;
    setGallery: React.Dispatch<React.SetStateAction<GalleryItem[]>>;
    setBookings: React.Dispatch<React.SetStateAction<Appointment[]>>;
    setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  };
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel, data, setters }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('bookings');

  // Edit State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editBuffer, setEditBuffer] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const secondFileInputRef = useRef<HTMLInputElement>(null);

  const handleLogin = () => {
    if (password === 'A1234567890a') onLogin?.();
    else setError('Security Clearance Failure');
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8">
        <div className="mb-12 animate-royal">
          <Logo size="xl" />
        </div>
        <div className="w-full glass-card p-10 rounded-[3rem] border-[#F7E7CE]/20 shadow-2xl max-w-sm">
          <h2 className="text-xl font-bold text-[#F7E7CE] mb-8 serif text-center uppercase tracking-widest">Command Center Login</h2>
          <div className="space-y-6">
            <input 
              type="password" 
              placeholder="Authorization Key" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full bg-[#0A2419] border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE] transition-all" 
            />
            {error && <p className="text-red-400 text-[10px] text-center uppercase font-bold tracking-[0.2em]">{error}</p>}
            <button onClick={handleLogin} className="w-full btn-royal py-5 rounded-2xl flex items-center justify-center gap-2">Verify Credential</button>
            <button onClick={onCancel} className="w-full text-[#F7E7CE]/30 py-2 text-[10px] font-bold uppercase tracking-[0.3em]">Abort Mission</button>
          </div>
        </div>
      </div>
    );
  }

  const handleMediaUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string = 'image') => {
    const file = e.target.files?.[0];
    if (file && editBuffer) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        setEditBuffer({ ...editBuffer, [field]: base64String });
        if (activeTab === 'reels') {
          // For reels, we set the URL as the base64 video stream
          setEditBuffer({ ...editBuffer, url: base64String, thumbnail: base64String });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const startEditing = (item: any) => {
    setEditingId(item.id);
    setEditBuffer({ ...item });
  };

  const saveEdit = () => {
    if (!setters || !editBuffer) return;
    const update = (prev: any[]) => prev.map(i => i.id === editingId ? editBuffer : i);

    if (activeTab === 'services') setters.setServices(update);
    else if (activeTab === 'products') setters.setProducts(update);
    else if (activeTab === 'courses') setters.setCourses(update);
    else if (activeTab === 'reels') setters.setVideos(update);
    else if (activeTab === 'gallery') setters.setGallery(update);

    setEditingId(null);
    setEditBuffer(null);
  };

  const deleteItem = (id: string) => {
    if (!setters || !confirm('Permanently remove this entry?')) return;

    if (activeTab === 'services') setters.setServices(p => p.filter(i => i.id !== id));
    else if (activeTab === 'products') setters.setProducts(p => p.filter(i => i.id !== id));
    else if (activeTab === 'courses') setters.setCourses(p => p.filter(i => i.id !== id));
    else if (activeTab === 'reels') setters.setVideos(p => p.filter(i => i.id !== id));
    else if (activeTab === 'gallery') setters.setGallery(p => p.filter(i => i.id !== id));

    if (editingId === id) {
      setEditingId(null);
      setEditBuffer(null);
    }
  };

  const addNewItem = () => {
    if (!setters) return;
    const id = Date.now().toString();
    const defaultImg = "https://images.unsplash.com/photo-1594465919760-441fe5908ab0";

    if (activeTab === 'services') setters.setServices(p => [{ id, name: 'New Service', description: 'Premium treatment...', price: 5000, duration: '1h', category: 'Makeup', image: defaultImg }, ...p]);
    else if (activeTab === 'products') setters.setProducts(p => [{ id, name: 'New Product', price: 1000, description: 'Luxury Cosmetic', image: defaultImg, category: 'Makeup' }, ...p]);
    else if (activeTab === 'courses') setters.setCourses(p => [{ id, title: 'New Course', duration: '1 Month', price: 20000, description: 'Academy Training', image: defaultImg, level: 'Beginner' }, ...p]);
    else if (activeTab === 'reels') setters.setVideos(p => [{ id, title: 'New Viral Reel', url: '', thumbnail: defaultImg, likes: 0, type: 'video' }, ...p]);
    else if (activeTab === 'gallery') setters.setGallery(p => [{ id, title: 'Transformation Piece', before: defaultImg, after: defaultImg }, ...p]);
  };

  const renderEditableList = (title: string, list: any[]) => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif">{title}</h3>
        <button onClick={addNewItem} className="bg-[#F7E7CE] text-[#0A2419] p-3 rounded-full shadow-lg active:scale-95 transition-all"><Plus size={20} /></button>
      </div>
      <div className="space-y-4">
        {list.map((item) => (
          <div key={item.id} className="glass-card p-5 rounded-[2.5rem] border-white/5 glow-gold">
            {editingId === item.id ? (
              <div className="space-y-5 animate-in slide-in-from-top-2">
                {activeTab === 'gallery' ? (
                  <div className="grid grid-cols-2 gap-4">
                    <div className="relative h-40 rounded-2xl overflow-hidden border border-white/10 group">
                      <img src={editBuffer.before} className="w-full h-full object-cover" alt="" />
                      <button onClick={() => fileInputRef.current?.click()} className="absolute inset-0 bg-black/40 flex flex-col items-center justify-center gap-1 text-[8px] font-bold uppercase text-white"><Camera size={16}/> Upload Before</button>
                      <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={(e) => handleMediaUpload(e, 'before')} />
                    </div>
                    <div className="relative h-40 rounded-2xl overflow-hidden border border-white/10 group">
                      <img src={editBuffer.after} className="w-full h-full object-cover" alt="" />
                      <button onClick={() => secondFileInputRef.current?.click()} className="absolute inset-0 bg-black/40 flex flex-col items-center justify-center gap-1 text-[8px] font-bold uppercase text-white"><Camera size={16}/> Upload After</button>
                      <input type="file" ref={secondFileInputRef} hidden accept="image/*" onChange={(e) => handleMediaUpload(e, 'after')} />
                    </div>
                  </div>
                ) : activeTab === 'reels' ? (
                  <div className="relative w-full h-48 rounded-2xl overflow-hidden border border-white/10 bg-black/40 flex flex-col items-center justify-center group">
                    {editBuffer.url ? (
                      <video src={editBuffer.url} className="w-full h-full object-cover opacity-50" muted playsInline />
                    ) : (
                      <Film size={40} className="text-[#F7E7CE]/20" />
                    )}
                    <button onClick={() => fileInputRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[#F7E7CE] font-bold text-[10px] uppercase tracking-widest"><Play size={24}/> Upload Video File</button>
                    <input type="file" ref={fileInputRef} hidden accept="video/*" onChange={(e) => handleMediaUpload(e, 'url')} />
                  </div>
                ) : (
                  <div className="relative w-full h-40 rounded-2xl overflow-hidden border border-white/10">
                    <img src={editBuffer.image} className="w-full h-full object-cover opacity-40" alt="" />
                    <button onClick={() => fileInputRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[#F7E7CE] font-bold text-[10px] uppercase tracking-widest"><Camera size={24}/> Choose New Photo</button>
                    <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={(e) => handleMediaUpload(e, 'image')} />
                  </div>
                )}

                <div className="space-y-3">
                  <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white outline-none focus:border-[#F7E7CE]/40" value={editBuffer.name || editBuffer.title} onChange={(e) => setEditBuffer({...editBuffer, [item.name ? 'name' : 'title']: e.target.value})} placeholder="Title / Name" />
                  {(activeTab === 'services' || activeTab === 'products' || activeTab === 'courses') && (
                    <div className="grid grid-cols-2 gap-3">
                      <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.price} type="number" onChange={(e) => setEditBuffer({...editBuffer, price: Number(e.target.value)})} placeholder="Price" />
                      <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.category || editBuffer.level || ''} onChange={(e) => setEditBuffer({...editBuffer, [item.category ? 'category' : 'level']: e.target.value})} placeholder="Category/Level" />
                    </div>
                  )}
                  {activeTab !== 'reels' && (
                    <textarea className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white h-20 resize-none" value={editBuffer.description} onChange={(e) => setEditBuffer({...editBuffer, description: e.target.value})} placeholder="Description" />
                  )}
                </div>

                <div className="flex gap-3">
                  <button onClick={saveEdit} className="flex-1 bg-green-500 text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-lg"><Save size={14}/> Save Changes</button>
                  <button onClick={() => setEditingId(null)} className="flex-1 bg-white/5 text-white/50 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><X size={14}/> Cancel</button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-5">
                <div className="relative">
                  {activeTab === 'reels' ? (
                    <div className="w-16 h-16 rounded-2xl bg-black flex items-center justify-center border border-white/10">
                      <Film size={20} className="text-[#F7E7CE]/50" />
                    </div>
                  ) : (
                    <img src={item.image || item.after || item.thumbnail} className="w-16 h-16 rounded-2xl object-cover border border-white/10" alt="" />
                  )}
                </div>
                <div className="flex-1">
                  <p className="text-xs font-bold text-white serif tracking-wide">{item.name || item.title}</p>
                  <p className="text-[9px] text-[#F7E7CE]/40 mt-1 uppercase tracking-widest">{item.category || item.level || (activeTab === 'reels' ? 'Video Format' : 'Portfolio')}</p>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => startEditing(item)} className="p-3 bg-white/5 rounded-xl text-[#F7E7CE]/60"><Edit2 size={16} /></button>
                  <button onClick={() => deleteItem(item.id)} className="p-3 bg-red-400/5 rounded-xl text-red-400/60"><Trash2 size={16} /></button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-20 border-b border-[#F7E7CE]/10 flex items-center justify-between px-8 bg-[#124C34]/30 backdrop-blur-3xl sticky top-0 z-[110]">
        <Logo size="sm" />
        <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 uppercase tracking-[0.2em]">Sign Out</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-10">
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-10 py-3">
          {[
            { id: 'bookings', icon: <Calendar size={14} />, label: 'Bookings' },
            { id: 'orders', icon: <ShoppingBag size={14} />, label: 'Orders' },
            { id: 'services', icon: <Edit2 size={14} />, label: 'Services' },
            { id: 'products', icon: <PackageCheck size={14} />, label: 'Inventory' },
            { id: 'courses', icon: <BookOpen size={14} />, label: 'Academy' },
            { id: 'reels', icon: <Video size={14} />, label: 'Viral Reels' },
            { id: 'gallery', icon: <ImageIcon size={14} />, label: 'Gallery' },
          ].map((t) => (
            <button 
              key={t.id} 
              onClick={() => {setActiveTab(t.id); setEditingId(null);}} 
              className={`px-6 py-4 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center gap-2.5 ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419] shadow-xl scale-105' : 'bg-[#124C34]/40 text-[#F7E7CE]/40 border border-white/5'}`}
            >
              {t.icon} {t.label}
            </button>
          ))}
        </div>

        {activeTab === 'bookings' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Client Appointments</h3>
            {data?.bookings.map(book => (
              <div key={book.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h4 className="text-lg font-bold text-white serif">{book.serviceName}</h4>
                    <p className="text-[10px] text-[#F7E7CE]/60 mt-1 font-bold uppercase tracking-widest">{book.clientName} • {book.phone}</p>
                  </div>
                  <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest ${book.status === 'Accepted' ? 'bg-green-400 text-[#0A2419]' : book.status === 'Rejected' ? 'bg-red-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{book.status}</span>
                </div>
                {book.status === 'Pending' && (
                  <div className="flex gap-3">
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Accepted'} : b))} className="flex-1 bg-green-500/20 text-green-400 py-4 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2"><CheckCircle2 size={14}/> Accept</button>
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Rejected'} : b))} className="flex-1 bg-red-500/20 text-red-400 py-4 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2"><XCircle size={14}/> Reject</button>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Pending Shipments</h3>
            {data?.orders.map(order => (
              <div key={order.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-4">
                  <h4 className="text-[10px] font-black text-[#F7E7CE] uppercase tracking-widest">Order #{order.id.slice(-6)}</h4>
                  <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase ${order.status === 'Shipped' ? 'bg-blue-400 text-black' : 'bg-[#F7E7CE] text-black'}`}>{order.status}</span>
                </div>
                <p className="text-lg font-bold text-white serif mb-1">{order.clientName}</p>
                <p className="text-[10px] text-white/40 mb-6 italic">{order.address}</p>
                {order.status === 'Pending' && (
                  <button onClick={() => setters?.setOrders(p => p.map(o => o.id === order.id ? {...o, status: 'Shipped'} : o))} className="w-full btn-royal py-4 rounded-xl text-[10px] flex items-center justify-center gap-2 uppercase tracking-widest shadow-xl">Mark as Shipped <Truck size={16}/></button>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'services' && renderEditableList('Salon Menu', data?.services || [])}
        {activeTab === 'products' && renderEditableList('Inventory', data?.products || [])}
        {activeTab === 'courses' && renderEditableList('Academy Academy', data?.courses || [])}
        {activeTab === 'reels' && renderEditableList('Viral Videos', data?.videos || [])}
        {activeTab === 'gallery' && renderEditableList('Before & After Portfolio', data?.gallery || [])}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useRef } from 'react';
import { ShoppingBag, Calendar, Video, BookOpen, Plus, Edit2, Trash2, CheckCircle2, XCircle, Truck, PackageCheck, Image as ImageIcon, Save, X, Camera, Play, Film, Upload } from 'lucide-react';
import { Service, Product, Course, VideoItem, GalleryItem, Appointment, Order } from '../types';
import Logo from '../components/Logo';

interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
  data?: {
    services: Service[];
    products: Product[];
    courses: Course[];
    videos: VideoItem[];
    gallery: GalleryItem[];
    bookings: Appointment[];
    orders: Order[];
  };
  setters?: {
    setServices: React.Dispatch<React.SetStateAction<Service[]>>;
    setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
    setCourses: React.Dispatch<React.SetStateAction<Course[]>>;
    setVideos: React.Dispatch<React.SetStateAction<VideoItem[]>>;
    setGallery: React.Dispatch<React.SetStateAction<GalleryItem[]>>;
    setBookings: React.Dispatch<React.SetStateAction<Appointment[]>>;
    setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  };
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel, data, setters }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('bookings');

  // Edit State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editBuffer, setEditBuffer] = useState<any>(null);

  // Refs for file inputs
  const mainFileRef = useRef<HTMLInputElement>(null);
  const secondaryFileRef = useRef<HTMLInputElement>(null);

  const handleLogin = () => {
    if (password === 'A1234567890a') onLogin?.();
    else setError('Security Clearance Failure');
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8">
        <div className="mb-12 animate-royal">
          <Logo size="xl" />
        </div>
        <div className="w-full glass-card p-10 rounded-[3rem] border-[#F7E7CE]/20 shadow-2xl max-w-sm">
          <h2 className="text-xl font-bold text-[#F7E7CE] mb-8 serif text-center uppercase tracking-widest">Command Center Login</h2>
          <div className="space-y-6">
            <input 
              type="password" 
              placeholder="Authorization Key" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full bg-[#0A2419] border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE] transition-all" 
            />
            {error && <p className="text-red-400 text-[10px] text-center uppercase font-bold tracking-[0.2em]">{error}</p>}
            <button onClick={handleLogin} className="w-full btn-royal py-5 rounded-2xl flex items-center justify-center gap-2">Verify Credential</button>
            <button onClick={onCancel} className="w-full text-[#F7E7CE]/30 py-2 text-[10px] font-bold uppercase tracking-[0.3em]">Abort Mission</button>
          </div>
        </div>
      </div>
    );
  }

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string) => {
    const file = e.target.files?.[0];
    if (file && editBuffer) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        setEditBuffer({ ...editBuffer, [field]: result });
        // If it's a video for reels, also set the thumbnail as the same data stream for now
        if (activeTab === 'reels' && field === 'url') {
          setEditBuffer(prev => ({ ...prev, url: result, thumbnail: result }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const startEditing = (item: any) => {
    setEditingId(item.id);
    setEditBuffer({ ...item });
  };

  const deleteItem = (id: string) => {
    if (!setters) return;
    if (!window.confirm("Are you sure you want to delete this permanently?")) return;

    switch (activeTab) {
      case 'services': setters.setServices(prev => prev.filter(item => item.id !== id)); break;
      case 'products': setters.setProducts(prev => prev.filter(item => item.id !== id)); break;
      case 'courses': setters.setCourses(prev => prev.filter(item => item.id !== id)); break;
      case 'reels': setters.setVideos(prev => prev.filter(item => item.id !== id)); break;
      case 'gallery': setters.setGallery(prev => prev.filter(item => item.id !== id)); break;
    }

    if (editingId === id) {
      setEditingId(null);
      setEditBuffer(null);
    }
  };

  const addItem = () => {
    if (!setters) return;
    const newId = `new-${Date.now()}`;
    const placeholderImg = "https://images.unsplash.com/photo-1594465919760-441fe5908ab0";

    if (activeTab === 'services') {
      const newItem: Service = { id: newId, name: 'New Service', description: 'Enter description...', price: 0, duration: '1h', category: 'Makeup', image: placeholderImg };
      setters.setServices(prev => [newItem, ...prev]);
      startEditing(newItem);
    } else if (activeTab === 'products') {
      const newItem: Product = { id: newId, name: 'New Product', price: 0, description: 'Enter description...', image: placeholderImg, category: 'Makeup' };
      setters.setProducts(prev => [newItem, ...prev]);
      startEditing(newItem);
    } else if (activeTab === 'courses') {
      const newItem: Course = { id: newId, title: 'New Academy Course', duration: '1 Month', price: 0, description: 'Masterclass details...', image: placeholderImg, level: 'Beginner' };
      setters.setCourses(prev => [newItem, ...prev]);
      startEditing(newItem);
    } else if (activeTab === 'reels') {
      const newItem: VideoItem = { id: newId, title: 'New Viral Reel', url: '', thumbnail: placeholderImg, likes: 0, type: 'video' };
      setters.setVideos(prev => [newItem, ...prev]);
      startEditing(newItem);
    } else if (activeTab === 'gallery') {
      const newItem: GalleryItem = { id: newId, title: 'New Portfolio Work', before: placeholderImg, after: placeholderImg };
      setters.setGallery(prev => [newItem, ...prev]);
      startEditing(newItem);
    }
  };

  const saveEdit = () => {
    if (!setters || !editBuffer) return;
    const updateFn = (prev: any[]) => prev.map(item => item.id === editingId ? editBuffer : item);

    switch (activeTab) {
      case 'services': setters.setServices(updateFn); break;
      case 'products': setters.setProducts(updateFn); break;
      case 'courses': setters.setCourses(updateFn); break;
      case 'reels': setters.setVideos(updateFn); break;
      case 'gallery': setters.setGallery(updateFn); break;
    }

    setEditingId(null);
    setEditBuffer(null);
  };

  const renderEditableList = (title: string, list: any[]) => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif">{title}</h3>
        <button onClick={addItem} className="bg-[#F7E7CE] text-[#0A2419] p-3 rounded-full shadow-lg active:scale-90 transition-transform"><Plus size={20} /></button>
      </div>
      <div className="space-y-4">
        {list.map((item) => (
          <div key={item.id} className="glass-card p-5 rounded-[2.5rem] border-white/5 glow-gold overflow-hidden">
            {editingId === item.id ? (
              <div className="space-y-5">
                {/* Media Upload Area */}
                {activeTab === 'gallery' ? (
                  <div className="grid grid-cols-2 gap-3">
                    <div className="relative h-32 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                      <img src={editBuffer.before} className="w-full h-full object-cover opacity-50" alt="" />
                      <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-1 text-[8px] text-white font-black uppercase tracking-widest"><Camera size={16}/> Before</button>
                      <input type="file" ref={mainFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'before')} />
                    </div>
                    <div className="relative h-32 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                      <img src={editBuffer.after} className="w-full h-full object-cover opacity-50" alt="" />
                      <button onClick={() => secondaryFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-1 text-[8px] text-white font-black uppercase tracking-widest"><Camera size={16}/> After</button>
                      <input type="file" ref={secondaryFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'after')} />
                    </div>
                  </div>
                ) : activeTab === 'reels' ? (
                  <div className="relative h-48 bg-black/60 rounded-2xl overflow-hidden border border-white/10 flex flex-col items-center justify-center">
                    {editBuffer.url ? (
                      <video src={editBuffer.url} className="w-full h-full object-cover opacity-30" muted />
                    ) : (
                      <Film size={32} className="text-white/20 mb-2" />
                    )}
                    <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[10px] text-white font-black uppercase tracking-widest bg-black/20"><Play size={24}/> Upload Video File</button>
                    <input type="file" ref={mainFileRef} hidden accept="video/*" onChange={(e) => handleFileUpload(e, 'url')} />
                  </div>
                ) : (
                  <div className="relative h-32 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                    <img src={editBuffer.image} className="w-full h-full object-cover opacity-50" alt="" />
                    <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[10px] text-white font-black uppercase tracking-widest"><Camera size={20}/> Change Image</button>
                    <input type="file" ref={mainFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'image')} />
                  </div>
                )}

                <div className="space-y-3">
                  <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.name || editBuffer.title} onChange={(e) => setEditBuffer({...editBuffer, [item.name ? 'name' : 'title']: e.target.value})} placeholder="Title / Name" />
                  {(activeTab === 'services' || activeTab === 'products' || activeTab === 'courses') && (
                    <div className="grid grid-cols-2 gap-3">
                      <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.price} type="number" onChange={(e) => setEditBuffer({...editBuffer, price: Number(e.target.value)})} placeholder="Price" />
                      <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.category || editBuffer.level || ''} onChange={(e) => setEditBuffer({...editBuffer, [item.category ? 'category' : 'level']: e.target.value})} placeholder="Category/Level" />
                    </div>
                  )}
                  {activeTab !== 'reels' && (
                    <textarea className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white h-20 resize-none" value={editBuffer.description} onChange={(e) => setEditBuffer({...editBuffer, description: e.target.value})} placeholder="Description" />
                  )}
                </div>

                <div className="flex gap-3">
                  <button onClick={saveEdit} className="flex-1 bg-green-600 text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><Save size={14}/> Save</button>
                  <button onClick={() => setEditingId(null)} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><X size={14}/> Cancel</button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-5">
                <div className="w-14 h-14 rounded-xl overflow-hidden border border-white/10 shrink-0 bg-black/20 flex items-center justify-center">
                  {activeTab === 'reels' ? <Film size={20} className="text-[#F7E7CE]/40"/> : <img src={item.image || item.after || item.thumbnail} className="w-full h-full object-cover" alt="" />}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-xs font-bold text-white serif truncate">{item.name || item.title}</p>
                  <p className="text-[9px] text-[#F7E7CE]/40 uppercase tracking-widest mt-1">{item.category || item.level || 'Portfolio'}</p>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => startEditing(item)} className="p-3 bg-white/5 rounded-xl text-[#F7E7CE]/60 hover:text-[#F7E7CE]"><Edit2 size={16} /></button>
                  <button onClick={() => deleteItem(item.id)} className="p-3 bg-red-400/10 rounded-xl text-red-400/60 hover:text-red-400"><Trash2 size={16} /></button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-20 border-b border-[#F7E7CE]/10 flex items-center justify-between px-8 bg-[#124C34]/30 backdrop-blur-3xl sticky top-0 z-[110]">
        <Logo size="sm" />
        <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 uppercase tracking-[0.2em]">Exit Panel</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-20">
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-10 py-2">
          {[
            { id: 'bookings', icon: <Calendar size={14} />, label: 'Bookings' },
            { id: 'orders', icon: <ShoppingBag size={14} />, label: 'Orders' },
            { id: 'services', icon: <Edit2 size={14} />, label: 'Services' },
            { id: 'products', icon: <PackageCheck size={14} />, label: 'Inventory' },
            { id: 'courses', icon: <BookOpen size={14} />, label: 'Academy' },
            { id: 'reels', icon: <Video size={14} />, label: 'Reels' },
            { id: 'gallery', icon: <ImageIcon size={14} />, label: 'Gallery' },
          ].map((t) => (
            <button 
              key={t.id} 
              onClick={() => {setActiveTab(t.id); setEditingId(null);}} 
              className={`px-5 py-3.5 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419] shadow-xl scale-105' : 'bg-[#124C34]/40 text-[#F7E7CE]/30 border border-white/5'}`}
            >
              {t.icon} {t.label}
            </button>
          ))}
        </div>

        {activeTab === 'bookings' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Client Appointments</h3>
            {data?.bookings.map(book => (
              <div key={book.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h4 className="text-lg font-bold text-white serif">{book.serviceName}</h4>
                    <p className="text-[10px] text-[#F7E7CE]/60 mt-1 uppercase tracking-widest">{book.clientName} • {book.phone}</p>
                  </div>
                  <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest ${book.status === 'Accepted' ? 'bg-green-400 text-[#0A2419]' : book.status === 'Rejected' ? 'bg-red-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{book.status}</span>
                </div>
                {book.status === 'Pending' && (
                  <div className="flex gap-3">
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Accepted'} : b))} className="flex-1 bg-green-500/20 text-green-400 py-3.5 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2 border border-green-500/10"><CheckCircle2 size={14}/> Accept</button>
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Rejected'} : b))} className="flex-1 bg-red-500/20 text-red-400 py-3.5 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2 border border-red-500/10"><XCircle size={14}/> Reject</button>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Pending Shipments</h3>
            {data?.orders.map(order => (
              <div key={order.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-4">
                  <h4 className="text-[10px] font-black text-[#F7E7CE] uppercase tracking-widest">Order ID: {order.id.slice(-6)}</h4>
                  <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase ${order.status === 'Shipped' ? 'bg-blue-400 text-[#0A2419]' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{order.status}</span>
                </div>
                <p className="text-lg font-bold text-white serif mb-1">{order.clientName}</p>
                <p className="text-[10px] text-white/40 mb-6 italic">{order.address}</p>
                {order.status === 'Pending' && (
                  <button onClick={() => setters?.setOrders(p => p.map(o => o.id === order.id ? {...o, status: 'Shipped'} : o))} className="w-full btn-royal py-4 rounded-xl text-[10px] flex items-center justify-center gap-2 uppercase tracking-widest shadow-xl">Process Order <Truck size={16}/></button>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'services' && renderEditableList('Salon Menu', data?.services || [])}
        {activeTab === 'products' && renderEditableList('Inventory Boutique', data?.products || [])}
        {activeTab === 'courses' && renderEditableList('Artistry Academy', data?.courses || [])}
        {activeTab === 'reels' && renderEditableList('Viral Video Studio', data?.videos || [])}
        {activeTab === 'gallery' && renderEditableList('Before & After Portfolio', data?.gallery || [])}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useRef } from 'react';
import { ShoppingBag, Calendar, Video, BookOpen, Plus, Edit2, Trash2, CheckCircle2, XCircle, Truck, PackageCheck, Image as ImageIcon, Save, X, Camera, Play, Film, AlertCircle } from 'lucide-react';
import { Service, Product, Course, VideoItem, GalleryItem, Appointment, Order } from '../types';
import Logo from '../components/Logo';

interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
  data?: {
    services: Service[];
    products: Product[];
    courses: Course[];
    videos: VideoItem[];
    gallery: GalleryItem[];
    bookings: Appointment[];
    orders: Order[];
  };
  setters?: {
    setServices: React.Dispatch<React.SetStateAction<Service[]>>;
    setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
    setCourses: React.Dispatch<React.SetStateAction<Course[]>>;
    setVideos: React.Dispatch<React.SetStateAction<VideoItem[]>>;
    setGallery: React.Dispatch<React.SetStateAction<GalleryItem[]>>;
    setBookings: React.Dispatch<React.SetStateAction<Appointment[]>>;
    setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  };
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel, data, setters }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('bookings');

  // Edit State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editBuffer, setEditBuffer] = useState<any>(null);
  const [validationError, setValidationError] = useState<string | null>(null);

  // Refs for file inputs
  const mainFileRef = useRef<HTMLInputElement>(null);
  const secondaryFileRef = useRef<HTMLInputElement>(null);

  const handleLogin = () => {
    if (password === 'A1234567890a') onLogin?.();
    else setError('Security Clearance Failure');
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8">
        <div className="mb-12 animate-royal">
          <Logo size="xl" />
        </div>
        <div className="w-full glass-card p-10 rounded-[3rem] border-[#F7E7CE]/20 shadow-2xl max-w-sm">
          <h2 className="text-xl font-bold text-[#F7E7CE] mb-8 serif text-center uppercase tracking-widest">Command Center Login</h2>
          <div className="space-y-6">
            <input 
              type="password" 
              placeholder="Authorization Key" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full bg-[#0A2419] border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE] transition-all" 
            />
            {error && <p className="text-red-400 text-[10px] text-center uppercase font-bold tracking-[0.2em]">{error}</p>}
            <button onClick={handleLogin} className="w-full btn-royal py-5 rounded-2xl flex items-center justify-center gap-2">Verify Credential</button>
            <button onClick={onCancel} className="w-full text-[#F7E7CE]/30 py-2 text-[10px] font-bold uppercase tracking-[0.3em]">Abort Mission</button>
          </div>
        </div>
      </div>
    );
  }

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string) => {
    const file = e.target.files?.[0];
    if (file && editBuffer) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        setEditBuffer({ ...editBuffer, [field]: result });
        if (activeTab === 'reels' && field === 'url') {
          setEditBuffer((prev: any) => ({ ...prev, url: result, thumbnail: result }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const startEditing = (item: any) => {
    setEditingId(item.id);
    setEditBuffer({ ...item });
    setValidationError(null);
  };

  const deleteItem = (id: string) => {
    if (!setters) return;
    if (!window.confirm("Permanently delete this item? This cannot be undone.")) return;

    // Explicitly update parent states to ensure immediate UI removal
    if (activeTab === 'services') setters.setServices(prev => prev.filter(i => i.id !== id));
    else if (activeTab === 'products') setters.setProducts(prev => prev.filter(i => i.id !== id));
    else if (activeTab === 'courses') setters.setCourses(prev => prev.filter(i => i.id !== id));
    else if (activeTab === 'reels') setters.setVideos(prev => prev.filter(i => i.id !== id));
    else if (activeTab === 'gallery') setters.setGallery(prev => prev.filter(i => i.id !== id));

    if (editingId === id) {
      setEditingId(null);
      setEditBuffer(null);
    }
  };

  const addItem = () => {
    if (!setters) return;
    const newId = `item-${Date.now()}`;
    const placeholderImg = "https://images.unsplash.com/photo-1594465919760-441fe5908ab0";

    // Add empty template to the top of the list
    if (activeTab === 'services') {
      const item: Service = { id: newId, name: '', description: '', price: 0, duration: '', category: '', image: '' };
      setters.setServices(prev => [item, ...prev]);
      startEditing(item);
    } else if (activeTab === 'products') {
      const item: Product = { id: newId, name: '', price: 0, description: '', image: '', category: '' };
      setters.setProducts(prev => [item, ...prev]);
      startEditing(item);
    } else if (activeTab === 'courses') {
      const item: Course = { id: newId, title: '', duration: '', price: 0, description: '', image: '', level: 'Beginner' };
      setters.setCourses(prev => [item, ...prev]);
      startEditing(item);
    } else if (activeTab === 'reels') {
      const item: VideoItem = { id: newId, title: '', url: '', thumbnail: '', likes: 0, type: 'video' };
      setters.setVideos(prev => [item, ...prev]);
      startEditing(item);
    } else if (activeTab === 'gallery') {
      const item: GalleryItem = { id: newId, title: '', before: '', after: '' };
      setters.setGallery(prev => [item, ...prev]);
      startEditing(item);
    }
  };

  const validate = () => {
    if (!editBuffer) return false;

    // Check main title/name
    const title = editBuffer.name || editBuffer.title;
    if (!title || title.trim() === '') {
      setValidationError("Name/Title is mandatory.");
      return false;
    }

    // Check media based on tab
    if (activeTab === 'gallery') {
      if (!editBuffer.before || !editBuffer.after) {
        setValidationError("Both Before and After images are mandatory.");
        return false;
      }
    } else if (activeTab === 'reels') {
      if (!editBuffer.url) {
        setValidationError("Video file is mandatory for reels.");
        return false;
      }
    } else {
      if (!editBuffer.image) {
        setValidationError("Main image is mandatory.");
        return false;
      }
    }

    // Check price/category for catalog items
    if (['services', 'products', 'courses'].includes(activeTab)) {
      if (!editBuffer.price || editBuffer.price <= 0) {
        setValidationError("A valid Price is mandatory.");
        return false;
      }
      if (!editBuffer.description || editBuffer.description.trim() === '') {
        setValidationError("Description is mandatory.");
        return false;
      }
    }

    setValidationError(null);
    return true;
  };

  const saveEdit = () => {
    if (!validate()) return;
    if (!setters || !editBuffer) return;

    const updateFn = (prev: any[]) => prev.map(item => item.id === editingId ? editBuffer : item);

    if (activeTab === 'services') setters.setServices(updateFn);
    else if (activeTab === 'products') setters.setProducts(updateFn);
    else if (activeTab === 'courses') setters.setCourses(updateFn);
    else if (activeTab === 'reels') setters.setVideos(updateFn);
    else if (activeTab === 'gallery') setters.setGallery(updateFn);

    setEditingId(null);
    setEditBuffer(null);
  };

  const renderEditableList = (title: string, list: any[]) => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif">{title}</h3>
        <button onClick={addItem} className="bg-[#F7E7CE] text-[#0A2419] p-3 rounded-full shadow-lg active:scale-90 transition-transform"><Plus size={20} /></button>
      </div>

      {validationError && (
        <div className="mb-6 bg-red-500/10 border border-red-500/20 p-4 rounded-2xl flex items-center gap-3 text-red-400 text-[10px] font-black uppercase tracking-widest animate-bounce">
          <AlertCircle size={16} /> {validationError}
        </div>
      )}

      <div className="space-y-4">
        {list.map((item) => (
          <div key={item.id} className="glass-card p-5 rounded-[2.5rem] border-white/5 glow-gold overflow-hidden">
            {editingId === item.id ? (
              <div className="space-y-5">
                {/* Media Upload Area */}
                {activeTab === 'gallery' ? (
                  <div className="grid grid-cols-2 gap-3">
                    <div className="relative h-32 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                      {editBuffer.before && <img src={editBuffer.before} className="w-full h-full object-cover" alt="" />}
                      <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-1 text-[8px] text-white font-black uppercase tracking-widest bg-black/30"><Camera size={16}/> Before Shot*</button>
                      <input type="file" ref={mainFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'before')} />
                    </div>
                    <div className="relative h-32 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                      {editBuffer.after && <img src={editBuffer.after} className="w-full h-full object-cover" alt="" />}
                      <button onClick={() => secondaryFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-1 text-[8px] text-white font-black uppercase tracking-widest bg-black/30"><Camera size={16}/> After Shot*</button>
                      <input type="file" ref={secondaryFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'after')} />
                    </div>
                  </div>
                ) : activeTab === 'reels' ? (
                  <div className="relative h-48 bg-black/60 rounded-2xl overflow-hidden border border-white/10 flex flex-col items-center justify-center">
                    {editBuffer.url ? (
                      <video src={editBuffer.url} className="w-full h-full object-cover opacity-50" muted />
                    ) : (
                      <Film size={32} className="text-white/20 mb-2" />
                    )}
                    <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[10px] text-white font-black uppercase tracking-widest bg-black/40"><Play size={24}/> Upload Video File*</button>
                    <input type="file" ref={mainFileRef} hidden accept="video/*" onChange={(e) => handleFileUpload(e, 'url')} />
                  </div>
                ) : (
                  <div className="relative h-40 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                    {editBuffer.image && <img src={editBuffer.image} className="w-full h-full object-cover" alt="" />}
                    <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[10px] text-white font-black uppercase tracking-widest bg-black/40"><Camera size={24}/> Upload Main Picture*</button>
                    <input type="file" ref={mainFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'image')} />
                  </div>
                )}

                <div className="space-y-3">
                  <div className="space-y-1">
                    <label className="text-[8px] font-black text-[#F7E7CE]/40 uppercase tracking-widest ml-2">Name / Title (Required)*</label>
                    <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white outline-none focus:border-[#F7E7CE]" value={editBuffer.name || editBuffer.title} onChange={(e) => setEditBuffer({...editBuffer, [item.name ? 'name' : 'title']: e.target.value})} placeholder="Enter name..." />
                  </div>

                  {(activeTab === 'services' || activeTab === 'products' || activeTab === 'courses') && (
                    <div className="grid grid-cols-2 gap-3">
                      <div className="space-y-1">
                         <label className="text-[8px] font-black text-[#F7E7CE]/40 uppercase tracking-widest ml-2">Price (Rs)*</label>
                         <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.price} type="number" onChange={(e) => setEditBuffer({...editBuffer, price: Number(e.target.value)})} placeholder="Price" />
                      </div>
                      <div className="space-y-1">
                         <label className="text-[8px] font-black text-[#F7E7CE]/40 uppercase tracking-widest ml-2">Category*</label>
                         <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.category || editBuffer.level || ''} onChange={(e) => setEditBuffer({...editBuffer, [item.category ? 'category' : 'level']: e.target.value})} placeholder="Category" />
                      </div>
                    </div>
                  )}

                  {activeTab !== 'reels' && (
                    <div className="space-y-1">
                      <label className="text-[8px] font-black text-[#F7E7CE]/40 uppercase tracking-widest ml-2">Description / Bio*</label>
                      <textarea className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white h-24 resize-none" value={editBuffer.description} onChange={(e) => setEditBuffer({...editBuffer, description: e.target.value})} placeholder="Description details..." />
                    </div>
                  )}
                </div>

                <div className="flex gap-3">
                  <button onClick={saveEdit} className="flex-1 bg-green-600 text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl"><Save size={14}/> Save Entry</button>
                  <button onClick={() => { setEditingId(null); setEditBuffer(null); }} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><X size={14}/> Discard</button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 rounded-2xl overflow-hidden border border-white/10 shrink-0 bg-black/40 flex items-center justify-center shadow-lg">
                  {activeTab === 'reels' ? <Film size={24} className="text-[#F7E7CE]/40"/> : <img src={item.image || item.after || item.thumbnail} className="w-full h-full object-cover" alt="" />}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold text-white serif truncate">{item.name || item.title || 'Untitled Draft'}</p>
                  <div className="flex items-center gap-3 mt-1">
                    {item.price !== undefined && <span className="text-[9px] text-[#F7E7CE] font-black tracking-widest">Rs. {item.price.toLocaleString()}</span>}
                    <span className="text-[8px] text-white/30 uppercase tracking-widest truncate">{item.category || item.level || 'Uncategorized'}</span>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => startEditing(item)} className="p-3 bg-white/5 rounded-2xl text-[#F7E7CE]/60 hover:text-[#F7E7CE] hover:bg-white/10 transition-all"><Edit2 size={18} /></button>
                  <button onClick={() => deleteItem(item.id)} className="p-3 bg-red-400/10 rounded-2xl text-red-400/60 hover:text-red-400 hover:bg-red-400/20 transition-all"><Trash2 size={18} /></button>
                </div>
              </div>
            )}
          </div>
        ))}
        {list.length === 0 && <div className="py-20 text-center text-white/20 italic text-xs tracking-widest">No entries found. Click + to add.</div>}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-20 border-b border-[#F7E7CE]/10 flex items-center justify-between px-8 bg-[#124C34]/30 backdrop-blur-3xl sticky top-0 z-[110]">
        <Logo size="sm" />
        <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 uppercase tracking-[0.2em] hover:bg-red-400/10 transition-all">End Session</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-24">
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-10 py-2">
          {[
            { id: 'bookings', icon: <Calendar size={14} />, label: 'Bookings' },
            { id: 'orders', icon: <ShoppingBag size={14} />, label: 'Orders' },
            { id: 'services', icon: <Edit2 size={14} />, label: 'Services' },
            { id: 'products', icon: <PackageCheck size={14} />, label: 'Inventory' },
            { id: 'courses', icon: <BookOpen size={14} />, label: 'Academy' },
            { id: 'reels', icon: <Video size={14} />, label: 'Reels' },
            { id: 'gallery', icon: <ImageIcon size={14} />, label: 'Gallery' },
          ].map((t) => (
            <button 
              key={t.id} 
              onClick={() => {setActiveTab(t.id); setEditingId(null); setValidationError(null);}} 
              className={`px-5 py-4 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center gap-2.5 whitespace-nowrap ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419] shadow-xl scale-105' : 'bg-[#124C34]/40 text-[#F7E7CE]/30 border border-white/5'}`}
            >
              {t.icon} {t.label}
            </button>
          ))}
        </div>

        {activeTab === 'bookings' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Client Appointments</h3>
            {data?.bookings.map(book => (
              <div key={book.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h4 className="text-lg font-bold text-white serif">{book.serviceName}</h4>
                    <p className="text-[10px] text-[#F7E7CE]/60 mt-1 uppercase tracking-widest font-black">{book.clientName} • {book.phone}</p>
                  </div>
                  <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest ${book.status === 'Accepted' ? 'bg-green-400 text-[#0A2419]' : book.status === 'Rejected' ? 'bg-red-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{book.status}</span>
                </div>
                {book.status === 'Pending' && (
                  <div className="flex gap-3">
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Accepted'} : b))} className="flex-1 bg-green-500/20 text-green-400 py-4 rounded-2xl text-[10px] font-black uppercase flex items-center justify-center gap-2 border border-green-500/10"><CheckCircle2 size={14}/> Accept</button>
                    <button onClick={() => setters?.setBookings(p => p.map(b => b.id === book.id ? {...b, status: 'Rejected'} : b))} className="flex-1 bg-red-500/20 text-red-400 py-4 rounded-2xl text-[10px] font-black uppercase flex items-center justify-center gap-2 border border-red-500/10"><XCircle size={14}/> Reject</button>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="space-y-6">
            <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Pending Shipments</h3>
            {data?.orders.map(order => (
              <div key={order.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                <div className="flex justify-between items-start mb-4">
                  <h4 className="text-[10px] font-black text-[#F7E7CE] uppercase tracking-widest">Order ID: {order.id.slice(-6)}</h4>
                  <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase ${order.status === 'Shipped' ? 'bg-blue-400 text-[#0A2419]' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{order.status}</span>
                </div>
                <p className="text-xl font-bold text-white serif mb-1">{order.clientName}</p>
                <p className="text-[10px] text-white/40 mb-6 italic tracking-tight">{order.address}</p>
                {order.status === 'Pending' && (
                  <button onClick={() => setters?.setOrders(p => p.map(o => o.id === order.id ? {...o, status: 'Shipped'} : o))} className="w-full btn-royal py-5 rounded-2xl text-[10px] flex items-center justify-center gap-2 uppercase tracking-widest shadow-xl">Process Order <Truck size={18}/></button>
                )}
              </div>
            ))}
          </div>
        )}

        {activeTab === 'services' && renderEditableList('Salon Catalog', data?.services || [])}
        {activeTab === 'products' && renderEditableList('Inventory Boutique', data?.products || [])}
        {activeTab === 'courses' && renderEditableList('Academy Academy', data?.courses || [])}
        {activeTab === 'reels' && renderEditableList('Viral Video Studio', data?.videos || [])}
        {activeTab === 'gallery' && renderEditableList('Before & After Portfolio', data?.gallery || [])}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useRef } from 'react';
import { ShoppingBag, Calendar, Video, BookOpen, Plus, Edit2, Trash2, CheckCircle2, XCircle, Truck, PackageCheck, Image as ImageIcon, Save, X, Camera, Play, Film, AlertCircle, ChevronLeft, Phone, User, Clock, MapPin, CreditCard, Info } from 'lucide-react';
import { Service, Product, Course, VideoItem, GalleryItem, Appointment, Order } from '../types';
import Logo from '../components/Logo';

interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
  data?: {
    services: Service[];
    products: Product[];
    courses: Course[];
    videos: VideoItem[];
    gallery: GalleryItem[];
    bookings: Appointment[];
    orders: Order[];
  };
  setters?: {
    setServices: React.Dispatch<React.SetStateAction<Service[]>>;
    setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
    setCourses: React.Dispatch<React.SetStateAction<Course[]>>;
    setVideos: React.Dispatch<React.SetStateAction<VideoItem[]>>;
    setGallery: React.Dispatch<React.SetStateAction<GalleryItem[]>>;
    setBookings: React.Dispatch<React.SetStateAction<Appointment[]>>;
    setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
  };
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel, data, setters }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('bookings');

  // States
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editBuffer, setEditBuffer] = useState<any>(null);
  const [selectedDetail, setSelectedDetail] = useState<any>(null);
  const [validationError, setValidationError] = useState<string | null>(null);

  const mainFileRef = useRef<HTMLInputElement>(null);
  const secondaryFileRef = useRef<HTMLInputElement>(null);

  const handleLogin = () => {
    if (password === 'A1234567890a') onLogin?.();
    else setError('Security Clearance Failure');
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8">
        <div className="mb-12 animate-royal">
          <Logo size="xl" />
        </div>
        <div className="w-full glass-card p-10 rounded-[3rem] border-[#F7E7CE]/20 shadow-2xl max-w-sm">
          <h2 className="text-xl font-bold text-[#F7E7CE] mb-8 serif text-center uppercase tracking-widest">Command Center Login</h2>
          <div className="space-y-6">
            <input 
              type="password" 
              placeholder="Authorization Key" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full bg-[#0A2419] border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE] transition-all" 
            />
            {error && <p className="text-red-400 text-[10px] text-center uppercase font-bold tracking-[0.2em]">{error}</p>}
            <button onClick={handleLogin} className="w-full btn-royal py-5 rounded-2xl flex items-center justify-center gap-2">Verify Credential</button>
            <button onClick={onCancel} className="w-full text-[#F7E7CE]/30 py-2 text-[10px] font-bold uppercase tracking-[0.3em]">Abort Mission</button>
          </div>
        </div>
      </div>
    );
  }

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string) => {
    const file = e.target.files?.[0];
    if (file && editBuffer) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        setEditBuffer({ ...editBuffer, [field]: result });
        if (activeTab === 'reels' && field === 'url') {
          setEditBuffer((prev: any) => ({ ...prev, url: result, thumbnail: result }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const deleteItem = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!setters) return;
    if (!window.confirm("Permanently delete this item? This cannot be undone.")) return;

    if (activeTab === 'services') setters.setServices(prev => prev.filter(i => i.id !== id));
    else if (activeTab === 'products') setters.setProducts(prev => prev.filter(i => i.id !== id));
    else if (activeTab === 'courses') setters.setCourses(prev => prev.filter(i => i.id !== id));
    else if (activeTab === 'reels') setters.setVideos(prev => prev.filter(i => i.id !== id));
    else if (activeTab === 'gallery') setters.setGallery(prev => prev.filter(i => i.id !== id));

    if (editingId === id) {
      setEditingId(null);
      setEditBuffer(null);
    }
  };

  const validate = () => {
    if (!editBuffer) return false;
    const title = editBuffer.name || editBuffer.title;
    if (!title || title.trim() === '') {
      setValidationError("Name/Title is mandatory.");
      return false;
    }
    if (activeTab === 'gallery') {
      if (!editBuffer.before || !editBuffer.after) {
        setValidationError("Both Before and After images are mandatory.");
        return false;
      }
    } else if (activeTab === 'reels') {
      if (!editBuffer.url) {
        setValidationError("Video file is mandatory for reels.");
        return false;
      }
    } else {
      if (!editBuffer.image) {
        setValidationError("Main image is mandatory.");
        return false;
      }
    }
    if (['services', 'products', 'courses'].includes(activeTab)) {
      if (editBuffer.price === undefined || editBuffer.price < 0) {
        setValidationError("A valid Price is mandatory.");
        return false;
      }
      if (!editBuffer.description || editBuffer.description.trim() === '') {
        setValidationError("Description is mandatory.");
        return false;
      }
    }
    setValidationError(null);
    return true;
  };

  const saveEdit = () => {
    if (!validate()) return;
    if (!setters || !editBuffer) return;
    const updateFn = (prev: any[]) => prev.map(item => item.id === editingId ? editBuffer : item);
    if (activeTab === 'services') setters.setServices(updateFn);
    else if (activeTab === 'products') setters.setProducts(updateFn);
    else if (activeTab === 'courses') setters.setCourses(updateFn);
    else if (activeTab === 'reels') setters.setVideos(updateFn);
    else if (activeTab === 'gallery') setters.setGallery(updateFn);
    setEditingId(null);
    setEditBuffer(null);
  };

  const updateBookingStatus = (id: string, status: Appointment['status']) => {
    setters?.setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
    setSelectedDetail(prev => prev && prev.id === id ? { ...prev, status } : prev);
  };

  const updateOrderStatus = (id: string, status: Order['status']) => {
    setters?.setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
    setSelectedDetail(prev => prev && prev.id === id ? { ...prev, status } : prev);
  };

  const renderBookingDetail = (booking: Appointment) => (
    <div className="animate-in fade-in zoom-in-95 duration-300">
      <button onClick={() => setSelectedDetail(null)} className="flex items-center gap-2 text-[#F7E7CE]/60 mb-6 uppercase tracking-widest text-[10px] font-black">
        <ChevronLeft size={16} /> Back to List
      </button>
      <div className="glass-card p-8 rounded-[3rem] border-white/10 glow-gold">
        <div className="flex justify-between items-center mb-10">
          <h3 className="text-2xl font-bold text-white serif uppercase">Appointment Details</h3>
          <span className={`text-[9px] font-black px-4 py-2 rounded-full uppercase tracking-widest ${booking.status === 'Accepted' ? 'bg-green-400 text-[#0A2419]' : booking.status === 'Rejected' ? 'bg-red-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>
            {booking.status}
          </span>
        </div>

        <div className="space-y-6">
          <div className="flex items-start gap-4 p-5 bg-black/20 rounded-2xl">
            <Info size={20} className="text-[#F7E7CE] shrink-0 mt-1" />
            <div>
              <p className="text-[9px] text-white/30 uppercase tracking-[0.2em] font-black mb-1">Service Requested</p>
              <p className="text-lg font-bold text-white serif">{booking.serviceName}</p>
              <p className="text-[11px] text-[#F7E7CE] font-bold mt-1">Rs. {booking.price.toLocaleString()}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="p-5 bg-black/20 rounded-2xl">
              <User size={18} className="text-[#F7E7CE] mb-2" />
              <p className="text-[8px] text-white/30 uppercase tracking-widest font-black">Client</p>
              <p className="text-xs font-bold text-white mt-1">{booking.clientName}</p>
            </div>
            <div className="p-5 bg-black/20 rounded-2xl">
              <Phone size={18} className="text-[#F7E7CE] mb-2" />
              <p className="text-[8px] text-white/30 uppercase tracking-widest font-black">Contact</p>
              <p className="text-xs font-bold text-white mt-1">{booking.phone}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="p-5 bg-black/20 rounded-2xl">
              <Calendar size={18} className="text-[#F7E7CE] mb-2" />
              <p className="text-[8px] text-white/30 uppercase tracking-widest font-black">Date</p>
              <p className="text-xs font-bold text-white mt-1">{booking.date}</p>
            </div>
            <div className="p-5 bg-black/20 rounded-2xl">
              <Clock size={18} className="text-[#F7E7CE] mb-2" />
              <p className="text-[8px] text-white/30 uppercase tracking-widest font-black">Time Slot</p>
              <p className="text-xs font-bold text-white mt-1">{booking.time}</p>
            </div>
          </div>
        </div>

        {booking.status === 'Pending' && (
          <div className="flex gap-4 mt-12">
            <button onClick={() => updateBookingStatus(booking.id, 'Accepted')} className="flex-1 bg-green-500 text-white py-5 rounded-2xl text-[10px] font-black uppercase flex items-center justify-center gap-2 shadow-2xl active:scale-95 transition-all">
              <CheckCircle2 size={16}/> Accept Session
            </button>
            <button onClick={() => updateBookingStatus(booking.id, 'Rejected')} className="flex-1 bg-red-500/20 text-red-400 border border-red-400/20 py-5 rounded-2xl text-[10px] font-black uppercase flex items-center justify-center gap-2 active:scale-95 transition-all">
              <XCircle size={16}/> Reject
            </button>
          </div>
        )}
      </div>
    </div>
  );

  const renderOrderDetail = (order: Order) => (
    <div className="animate-in fade-in zoom-in-95 duration-300">
      <button onClick={() => setSelectedDetail(null)} className="flex items-center gap-2 text-[#F7E7CE]/60 mb-6 uppercase tracking-widest text-[10px] font-black">
        <ChevronLeft size={16} /> Back to List
      </button>
      <div className="glass-card p-8 rounded-[3rem] border-white/10 glow-gold">
        <div className="flex justify-between items-center mb-8">
          <h3 className="text-2xl font-bold text-white serif uppercase">Order Profile</h3>
          <span className={`text-[9px] font-black px-4 py-2 rounded-full uppercase tracking-widest ${order.status === 'Shipped' ? 'bg-blue-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>
            {order.status}
          </span>
        </div>

        <div className="space-y-6">
          <div className="p-6 bg-black/20 rounded-2xl border border-white/5">
            <p className="text-[8px] text-white/30 uppercase tracking-[0.2em] font-black mb-4">Ordered Artifacts</p>
            <div className="space-y-4">
              {order.items.map((it, i) => (
                <div key={i} className="flex justify-between items-center border-b border-white/5 pb-3">
                  <div className="flex items-center gap-3">
                    <img src={it.image} className="w-10 h-10 rounded-lg object-cover" />
                    <span className="text-[11px] font-bold text-white">{it.quantity}x {it.name}</span>
                  </div>
                  <span className="text-[10px] font-bold text-[#F7E7CE]">Rs. {(it.price * it.quantity).toLocaleString()}</span>
                </div>
              ))}
            </div>
            <div className="flex justify-between items-center mt-6 pt-4 border-t-2 border-white/10">
              <span className="text-[10px] font-black text-white/40 uppercase tracking-widest">Grand Total</span>
              <span className="text-xl font-black text-[#F7E7CE]">Rs. {order.total.toLocaleString()}</span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div className="p-5 bg-black/20 rounded-2xl">
               <User size={18} className="text-[#F7E7CE] mb-2" />
               <p className="text-[8px] text-white/30 uppercase tracking-widest font-black">Receiver</p>
               <p className="text-xs font-bold text-white mt-1">{order.clientName}</p>
             </div>
             <div className="p-5 bg-black/20 rounded-2xl">
               <CreditCard size={18} className="text-[#F7E7CE] mb-2" />
               <p className="text-[8px] text-white/30 uppercase tracking-widest font-black">Method</p>
               <p className="text-xs font-bold text-white mt-1">{order.paymentMethod}</p>
             </div>
          </div>

          <div className="p-5 bg-black/20 rounded-2xl">
            <MapPin size={18} className="text-[#F7E7CE] mb-2" />
            <p className="text-[8px] text-white/30 uppercase tracking-widest font-black">Shipping Address</p>
            <p className="text-xs font-bold text-white mt-2 leading-relaxed italic">{order.address}</p>
          </div>
        </div>

        {order.status === 'Pending' && (
          <button onClick={() => updateOrderStatus(order.id, 'Shipped')} className="w-full mt-12 bg-[#F7E7CE] text-[#0A2419] py-5 rounded-2xl text-[10px] font-black uppercase flex items-center justify-center gap-3 shadow-2xl active:scale-95 transition-all">
            <Truck size={20}/> Mark as Shipped
          </button>
        )}
      </div>
    </div>
  );

  const renderEditableList = (title: string, list: any[]) => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif">{title}</h3>
        <button onClick={() => {
          const newId = `item-${Date.now()}`;
          if (activeTab === 'services') setters?.setServices(p => [{ id: newId, name: '', description: '', price: 0, duration: '', category: '', image: '' }, ...p]);
          else if (activeTab === 'products') setters?.setProducts(p => [{ id: newId, name: '', price: 0, description: '', image: '', category: '' }, ...p]);
          else if (activeTab === 'courses') setters?.setCourses(p => [{ id: newId, title: '', duration: '', price: 0, description: '', image: '', level: 'Beginner' }, ...p]);
          else if (activeTab === 'reels') setters?.setVideos(p => [{ id: newId, title: '', url: '', thumbnail: '', likes: 0, type: 'video' }, ...p]);
          else if (activeTab === 'gallery') setters?.setGallery(p => [{ id: newId, title: '', before: '', after: '' }, ...p]);
          setEditingId(newId);
          setEditBuffer({ id: newId });
        }} className="bg-[#F7E7CE] text-[#0A2419] p-3 rounded-full shadow-lg active:scale-90 transition-transform"><Plus size={20} /></button>
      </div>

      {validationError && (
        <div className="mb-6 bg-red-500/10 border border-red-500/20 p-4 rounded-2xl flex items-center gap-3 text-red-400 text-[10px] font-black uppercase tracking-widest animate-bounce">
          <AlertCircle size={16} /> {validationError}
        </div>
      )}

      <div className="space-y-4">
        {list.map((item) => (
          <div key={item.id} className="glass-card p-5 rounded-[2.5rem] border-white/5 glow-gold overflow-hidden">
            {editingId === item.id ? (
              <div className="space-y-5">
                {activeTab === 'gallery' ? (
                  <div className="grid grid-cols-2 gap-3">
                    <div className="relative h-32 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                      {editBuffer.before && <img src={editBuffer.before} className="w-full h-full object-cover" />}
                      <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-1 text-[8px] text-white font-black uppercase tracking-widest bg-black/30"><Camera size={16}/> Before*</button>
                      <input type="file" ref={mainFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'before')} />
                    </div>
                    <div className="relative h-32 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                      {editBuffer.after && <img src={editBuffer.after} className="w-full h-full object-cover" />}
                      <button onClick={() => secondaryFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-1 text-[8px] text-white font-black uppercase tracking-widest bg-black/30"><Camera size={16}/> After*</button>
                      <input type="file" ref={secondaryFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'after')} />
                    </div>
                  </div>
                ) : activeTab === 'reels' ? (
                  <div className="relative h-48 bg-black/60 rounded-2xl overflow-hidden border border-white/10 flex flex-col items-center justify-center">
                    {editBuffer.url ? <video src={editBuffer.url} className="w-full h-full object-cover opacity-50" muted /> : <Film size={32} className="text-white/20 mb-2" />}
                    <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[10px] text-white font-black uppercase tracking-widest bg-black/40"><Play size={24}/> Upload Video*</button>
                    <input type="file" ref={mainFileRef} hidden accept="video/*" onChange={(e) => handleFileUpload(e, 'url')} />
                  </div>
                ) : (
                  <div className="relative h-40 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                    {editBuffer.image && <img src={editBuffer.image} className="w-full h-full object-cover" />}
                    <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[10px] text-white font-black uppercase tracking-widest bg-black/40"><Camera size={24}/> Upload Photo*</button>
                    <input type="file" ref={mainFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'image')} />
                  </div>
                )}
                <div className="space-y-3">
                  <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.name || editBuffer.title || ''} onChange={(e) => setEditBuffer({...editBuffer, [item.name ? 'name' : 'title']: e.target.value})} placeholder="Title / Name (Laxmi)*" />
                  {['services', 'products', 'courses'].includes(activeTab) && (
                    <div className="grid grid-cols-2 gap-3">
                      <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.price || ''} type="number" onChange={(e) => setEditBuffer({...editBuffer, price: Number(e.target.value)})} placeholder="Price (Laxmi)*" />
                      <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.category || editBuffer.level || ''} onChange={(e) => setEditBuffer({...editBuffer, [item.category ? 'category' : 'level']: e.target.value})} placeholder="Category/Level*" />
                    </div>
                  )}
                  {activeTab !== 'reels' && <textarea className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white h-24 resize-none" value={editBuffer.description || ''} onChange={(e) => setEditBuffer({...editBuffer, description: e.target.value})} placeholder="Description (Laxmi)*" />}
                </div>
                <div className="flex gap-3">
                  <button onClick={saveEdit} className="flex-1 bg-green-600 text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl"><Save size={14}/> Save</button>
                  <button onClick={() => { setEditingId(null); setEditBuffer(null); setValidationError(null); }} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2"><X size={14}/> Discard</button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 rounded-2xl overflow-hidden border border-white/10 shrink-0 bg-black/40 flex items-center justify-center shadow-lg">
                  {activeTab === 'reels' ? <Film size={24} className="text-[#F7E7CE]/40"/> : <img src={item.image || item.after || item.thumbnail} className="w-full h-full object-cover" />}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold text-white serif truncate">{item.name || item.title || 'Draft'}</p>
                  <div className="flex items-center gap-3 mt-1">
                    {item.price !== undefined && <span className="text-[9px] text-[#F7E7CE] font-black">Rs. {item.price.toLocaleString()}</span>}
                    <span className="text-[8px] text-white/30 uppercase tracking-widest">{item.category || item.level || 'Portfolio'}</span>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => { setEditingId(item.id); setEditBuffer({ ...item }); setValidationError(null); }} className="p-3 bg-white/5 rounded-2xl text-[#F7E7CE]/60 hover:text-[#F7E7CE] transition-all"><Edit2 size={18} /></button>
                  <button onClick={(e) => deleteItem(item.id, e)} className="p-3 bg-red-400/10 rounded-2xl text-red-400/60 hover:text-red-400 transition-all"><Trash2 size={18} /></button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-20 border-b border-[#F7E7CE]/10 flex items-center justify-between px-8 bg-[#124C34]/30 backdrop-blur-3xl sticky top-0 z-[110]">
        <Logo size="sm" />
        <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 uppercase tracking-[0.2em] hover:bg-red-400/10">Log Out</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-24">
        {selectedDetail ? (
          activeTab === 'bookings' ? renderBookingDetail(selectedDetail) : renderOrderDetail(selectedDetail)
        ) : (
          <>
            <div className="flex gap-2 overflow-x-auto no-scrollbar mb-10 py-2">
              {[
                { id: 'bookings', icon: <Calendar size={14} />, label: 'Bookings' },
                { id: 'orders', icon: <ShoppingBag size={14} />, label: 'Orders' },
                { id: 'services', icon: <Edit2 size={14} />, label: 'Services' },
                { id: 'products', icon: <PackageCheck size={14} />, label: 'Inventory' },
                { id: 'courses', icon: <BookOpen size={14} />, label: 'Academy' },
                { id: 'reels', icon: <Video size={14} />, label: 'Reels' },
                { id: 'gallery', icon: <ImageIcon size={14} />, label: 'Gallery' },
              ].map((t) => (
                <button 
                  key={t.id} 
                  onClick={() => {setActiveTab(t.id); setEditingId(null); setSelectedDetail(null); setValidationError(null);}} 
                  className={`px-5 py-4 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center gap-2.5 whitespace-nowrap ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419] shadow-xl scale-105' : 'bg-[#124C34]/40 text-[#F7E7CE]/30 border border-white/5'}`}
                >
                  {t.icon} {t.label}
                </button>
              ))}
            </div>

            {activeTab === 'bookings' && (
              <div className="space-y-6">
                <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Pending Sessions</h3>
                {data?.bookings.map(book => (
                  <div key={book.id} onClick={() => setSelectedDetail(book)} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold cursor-pointer active:scale-[0.98] transition-all">
                    <div className="flex justify-between items-start">
                      <div>
                        <h4 className="text-lg font-bold text-white serif">{book.serviceName}</h4>
                        <p className="text-[10px] text-[#F7E7CE]/60 mt-1 uppercase tracking-widest font-black">{book.clientName}</p>
                      </div>
                      <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest ${book.status === 'Accepted' ? 'bg-green-400 text-[#0A2419]' : book.status === 'Rejected' ? 'bg-red-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{book.status}</span>
                    </div>
                    <div className="mt-4 flex items-center gap-4 text-[9px] text-white/40 uppercase tracking-widest">
                       <span className="flex items-center gap-1"><Calendar size={12}/> {book.date}</span>
                       <span className="flex items-center gap-1"><Clock size={12}/> {book.time}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'orders' && (
              <div className="space-y-6">
                <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Pending Artifacts</h3>
                {data?.orders.map(order => (
                  <div key={order.id} onClick={() => setSelectedDetail(order)} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold cursor-pointer active:scale-[0.98] transition-all">
                    <div className="flex justify-between items-start mb-4">
                      <h4 className="text-[10px] font-black text-[#F7E7CE] uppercase tracking-widest">#{order.id.slice(-6)}</h4>
                      <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase ${order.status === 'Shipped' ? 'bg-blue-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{order.status}</span>
                    </div>
                    <p className="text-xl font-bold text-white serif mb-1">{order.clientName}</p>
                    <p className="text-[10px] text-white/40 italic truncate">{order.address}</p>
                    <div className="mt-4 pt-4 border-t border-white/5 flex justify-between items-center">
                       <span className="text-[9px] text-[#F7E7CE] font-black uppercase tracking-widest">{order.items.length} items</span>
                       <span className="text-sm font-bold text-white">Rs. {order.total.toLocaleString()}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'services' && renderEditableList('Salon Menu', data?.services || [])}
            {activeTab === 'products' && renderEditableList('Inventory', data?.products || [])}
            {activeTab === 'courses' && renderEditableList('Academy', data?.courses || [])}
            {activeTab === 'reels' && renderEditableList('Reels', data?.videos || [])}
            {activeTab === 'gallery' && renderEditableList('Gallery', data?.gallery || [])}
          </>
        )}
      </div>
    </div>
  );
};

