import React, { useState } from 'react';
import { Play, Heart, Share2, Crown, Film } from 'lucide-react';
import { VideoItem, GalleryItem } from '../types';

interface ViralScreenProps {
  videos: VideoItem[];
  gallery: GalleryItem[];
}

const ViralScreen: React.FC<ViralScreenProps> = ({ videos, gallery }) => {
  const [likedVideos, setLikedVideos] = useState<Set<string>>(new Set());
  const [animatingId, setAnimatingId] = useState<string | null>(null);

  const handleLike = (id: string) => {
    setAnimatingId(id);
    setLikedVideos(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
    setTimeout(() => setAnimatingId(null), 400);
  };

  const handleShare = (title: string) => {
    if (navigator.share) {
      navigator.share({
        title: 'Aneelas MakeOver - ' + title,
        text: 'Check out this masterpiece at Aneelas MakeOver!',
        url: window.location.href,
      }).catch(console.error);
    } else {
      alert("Sharing " + title);
    }
  };

  return (
    <div className="animate-in slide-in-from-right-10 duration-500 pb-10">
      <div className="mb-8">
        <h2 className="text-2xl font-bold text-[#F7E7CE] serif uppercase tracking-wider">The Reel Studio</h2>
        <p className="text-xs text-[#F7E7CE]/60 uppercase tracking-widest mt-1">Experience Perfection in Motion</p>
      </div>

      <div className="flex gap-4 overflow-x-auto no-scrollbar pb-6 px-1">
        {videos.length === 0 && <div className="text-white/20 italic text-xs py-10">No cinematic reels available.</div>}
        {videos.map((vid) => (
          <div key={vid.id} className="min-w-[280px] h-[500px] relative rounded-[2.8rem] overflow-hidden group glow-gold bg-black shadow-2xl">
            {vid.url ? (
              <video 
                src={vid.url} 
                className="absolute inset-0 w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" 
                autoPlay 
                muted 
                loop 
                playsInline 
              />
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-white/10 gap-4">
                 <Film size={60} />
                 <span className="text-[10px] uppercase tracking-widest font-black">Video Processing</span>
              </div>
            )}

            <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent flex flex-col justify-end p-8">
              <h4 className="text-lg font-bold text-white mb-3 serif tracking-wide">{vid.title}</h4>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-6">
                  <button 
                    onClick={() => handleLike(vid.id)}
                    className={`flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest transition-all duration-300 active:scale-125 ${
                      likedVideos.has(vid.id) ? 'text-[#F7E7CE]' : 'text-white/80'
                    }`}
                  >
                    <Heart 
                      size={18} 
                      fill={likedVideos.has(vid.id) ? "#F7E7CE" : "transparent"} 
                      className={`transition-all duration-500 ${animatingId === vid.id ? 'scale-150 animate-bounce' : 'scale-100'}`} 
                    /> 
                    {vid.likes + (likedVideos.has(vid.id) ? 1 : 0)}
                  </button>
                  <button 
                    onClick={() => handleShare(vid.title)}
                    className="flex items-center gap-1.5 text-[10px] font-black text-white/80 uppercase tracking-widest hover:text-[#F7E7CE] active:scale-90 transition-all duration-300"
                  >
                    <Share2 size={18} className="hover:rotate-12 transition-transform" /> Share
                  </button>
                </div>
                <div className="w-10 h-10 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center border border-white/20 active:scale-110 transition-transform cursor-pointer">
                   <Play size={16} fill="white" className="text-white ml-0.5" />
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="mt-14 flex items-center gap-3 mb-8">
        <div className="w-10 h-10 rounded-full bg-[#F7E7CE]/10 flex items-center justify-center">
           <Crown className="text-[#F7E7CE]" size={20} />
        </div>
        <h3 className="text-xl font-bold text-[#F7E7CE] serif uppercase tracking-widest">Master Artifacts</h3>
      </div>

      <div className="grid gap-10">
        {gallery.map((item) => (
          <div key={item.id} className="glass-card rounded-[3rem] overflow-hidden p-4 glow-gold">
            <div className="flex h-[320px] gap-2">
              <div className="flex-1 relative group rounded-2xl overflow-hidden">
                <img src={item.before} className="w-full h-full object-cover brightness-75 transition-all group-hover:brightness-100" alt="" />
                <div className="absolute top-4 left-4 bg-black/80 px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-[0.2em] text-white/80 border border-white/10 backdrop-blur-md">Before</div>
              </div>
              <div className="flex-1 relative group rounded-2xl overflow-hidden border border-[#F7E7CE]/20">
                <img src={item.after} className="w-full h-full object-cover transition-transform duration-[4s] group-hover:scale-110" alt="" />
                <div className="absolute top-4 right-4 bg-[#F7E7CE] text-[#0A2419] px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-[0.2em] shadow-xl">After Perfection</div>
              </div>
            </div>
            <div className="pt-6 pb-2 text-center">
              <h4 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.3em] serif">{item.title}</h4>
              <p className="text-[8px] text-white/30 uppercase mt-2 tracking-widest">Artistry by Aneela</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

