                       <textarea className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white h-20 resize-none" value={editBuffer.highlights?.join(', ') || ''} onChange={(e) => setEditBuffer({...editBuffer, highlights: e.target.value.split(',').map(s => s.trim()).filter(s => s !== '')})} placeholder="Enter highlights separated by commas..." />
                    </div>
                  )}

                  {activeTab === 'services' && (
                    <div className="space-y-3 p-4 bg-white/5 rounded-2xl border border-white/5">
