                        <span className="text-[9px] font-black text-[#F7E7CE] uppercase tracking-widest">Transformation Preview</span>
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                        <div className="relative aspect-square bg-black/40 rounded-xl overflow-hidden border border-white/10">
                          {editBuffer.transformations?.[0]?.before && <img src={editBuffer.transformations[0].before} className="w-full h-full object-cover" />}
                          <button onClick={() => transBeforeRef.current?.click()} className="absolute inset-0 bg-black/30 text-[7px] text-white font-black uppercase flex items-center justify-center">Before Image</button>
                          <input type="file" ref={transBeforeRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'before', true)} />
                        </div>
                        <div className="relative aspect-square bg-black/40 rounded-xl overflow-hidden border border-white/10">
                          {editBuffer.transformations?.[0]?.after && <img src={editBuffer.transformations[0].after} className="w-full h-full object-cover" />}
                          <button onClick={() => transAfterRef.current?.click()} className="absolute inset-0 bg-black/30 text-[7px] text-white font-black uppercase flex items-center justify-center">After Image</button>
                          <input type="file" ref={transAfterRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, 'after', true)} />
                        </div>
                      </div>
                    </div>
                  )}

                  {activeTab !== 'reels' && <textarea className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white h-24 resize-none" value={editBuffer.description || ''} onChange={(e) => setEditBuffer({...editBuffer, description: e.target.value})} placeholder="Detailed Description*" />}
                </div>

                <div className="flex gap-3">
                  <button onClick={saveEdit} className="flex-1 bg-green-600 text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl"><Save size={14}/> Save</button>
                  <button onClick={() => { setEditingId(null); setEditBuffer(null); setValidationError(null); }} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2"><X size={14}/> Discard</button>
