            ) : (
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 rounded-2xl overflow-hidden border border-white/10 shrink-0 bg-black/40 flex items-center justify-center shadow-lg">
                  {activeTab === 'reels' ? <Film size={24} className="text-[#F7E7CE]/40"/> : <img src={item.image || (item.transformations?.[0]?.after) || item.after || item.thumbnail} className="w-full h-full object-cover" />}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold text-white serif truncate">{item.name || item.title || 'Draft'}</p>
                  <div className="flex items-center gap-3 mt-1">
                    {item.price !== undefined && <span className="text-[9px] text-[#F7E7CE] font-black">Rs. {item.price.toLocaleString()}</span>}
                    <span className="text-[8px] text-white/30 uppercase tracking-widest">{item.category || item.level || 'Portfolio'}</span>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => { setEditingId(item.id); setEditBuffer({ ...item }); setValidationError(null); }} className="p-3 bg-white/5 rounded-2xl text-[#F7E7CE]/60 hover:text-[#F7E7CE] transition-all"><Edit2 size={18} /></button>
                  <button onClick={(e) => deleteItem(item.id, e)} className="p-3 bg-red-400/10 rounded-2xl text-red-400/60 hover:text-red-400 transition-all"><Trash2 size={18} /></button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
      <header className="h-20 border-b border-[#F7E7CE]/10 flex items-center justify-between px-8 bg-[#124C34]/30 backdrop-blur-3xl sticky top-0 z-[110]">
        <Logo size="sm" />
        <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 uppercase tracking-[0.2em] hover:bg-red-400/10">Log Out</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-24">
        {selectedDetail ? (
          activeTab === 'bookings' ? renderBookingDetail(selectedDetail) : renderOrderDetail(selectedDetail)
        ) : (
          <>
            <div className="flex gap-2 overflow-x-auto no-scrollbar mb-10 py-2">
              {[
                { id: 'bookings', icon: <Calendar size={14} />, label: 'Bookings' },
                { id: 'orders', icon: <ShoppingBag size={14} />, label: 'Orders' },
                { id: 'feedbacks', icon: <MessageSquare size={14} />, label: 'Feedback' },
                { id: 'services', icon: <Edit2 size={14} />, label: 'Services' },
                { id: 'products', icon: <PackageCheck size={14} />, label: 'Inventory' },
                { id: 'courses', icon: <BookOpen size={14} />, label: 'Academy' },
                { id: 'reels', icon: <Video size={14} />, label: 'Reels' },
                { id: 'gallery', icon: <ImageIcon size={14} />, label: 'Gallery' },
              ].map((t) => (
                <button 
                  key={t.id} 
                  onClick={() => {setActiveTab(t.id); setEditingId(null); setSelectedDetail(null); setValidationError(null);}} 
                  className={`px-5 py-4 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center gap-2.5 whitespace-nowrap ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419] shadow-xl scale-105' : 'bg-[#124C34]/40 text-[#F7E7CE]/30 border border-white/5'}`}
                >
                  {t.icon} {t.label}
                </button>
              ))}
            </div>

            {activeTab === 'feedbacks' && (
              <div className="space-y-6">
                <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Client Voices</h3>
                {data?.feedbacks.length === 0 && <p className="text-white/20 italic text-xs py-20 text-center uppercase tracking-widest">No feedback received yet.</p>}
                {data?.feedbacks.map(fb => (
                  <div key={fb.id} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h4 className="text-lg font-bold text-white serif">{fb.userName}</h4>
                        <p className="text-[10px] text-[#F7E7CE]/60 font-black uppercase tracking-widest">{fb.userPhone || 'Anonymous'}</p>
                      </div>
                      <div className="flex gap-0.5">
                        {[1, 2, 3, 4, 5].map(s => (
                          <Star key={s} size={12} fill={s <= fb.rating ? "#F7E7CE" : "transparent"} className={s <= fb.rating ? "text-[#F7E7CE]" : "text-white/10"} />
                        ))}
                      </div>
                    </div>
                    <p className="text-xs text-[#F3F3F3]/80 leading-relaxed italic border-l border-white/10 pl-4 py-1 mb-4">{fb.message}</p>
                    <div className="flex justify-between items-center">
                      <span className="text-[8px] text-white/30 uppercase tracking-widest">{fb.date}</span>
                      <button onClick={(e) => deleteItem(fb.id, e)} className="text-red-400/40 hover:text-red-400 transition-colors">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'bookings' && (
              <div className="space-y-6">
                <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Pending Sessions</h3>
                {data?.bookings.map(book => (
                  <div key={book.id} onClick={() => setSelectedDetail(book)} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold cursor-pointer active:scale-[0.98] transition-all">
                    <div className="flex justify-between items-start">
                      <div>
                        <h4 className="text-lg font-bold text-white serif">{book.serviceName}</h4>
                        <p className="text-[10px] text-[#F7E7CE]/60 mt-1 uppercase tracking-widest font-black">{book.clientName}</p>
                      </div>
                      <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest ${book.status === 'Accepted' ? 'bg-green-400 text-[#0A2419]' : book.status === 'Rejected' ? 'bg-red-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{book.status}</span>
                    </div>
                    <div className="mt-4 flex items-center gap-4 text-[9px] text-white/40 uppercase tracking-widest">
                       <span className="flex items-center gap-1"><Calendar size={12}/> {book.date}</span>
                       <span className="flex items-center gap-1"><Clock size={12}/> {book.time}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'orders' && (
              <div className="space-y-6">
                <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif mb-8">Pending Artifacts</h3>
                {data?.orders.map(order => (
                  <div key={order.id} onClick={() => setSelectedDetail(order)} className="glass-card p-6 rounded-[2.5rem] border-white/5 glow-gold cursor-pointer active:scale-[0.98] transition-all">
                    <div className="flex justify-between items-start mb-4">
                      <h4 className="text-[10px] font-black text-[#F7E7CE] uppercase tracking-widest">#{order.id.slice(-6)}</h4>
                      <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase ${order.status === 'Shipped' ? 'bg-blue-400 text-white' : 'bg-[#F7E7CE] text-[#0A2419]'}`}>{order.status}</span>
                    </div>
                    <p className="text-xl font-bold text-white serif mb-1">{order.clientName}</p>
                    <p className="text-[10px] text-white/40 italic truncate">{order.address}</p>
                    <div className="mt-4 pt-4 border-t border-white/5 flex justify-between items-center">
                       <span className="text-[9px] text-[#F7E7CE] font-black uppercase tracking-widest">{order.items.length} items</span>
                       <span className="text-sm font-bold text-white">Rs. {order.total.toLocaleString()}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'services' && renderEditableList('Salon Menu', data?.services || [])}
            {activeTab === 'products' && renderEditableList('Inventory', data?.products || [])}
            {activeTab === 'courses' && renderEditableList('Academy', data?.courses || [])}
            {activeTab === 'reels' && renderEditableList('Reels', data?.videos || [])}
            {activeTab === 'gallery' && renderEditableList('Gallery', data?.gallery || [])}
          </>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState } from 'react';
import { Bell, ShoppingBag, Search } from 'lucide-react';
import Logo from './Logo';

interface HeaderProps {
  onAdminTrigger?: () => void;
  cartCount: number;
  onCartClick: () => void;
}

const Header: React.FC<HeaderProps> = ({ onAdminTrigger, cartCount, onCartClick }) => {
  const [tapCount, setTapCount] = useState(0);

  const handleLogoTap = () => {
    const newCount = tapCount + 1;
    setTapCount(newCount);
    if (newCount === 6) {
      onAdminTrigger?.();
      setTapCount(0);
    }
    setTimeout(() => setTapCount(0), 3000);
  };

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-[#0A2419]/95 backdrop-blur-2xl z-50 flex items-center justify-between px-6 border-b border-[#F7E7CE]/10 shadow-lg">
      <div className="flex items-center gap-3 cursor-pointer group" onClick={handleLogoTap}>
        <div className="relative w-10 h-10 rounded-full border border-[#F7E7CE]/30 overflow-hidden shadow-inner glow-gold flex-shrink-0">
          <img 
            src="https://images.unsplash.com/photo-1595152772835-219674b2a8a6?q=80&w=150&h=150&auto=format&fit=crop" 
            alt="Aneela Master Stylist" 
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
          />
        </div>
        <div className="hidden xs:block">
          <Logo size="sm" />
        </div>
      </div>

      <div className="flex items-center gap-5">
        <button className="text-[#F3F3F3] hover:text-[#F7E7CE] transition-colors">
          <Search size={20} strokeWidth={1.5} />
        </button>
        <button 
          onClick={onCartClick}
          className="text-[#F3F3F3] hover:text-[#F7E7CE] transition-colors relative"
        >
          <ShoppingBag size={20} strokeWidth={1.5} />
          {cartCount > 0 && (
            <span className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-[#F7E7CE] text-[#0A2419] rounded-full text-[9px] font-bold flex items-center justify-center">
              {cartCount}
            </span>
          )}
        </button>
        <button className="text-[#F3F3F3] hover:text-[#F7E7CE] transition-colors relative">
          <Bell size={20} strokeWidth={1.5} />
          <span className="absolute top-0 right-0 w-1.5 h-1.5 bg-[#E1B84F] rounded-full"></span>
        </button>
      </div>
    </header>
  );
};

export default Header;

export const ICON_URL = 'https://images.unsplash.com/photo-1595152772835-219674b2a8a6?q=80&w=150&h=150&auto=format&fit=crop';

export const requestNotificationPermission = async (): Promise<boolean> => {
  if (!('Notification' in window)) {
    console.warn("This browser does not support notifications.");
    return false;
  }

  if (Notification.permission === 'granted') return true;

  const permission = await Notification.requestPermission();
  return permission === 'granted';
};

export const sendNotification = (title: string, body: string, tag?: string) => {
  if (Notification.permission === 'granted') {
    new Notification(title, {
      body,
      icon: ICON_URL,
      tag: tag || 'aneela-makeover',
      badge: ICON_URL,
    });
  }
};

export const scheduleReminder = (title: string, body: string, delayMs: number) => {
  setTimeout(() => {
    sendNotification(title, body);
  }, delayMs);
};

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import Logo from './components/Logo';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import ServiceDetailScreen from './screens/ServiceDetailScreen';
import ProductDetailScreen from './screens/ProductDetailScreen';
import CourseDetailScreen from './screens/CourseDetailScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import FeedbackScreen from './screens/FeedbackScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import { MOCK_SERVICES, MOCK_PRODUCTS, MOCK_COURSES, MOCK_VIDEOS, MOCK_GALLERY } from './constants';
import { CartItem, Service, Product, Course, VideoItem, GalleryItem, Appointment, Order, Feedback } from './types';
import { MessageCircle } from 'lucide-react';
import { sendNotification, requestNotificationPermission } from './services/notificationService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [loading, setLoading] = useState(true);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<CartItem[] | null>(null);
  const [bookingService, setBookingService] = useState<Service | null>(null);
  const [selectedServiceDetail, setSelectedServiceDetail] = useState<Service | null>(null);
  const [selectedProductDetail, setSelectedProductDetail] = useState<Product | null>(null);
  const [selectedCourseDetail, setSelectedCourseDetail] = useState<Course | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  // Business Data State
  const [services, setServices] = useState<Service[]>(MOCK_SERVICES);
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [courses, setCourses] = useState<Course[]>(MOCK_COURSES);
  const [videos, setVideos] = useState<VideoItem[]>(MOCK_VIDEOS);
  const [gallery, setGallery] = useState<GalleryItem[]>(MOCK_GALLERY);

  // Operational Data State
  const [bookings, setBookings] = useState<Appointment[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [feedbacks, setFeedbacks] = useState<Feedback[]>([]);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 3000);
    return () => clearTimeout(timer);
  }, []);

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
  };

  const handleBookingConfirm = (appointment: Appointment) => {
    setBookings(prev => [appointment, ...prev]);
    sendNotification(
      "Reservation Confirmed ✨",
      `Your session for ${appointment.serviceName} is secured for ${appointment.date} at ${appointment.time}.`
    );
  };

  const handleOrderConfirm = (order: Order) => {
    setOrders(prev => [order, ...prev]);
    setCartItems([]);
    sendNotification(
      "Luxury Order Placed 🛍️",
      `Thank you ${order.clientName}! Your order #${order.id.slice(-6)} is being prepared for perfection.`
    );
  };

  const handleFeedbackSubmit = (fb: Feedback) => {
    setFeedbacks(prev => [fb, ...prev]);
  };

  const openWhatsApp = () => {
    window.open('https://wa.me/923134528585', '_blank');
  };

  if (loading) {
    return (
      <div className="h-screen w-screen bg-[#0A2419] flex flex-col items-center justify-center relative overflow-hidden">
        <div className="absolute inset-0 opacity-20">
          <div className="absolute top-[-20%] left-[-20%] w-[60%] h-[60%] bg-[#F7E7CE] rounded-full blur-[150px] animate-pulse"></div>
          <div className="absolute bottom-[-20%] right-[-20%] w-[60%] h-[60%] bg-[#F7E7CE] rounded-full blur-[150px] animate-pulse delay-1000"></div>
        </div>

        <div className="relative z-10 transform scale-125 animate-royal">
           <Logo size="xl" />
        </div>

        <div className="mt-24 w-64 h-0.5 bg-white/5 rounded-full overflow-hidden relative">
          <div className="absolute top-0 left-0 h-full gold-gradient animate-[progress_3s_ease-in-out_infinite]" style={{ width: '100%' }}></div>
        </div>

        <div className="mt-10 text-[#F7E7CE] text-[10px] font-bold tracking-[0.8em] uppercase flex flex-col items-center gap-3">
           <span className="animate-pulse">Curating Perfection</span>
           <div className="flex gap-1.5">
             <div className="w-1.5 h-1.5 bg-[#F7E7CE] rounded-full animate-bounce [animation-delay:-0.3s]"></div>
             <div className="w-1.5 h-1.5 bg-[#F7E7CE] rounded-full animate-bounce [animation-delay:-0.15s]"></div>
             <div className="w-1.5 h-1.5 bg-[#F7E7CE] rounded-full animate-bounce"></div>
           </div>
        </div>

        <style>{`
          @keyframes progress {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(100%); }
          }
        `}</style>
      </div>
    );
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return (
      <AdminPanel 
        isFullPanel 
        onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }}
        data={{ services, products, courses, videos, gallery, bookings, orders, feedbacks }}
        setters={{ setServices, setProducts, setCourses, setVideos, setGallery, setBookings, setOrders, setFeedbacks }}
      />
    );
  }

  const renderScreen = () => {
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={(id) => setCartItems(p => p.filter(i => i.id !== id))} onUpdateQty={(id, d) => setCartItems(p => p.map(i => i.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={handleOrderConfirm} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} onConfirm={handleBookingConfirm} />;
    if (showFeedback) return <FeedbackScreen onBack={() => setShowFeedback(false)} onSubmit={handleFeedbackSubmit} />;
    if (selectedServiceDetail) return <ServiceDetailScreen service={selectedServiceDetail} onBack={() => setSelectedServiceDetail(null)} onBook={(s) => { setSelectedServiceDetail(null); setBookingService(s); }} />;
    if (selectedProductDetail) return <ProductDetailScreen product={selectedProductDetail} onBack={() => setSelectedProductDetail(null)} onAddToCart={addToCart} />;
    if (selectedCourseDetail) return <CourseDetailScreen course={selectedCourseDetail} onBack={() => setSelectedCourseDetail(null)} onEnroll={addToCart} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} onOpenFeedback={() => setShowFeedback(true)} />;
      case 'services': return <ServicesScreen services={services} onBook={(s) => setBookingService(s)} onViewDetails={(s) => setSelectedServiceDetail(s)} />;
      case 'store': return <StoreScreen products={products} courses={courses} onAddToCart={addToCart} onViewProduct={setSelectedProductDetail} onViewCourse={setSelectedCourseDetail} />;
      case 'viral': return <ViralScreen videos={videos} gallery={gallery} />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen gallery={gallery} />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} onOpenFeedback={() => setShowFeedback(true)} />;
    }
  };

  const showGlobalUI = !checkoutItem && !bookingService && !showCart && !selectedServiceDetail && !selectedProductDetail && !selectedCourseDetail && !showFeedback;

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      <Header 
        onAdminTrigger={handleAdminTrigger} 
        cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} 
        onCartClick={() => setShowCart(true)} 
      />
      <main className="flex-1 pb-24 pt-20 px-4 max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal">
        {renderScreen()}
      </main>

      {showGlobalUI && (
        <>
          <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
          {/* WhatsApp Floating Button */}
          <button 
            onClick={openWhatsApp}
            className="fixed bottom-24 right-6 z-[60] w-14 h-14 gold-gradient text-[#0A2419] rounded-full flex items-center justify-center shadow-[0_10px_30px_rgba(0,0,0,0.5)] active:scale-90 transition-all hover:scale-110 group border-2 border-white/10"
            aria-label="Connect on WhatsApp"
          >
            <div className="absolute inset-0 bg-[#F7E7CE] rounded-full animate-ping opacity-20 group-hover:opacity-40"></div>
            <MessageCircle size={28} />
          </button>
        </>
      )}
    </div>
  );
};

export default App;

