                <div className="space-y-3">
                  <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.name || editBuffer.title || ''} onChange={(e) => setEditBuffer({...editBuffer, [editBuffer.name !== undefined ? 'name' : 'title']: e.target.value})} placeholder="Title / Name*" />

                  {['services', 'products', 'courses'].includes(activeTab) && (
                    <div className="grid grid-cols-2 gap-3">
                      <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.price || ''} type="number" onChange={(e) => setEditBuffer({...editBuffer, price: Number(e.target.value)})} placeholder="Price (PKR)*" />
                      <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.category || editBuffer.level || ''} onChange={(e) => setEditBuffer({...editBuffer, [editBuffer.category !== undefined ? 'category' : 'level']: e.target.value})} placeholder="Category/Level*" />
                    </div>
