                       <Clock size={16} className="text-[#F7E7CE] shrink-0" />
                       <input className="flex-1 bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.duration || ''} onChange={(e) => setEditBuffer({...editBuffer, duration: e.target.value})} placeholder="Duration (e.g. 4h, 3 Months)*" />
