          <button onClick={handlePlaceOrder} className="w-full btn-royal py-5 rounded-2xl shadow-2xl active:scale-95 transition-all text-[11px] font-black uppercase tracking-[0.3em]">
            Authorize Order
          </button>
        </div>
      </div>
    </div>
  );
};

