import ServiceDetailScreen from './screens/ServiceDetailScreen';
import ProductDetailScreen from './screens/ProductDetailScreen';
import CourseDetailScreen from './screens/CourseDetailScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import FeedbackScreen from './screens/FeedbackScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import { MOCK_SERVICES, MOCK_PRODUCTS, MOCK_COURSES, MOCK_VIDEOS, MOCK_GALLERY } from './constants';
import { CartItem, Service, Product, Course, VideoItem, GalleryItem, Appointment, Order, Feedback } from './types';
import { MessageCircle, CloudSync } from 'lucide-react';
import { sendNotification, requestNotificationPermission } from './services/notificationService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [loading, setLoading] = useState(true);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<CartItem[] | null>(null);
  const [bookingService, setBookingService] = useState<Service | null>(null);
  const [selectedServiceDetail, setSelectedServiceDetail] = useState<Service | null>(null);
  const [selectedProductDetail, setSelectedProductDetail] = useState<Product | null>(null);
  const [selectedCourseDetail, setSelectedCourseDetail] = useState<Course | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  // Business Data State initialized from LocalStorage or Mocks
  const [services, setServices] = useState<Service[]>(() => JSON.parse(localStorage.getItem('aneela_services') || JSON.stringify(MOCK_SERVICES)));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('aneela_products') || JSON.stringify(MOCK_PRODUCTS)));
  const [courses, setCourses] = useState<Course[]>(() => JSON.parse(localStorage.getItem('aneela_courses') || JSON.stringify(MOCK_COURSES)));
  const [videos, setVideos] = useState<VideoItem[]>(() => JSON.parse(localStorage.getItem('aneela_videos') || JSON.stringify(MOCK_VIDEOS)));
  const [gallery, setGallery] = useState<GalleryItem[]>(() => JSON.parse(localStorage.getItem('aneela_gallery') || JSON.stringify(MOCK_GALLERY)));

  // Operational Data State
  const [bookings, setBookings] = useState<Appointment[]>(() => JSON.parse(localStorage.getItem('aneela_bookings') || '[]'));
  const [orders, setOrders] = useState<Order[]>(() => JSON.parse(localStorage.getItem('aneela_orders') || '[]'));
  const [feedbacks, setFeedbacks] = useState<Feedback[]>(() => JSON.parse(localStorage.getItem('aneela_feedbacks') || '[]'));

  // Sync state to LocalStorage whenever it changes
  useEffect(() => {
    localStorage.setItem('aneela_services', JSON.stringify(services));
    localStorage.setItem('aneela_products', JSON.stringify(products));
    localStorage.setItem('aneela_courses', JSON.stringify(courses));
    localStorage.setItem('aneela_videos', JSON.stringify(videos));
    localStorage.setItem('aneela_gallery', JSON.stringify(gallery));
    localStorage.setItem('aneela_bookings', JSON.stringify(bookings));
    localStorage.setItem('aneela_orders', JSON.stringify(orders));
    localStorage.setItem('aneela_feedbacks', JSON.stringify(feedbacks));
  }, [services, products, courses, videos, gallery, bookings, orders, feedbacks]);

  // Listen for storage changes from other tabs/instances
  useEffect(() => {
    const handleStorageChange = (e: StorageEvent) => {
      if (!e.newValue) return;
      const val = JSON.parse(e.newValue);
      switch (e.key) {
        case 'aneela_services': setServices(val); break;
        case 'aneela_products': setProducts(val); break;
