import { initializeApp } from "firebase/app";
import { getFirestore, doc, onSnapshot, setDoc, collection, updateDoc, deleteDoc } from "firebase/firestore";

// TODO: Replace with your actual Firebase config from Firebase Console
const firebaseConfig = {
  apiKey: "YOUR_API_KEY",
  authDomain: "aneelas-makeover.firebaseapp.com",
  projectId: "aneelas-makeover",
  storageBucket: "aneelas-makeover.appspot.com",
  messagingSenderId: "YOUR_SENDER_ID",
  appId: "YOUR_APP_ID"
};

// Initialize Firebase only if config is provided
const isConfigured = firebaseConfig.apiKey !== "YOUR_API_KEY";
const app = isConfigured ? initializeApp(firebaseConfig) : null;
export const db = app ? getFirestore(app) : null;

/**
 * Real-time Listener for a collection
 */
export const subscribeToCollection = (collectionName: string, callback: (data: any[]) => void) => {
  if (!db) return () => {};
  return onSnapshot(collection(db, collectionName), (snapshot) => {
    const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    callback(data);
  });
};

/**
 * Save or Update Data Globally
 */
export const saveGlobalData = async (collectionName: string, id: string, data: any) => {
  if (!db) {
    console.warn("Firebase not configured. Saving locally only.");
    return;
  }
  await setDoc(doc(db, collectionName, id), data, { merge: true });
};

/**
 * Delete Data Globally
 */
export const deleteGlobalData = async (collectionName: string, id: string) => {
  if (!db) return;
  await deleteDoc(doc(db, collectionName, id));
};

