import React, { useState, useRef } from 'react';
import { ShoppingBag, Calendar, Video, BookOpen, Plus, Edit2, Trash2, CheckCircle2, XCircle, Truck, PackageCheck, Image as ImageIcon, Save, X, Camera, Play, Film, AlertCircle, ChevronLeft, Phone, User, Clock, MapPin, CreditCard, Info, ListChecks, ArrowLeftRight, MessageSquare, Star, Megaphone, Send, CloudSync, Wifi, WifiOff } from 'lucide-react';
