interface AdminPanelProps {
  onLogin?: () => void;
  onCancel?: () => void;
  onLogout?: () => void;
  isFullPanel?: boolean;
  data?: {
    services: Service[];
    products: Product[];
    courses: Course[];
    videos: VideoItem[];
    gallery: GalleryItem[];
    bookings: Appointment[];
    orders: Order[];
    feedbacks: Feedback[];
  };
  setters?: {
    setServices: React.Dispatch<React.SetStateAction<Service[]>>;
    setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
    setCourses: React.Dispatch<React.SetStateAction<Course[]>>;
    setVideos: React.Dispatch<React.SetStateAction<VideoItem[]>>;
    setGallery: React.Dispatch<React.SetStateAction<GalleryItem[]>>;
    setBookings: React.Dispatch<React.SetStateAction<Appointment[]>>;
    setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
    setFeedbacks: React.Dispatch<React.SetStateAction<Feedback[]>>;
  };
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onLogin, onCancel, onLogout, isFullPanel, data, setters }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('bookings');
  const [syncing, setSyncing] = useState(false);

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editBuffer, setEditBuffer] = useState<any>(null);
  const [selectedDetail, setSelectedDetail] = useState<any>(null);

  const mainFileRef = useRef<HTMLInputElement>(null);

  const handleLogin = () => {
    if (password === 'A1234567890a') onLogin?.();
    else setError('Security Clearance Failure');
  };

  const triggerSyncFeedback = () => {
    setSyncing(true);
    setTimeout(() => setSyncing(false), 800);
  };

  const deleteItem = async (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("Permanently delete this item globally?")) return;

    triggerSyncFeedback();
    const colMap: Record<string, string> = {
      services: 'services', products: 'products', courses: 'courses', videos: 'videos', gallery: 'gallery'
    };

    if (colMap[activeTab]) {
      await deleteGlobalData(colMap[activeTab], id);
    }
  };

  const saveEdit = async () => {
    if (!editBuffer) return;
    triggerSyncFeedback();

    const colMap: Record<string, string> = {
      services: 'services', products: 'products', courses: 'courses', videos: 'videos', gallery: 'gallery'
    };

    if (colMap[activeTab]) {
      await saveGlobalData(colMap[activeTab], editingId!, editBuffer);
    }

    setEditingId(null);
    setEditBuffer(null);
  };

  const updateBookingStatus = async (id: string, status: Appointment['status']) => {
    triggerSyncFeedback();
    const item = data?.bookings.find(b => b.id === id);
    if (item) {
      const updated = { ...item, status };
      await saveGlobalData('bookings', id, updated);
      sendNotification("Booking Update", `Session for ${item.clientName} is now ${status}.`);
    }
  };

  const updateOrderStatus = async (id: string, status: Order['status']) => {
    triggerSyncFeedback();
    const item = data?.orders.find(o => o.id === id);
    if (item) {
      const updated = { ...item, status };
      await saveGlobalData('orders', id, updated);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string) => {
    const file = e.target.files?.[0];
    if (file && editBuffer) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditBuffer({ ...editBuffer, [field]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  if (!isFullPanel) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#0A2419] flex flex-col items-center justify-center px-8">
        <div className="mb-12 animate-royal">
          <Logo size="xl" />
        </div>
        <div className="w-full glass-card p-10 rounded-[3rem] border-[#F7E7CE]/20 shadow-2xl max-w-sm">
          <h2 className="text-xl font-bold text-[#F7E7CE] mb-8 serif text-center uppercase tracking-widest">Admin Access</h2>
          <div className="space-y-6">
            <input 
              type="password" 
              placeholder="Enter Access Key" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full bg-[#0A2419] border border-[#F7E7CE]/20 rounded-2xl py-4 px-6 text-center text-white outline-none focus:border-[#F7E7CE] transition-all" 
              onKeyPress={(e) => e.key === 'Enter' && handleLogin()}
            />
            {error && <p className="text-red-400 text-[10px] text-center uppercase font-bold tracking-[0.2em]">{error}</p>}
            <button onClick={handleLogin} className="w-full btn-royal py-5 rounded-2xl flex items-center justify-center gap-2">Verify & Sync</button>
            <button onClick={onCancel} className="w-full text-[#F7E7CE]/30 py-2 text-[10px] font-bold uppercase tracking-[0.3em]">Cancel</button>
          </div>
        </div>
      </div>
    );
  }

  const renderEditableList = (title: string, list: any[]) => (
    <div className="animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-sm font-bold text-[#F7E7CE] uppercase tracking-[0.4em] serif">{title}</h3>
        <button onClick={() => {
          const newId = `item-${Date.now()}`;
          setEditingId(newId);
          setEditBuffer({ id: newId });
        }} className="bg-[#F7E7CE] text-[#0A2419] p-3 rounded-full shadow-lg active:scale-90 transition-transform"><Plus size={20} /></button>
      </div>

      <div className="space-y-4">
        {list.map((item) => (
          <div key={item.id} className="glass-card p-5 rounded-[2.5rem] border-white/5 glow-gold overflow-hidden">
            {editingId === item.id ? (
              <div className="space-y-5">
                <div className="relative h-48 bg-black/40 rounded-2xl overflow-hidden border border-white/10">
                  {(editBuffer.image || editBuffer.after || editBuffer.thumbnail) && (
                    <img src={editBuffer.image || editBuffer.after || editBuffer.thumbnail} className="w-full h-full object-cover" />
                  )}
                  <button onClick={() => mainFileRef.current?.click()} className="absolute inset-0 flex flex-col items-center justify-center gap-2 text-[10px] text-white font-black uppercase tracking-widest bg-black/40">
                    <Camera size={24}/> Upload Media
                  </button>
                  <input type="file" ref={mainFileRef} hidden accept="image/*" onChange={(e) => handleFileUpload(e, activeTab === 'gallery' ? 'after' : (activeTab === 'videos' ? 'thumbnail' : 'image'))} />
                </div>
                <div className="space-y-3">
                  <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.name || editBuffer.title || ''} onChange={(e) => setEditBuffer({...editBuffer, [editBuffer.name !== undefined ? 'name' : 'title']: e.target.value})} placeholder="Title / Name*" />
                  <input className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white" value={editBuffer.price || ''} type="number" onChange={(e) => setEditBuffer({...editBuffer, price: Number(e.target.value)})} placeholder="Price (PKR)" />
                  <textarea className="w-full bg-[#0A2419] border border-white/10 rounded-xl p-4 text-xs text-white h-24 resize-none" value={editBuffer.description || ''} onChange={(e) => setEditBuffer({...editBuffer, description: e.target.value})} placeholder="Description" />
                </div>
                <div className="flex gap-3">
                  <button onClick={saveEdit} className="flex-1 bg-green-600 text-white py-4 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2 shadow-xl"><Save size={14}/> Save to Cloud</button>
                  <button onClick={() => { setEditingId(null); setEditBuffer(null); }} className="flex-1 bg-white/5 text-white/40 py-4 rounded-xl text-[10px] font-black uppercase flex items-center justify-center gap-2"><X size={14}/> Discard</button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 rounded-2xl overflow-hidden border border-white/10 shrink-0 bg-black/40">
                  <img src={item.image || item.after || item.thumbnail} className="w-full h-full object-cover" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold text-white serif truncate">{item.name || item.title}</p>
                  <p className="text-[9px] text-[#F7E7CE] font-black">Rs. {item.price?.toLocaleString() || '0'}</p>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => { setEditingId(item.id); setEditBuffer({ ...item }); }} className="p-3 bg-white/5 rounded-2xl text-[#F7E7CE]/60"><Edit2 size={18} /></button>
                  <button onClick={(e) => deleteItem(item.id, e)} className="p-3 bg-red-400/10 rounded-2xl text-red-400/60"><Trash2 size={18} /></button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A2419] flex flex-col">
