        </div>
        <button onClick={onLogout} className="text-red-400 text-[9px] font-black py-2.5 px-6 rounded-2xl border border-red-400/20 bg-red-400/5 uppercase tracking-[0.2em]">Logout</button>
      </header>

      <div className="p-6 overflow-y-auto flex-1 no-scrollbar pb-24">
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-10 py-2">
