              onClick={() => setActiveTab(t.id)} 
              className={`px-5 py-4 rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center gap-2.5 whitespace-nowrap ${activeTab === t.id ? 'bg-[#F7E7CE] text-[#0A2419]' : 'bg-[#124C34]/40 text-[#F7E7CE]/30'}`}
            >
              {t.icon} {t.label}
