    if (!window.confirm("Permanently delete this item globally?")) return;

    triggerSyncFeedback();
    const colMap: Record<string, string> = {
      services: 'services', products: 'products', courses: 'courses', videos: 'videos', gallery: 'gallery'
    };

    if (colMap[activeTab]) {
      await deleteGlobalData(colMap[activeTab], id);
    }
  };

  const saveEdit = async () => {
    if (!editBuffer || !editingId) return;

    // Validation: Title/Name is required
    if (!editBuffer.name && !editBuffer.title) {
      alert("Please enter a Title or Name.");
      return;
    }

    triggerSyncFeedback();

    const colMap: Record<string, string> = {
      services: 'services', products: 'products', courses: 'courses', videos: 'videos', gallery: 'gallery'
    };

    if (colMap[activeTab]) {
      // Ensure the correct structure based on tab
      const finalData = { ...editBuffer };
      if (activeTab === 'services' && !finalData.category) finalData.category = 'Makeup';
      if (activeTab === 'products' && !finalData.category) finalData.category = 'Makeup';
      if (activeTab === 'videos') finalData.type = 'video';

      await saveGlobalData(colMap[activeTab], editingId, finalData);
    }

    setEditingId(null);
    setEditBuffer(null);
  };

  const updateBookingStatus = async (id: string, status: Appointment['status']) => {
    triggerSyncFeedback();
    const item = data?.bookings.find(b => b.id === id);
    if (item) {
      const updated = { ...item, status };
      await saveGlobalData('bookings', id, updated);
      sendNotification("Booking Update", `Session for ${item.clientName} is now ${status}.`);
    }
  };

  const updateOrderStatus = async (id: string, status: Order['status']) => {
    triggerSyncFeedback();
    const item = data?.orders.find(o => o.id === id);
    if (item) {
      const updated = { ...item, status };
      await saveGlobalData('orders', id, updated);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, field: string) => {
    const file = e.target.files?.[0];
    if (file && editBuffer) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditBuffer({ ...editBuffer, [field]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const renderEditForm = () => (
    <div className="glass-card p-6 rounded-[2.5rem] border-[#F7E7CE]/40 glow-gold mb-8 animate-in slide-in-from-top-4 duration-500">
      <div className="flex justify-between items-center mb-6">
        <h4 className="text-[10px] font-black text-[#F7E7CE] uppercase tracking-[0.3em]">
