              value={editBuffer.duration || ''} 
              onChange={(e) => setEditBuffer({...editBuffer, duration: e.target.value})} 
              placeholder="Duration (e.g. 3h)" 
            />
          )}

          {activeTab === 'videos' && (
            <input 
              className="w-full bg-[#0A2419] border border-white/10 rounded-2xl p-4 text-xs text-white outline-none focus:border-[#F7E7CE]" 
              value={editBuffer.url || ''} 
              onChange={(e) => setEditBuffer({...editBuffer, url: e.target.value})} 
              placeholder="Video URL (Optional for now)" 
            />
          )}

          {activeTab === 'gallery' && (
             <div className="p-4 bg-white/5 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-[#F7E7CE]/40 uppercase tracking-widest mb-3">Before Image (Optional)</p>
                <input type="file" className="text-[10px] text-white/60" onChange={(e) => {
                   const file = e.target.files?.[0];
                   if (file) {
                     const reader = new FileReader();
