      </div>
    </div>
  );
};

export default AdminPanel;

import { initializeApp, getApp, getApps } from "firebase/app";
import { getFirestore, doc, onSnapshot, setDoc, collection, deleteDoc } from "firebase/firestore";

/**
 * FIREBASE CONFIGURATION - makeover-aa3dc
 */
const firebaseConfig = {
  apiKey: "AIzaSyANZ0Xb-Qf0clNFzBKA6lWOhvIHcxBkO1A",
  authDomain: "makeover-aa3dc.firebaseapp.com",
  projectId: "makeover-aa3dc",
  storageBucket: "makeover-aa3dc.firebasestorage.app",
  messagingSenderId: "6449060730",
  appId: "1:6449060730:web:4d6f987b3f87a1804b14c3",
  measurementId: "G-GCJHGS4QR6"
};

let db: any = null;
let isConnected = false;

const initFirebase = () => {
  try {
    const app = getApps().length > 0 ? getApp() : initializeApp(firebaseConfig);
    db = getFirestore(app);
    isConnected = true;
    console.log(`%c Firebase Ready: ${firebaseConfig.projectId} `, 'background: #0A2419; color: #F7E7CE; font-weight: bold;');
  } catch (error: any) {
    console.error("Firebase Initialization Error:", error);
    // If firestore is not available, it might be due to missing database in console
    if (error.code === 'firestore/service-not-available') {
      console.warn("Firestore service not available. Please ensure Firestore is enabled in the Firebase Console.");
    }
  }
};

initFirebase();

export { isConnected };

/**
 * Real-time Listener
 */
export const subscribeToCollection = (collectionName: string, callback: (data: any[]) => void) => {
  if (!db) {
    console.warn(`Firestore not ready for ${collectionName}. Retrying in 2s...`);
    setTimeout(() => subscribeToCollection(collectionName, callback), 2000);
    return () => {};
  }

  try {
    return onSnapshot(collection(db, collectionName), (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      // Only trigger callback if we actually have documents to prevent overwriting mocks with empty arrays 
      // during first sync if cloud is fresh.
      if (data.length > 0) {
        callback(data);
      }
    }, (error) => {
      console.error(`Firebase error in ${collectionName}:`, error);
    });
  } catch (err) {
    return () => {};
  }
};

/**
 * Save Data
 */
export const saveGlobalData = async (collectionName: string, id: string, data: any) => {
  if (!db) {
    console.error("Cannot save: Database not initialized.");
    return false;
  }
  try {
    console.log(`Pushing to ${collectionName}/${id}...`);
    await setDoc(doc(db, collectionName, id), data, { merge: true });
    return true;
  } catch (error) {
    console.error("Cloud Save Error:", error);
    return false;
  }
};

/**
 * Delete Data
 */
export const deleteGlobalData = async (collectionName: string, id: string) => {
  if (!db) return;
  try {
    await deleteDoc(doc(db, collectionName, id));
  } catch (error) {
    console.error("Cloud Delete Error:", error);
  }
};

