export const subscribeToCollection = (collectionName: string, callback: (data: any[]) => void) => {
  if (!db) {
    console.warn(`Firestore not ready for ${collectionName}. Retrying in 2s...`);
    setTimeout(() => subscribeToCollection(collectionName, callback), 2000);
    return () => {};
  }

  try {
    return onSnapshot(collection(db, collectionName), (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      // Only trigger callback if we actually have documents to prevent overwriting mocks with empty arrays 
      // during first sync if cloud is fresh.
      if (data.length > 0) {
        callback(data);
      }
    }, (error) => {
      console.error(`Firebase error in ${collectionName}:`, error);
    });
  } catch (err) {
    return () => {};
  }
};

/**
 * Save Data
 */
export const saveGlobalData = async (collectionName: string, id: string, data: any) => {
  if (!db) {
    console.error("Cannot save: Database not initialized.");
    return false;
  }
  try {
    console.log(`Pushing to ${collectionName}/${id}...`);
    await setDoc(doc(db, collectionName, id), data, { merge: true });
    return true;
  } catch (error) {
    console.error("Cloud Save Error:", error);
    return false;
  }
};

/**
 * Delete Data
 */
export const deleteGlobalData = async (collectionName: string, id: string) => {
  if (!db) return;
  try {
    await deleteDoc(doc(db, collectionName, id));
  } catch (error) {
    console.error("Cloud Delete Error:", error);
  }
};

