    triggerSyncFeedback();
    const colMap: Record<string, string> = {
      services: 'services', products: 'products', courses: 'courses', videos: 'videos', gallery: 'gallery'
    };

    if (colMap[activeTab]) {
      await deleteGlobalData(colMap[activeTab], id);
