/**
 * RESET & REBUILD DATABASE
 * Clears and repopulates all collections with provided initial data
 */
export const resetDatabase = async (initialData: Record<string, any[]>) => {
  if (!db) return false;

  const collections = Object.keys(initialData);
  const batch = writeBatch(db);

  try {
    for (const colName of collections) {
      const snapshot = await getDocs(collection(db, colName));
      snapshot.docs.forEach((doc) => {
        batch.delete(doc.ref);
      });

      initialData[colName].forEach((item) => {
        const docRef = doc(collection(db!, colName), item.id);
        batch.set(docRef, item);
      });
    }

    await batch.commit();
    console.log("Database Rebuild Complete");
    return true;
  } catch (error) {
    console.error("Database Rebuild Failed:", error);
    return false;
  }
};

