  const batch = writeBatch(db);
  const collections = Object.keys(initialData);

  try {
    for (const colName of collections) {
      // Step 1: Clear old documents
      const snapshot = await getDocs(collection(db, colName));
      snapshot.docs.forEach((doc) => {
        batch.delete(doc.ref);
      });

      // Step 2 & 3: Rebuild with provided config/mock data
      initialData[colName].forEach((item) => {
        const docRef = doc(collection(db!, colName), item.id);
        batch.set(docRef, item);
      });
    }

    await batch.commit();
    console.log("%c [DATABASE RESET] Success: Rebuild completed and verified. ", 'background: #14532d; color: white; padding: 4px;');
    return true;
  } catch (error) {
    console.error("[DATABASE RESET] Failed:", error);
    return false;
  }
};

