import React, { useState, useMemo } from 'react';
import { X, Home, Scissors, ShoppingBag, Zap, Image, Sparkles, Crown, Search, ArrowRight } from 'lucide-react';
import { Service, Product } from '../types';

interface LuxuryMenuProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  isOpen: boolean;
  setIsOpen: (open: boolean) => void;
  services: Service[];
  products: Product[];
  onServiceSelect: (s: Service) => void;
  onProductSelect: (p: Product) => void;
}

const LuxuryMenu: React.FC<LuxuryMenuProps> = ({ 
  activeTab, 
  setActiveTab, 
  isOpen, 
  setIsOpen, 
  services, 
  products,
  onServiceSelect,
  onProductSelect
}) => {
  const [searchQuery, setSearchQuery] = useState('');

  const menuItems = [
    { id: 'home', icon: <Home size={22} />, label: 'Home Studio' },
    { id: 'services', icon: <Scissors size={22} />, label: 'Master Salon' },
    { id: 'store', icon: <ShoppingBag size={22} />, label: 'Luxury Boutique' },
    { id: 'viral', icon: <Zap size={22} />, label: 'Viral Studio' },
    { id: 'ai', icon: <Sparkles size={22} />, label: 'AI Concierge' },
    { id: 'gallery', icon: <Image size={22} />, label: 'The Gallery' },
  ];

  const searchResults = useMemo(() => {
    if (!searchQuery.trim()) return { services: [], products: [], menu: menuItems };

    const query = searchQuery.toLowerCase();

    return {
      services: services.filter(s => s.name.toLowerCase().includes(query)).slice(0, 3),
      products: products.filter(p => p.name.toLowerCase().includes(query)).slice(0, 3),
      menu: menuItems.filter(m => m.label.toLowerCase().includes(query))
    };
  }, [searchQuery, services, products]);

  const handleSelect = (id: string) => {
    setActiveTab(id);
    setSearchQuery('');
    setIsOpen(false);
  };

  const handleResultClick = (item: any, type: 'service' | 'product') => {
    if (type === 'service') onServiceSelect(item);
    else onProductSelect(item);
    setSearchQuery('');
    setIsOpen(false);
  };

  return (
    <div className={`fixed inset-0 z-[120] transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] ${isOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
      {/* Blurred Backdrop */}
      <div 
        className="absolute inset-0 bg-[#0A2419]/98 backdrop-blur-3xl" 
        onClick={() => {
          setIsOpen(false);
          setSearchQuery('');
        }}
      ></div>

      {/* Luxury Patterns */}
      <div className="absolute inset-0 opacity-5 pointer-events-none overflow-hidden">
        <Crown size={400} className="absolute -top-20 -right-20 text-[#F7E7CE]" />
        <Crown size={300} className="absolute -bottom-20 -left-20 text-[#F7E7CE]" />
      </div>

      {/* Close Button */}
      <div className="absolute top-6 right-6 z-[130]">
        <button 
          onClick={(e) => {
            e.stopPropagation();
            setIsOpen(false);
            setSearchQuery('');
          }}
          className="w-12 h-12 rounded-full border border-[#F7E7CE]/20 flex items-center justify-center text-[#F7E7CE] bg-white/5 active:scale-90 transition-transform hover:bg-white/10"
        >
          <X size={24} />
        </button>
      </div>

      <div className="relative h-full flex flex-col items-center justify-center px-8 z-[125] pt-12">
        {/* Search Bar inside Menu */}
        <div className={`w-full max-w-xs mb-8 transition-all duration-700 delay-100 ${isOpen ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-[#F7E7CE]/40" size={18} />
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search services or products..." 
              className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-6 text-sm text-white placeholder:text-[#F7E7CE]/30 outline-none focus:border-[#F7E7CE]/40 transition-all shadow-inner"
            />
            {searchQuery && (
              <button 
                onClick={() => setSearchQuery('')}
                className="absolute right-4 top-1/2 -translate-y-1/2 text-white/20 hover:text-white"
              >
                <X size={14} />
              </button>
            )}
          </div>
        </div>

        {/* Scrollable Content Area */}
        <div className="w-full max-w-xs overflow-y-auto no-scrollbar max-h-[60vh] py-2 flex flex-col gap-6">

          {/* Search Content Results */}
          {searchQuery.trim() && (searchResults.services.length > 0 || searchResults.products.length > 0) && (
            <div className="flex flex-col gap-4 animate-in fade-in slide-in-from-top-4 duration-500">
               <h4 className="text-[10px] font-black text-[#F7E7CE]/40 uppercase tracking-[0.3em] pl-2">Top Matches</h4>

               {/* Service Results */}
               {searchResults.services.map(s => (
                 <button 
                   key={s.id} 
                   onClick={() => handleResultClick(s, 'service')}
