import Logo from './Logo';

interface HeaderProps {
  onAdminTrigger?: () => void;
  cartCount: number;
  onCartClick: () => void;
  onMenuOpen: () => void;
  onProfileClick: () => void;
  user: any;
}

const Header: React.FC<HeaderProps> = ({ onAdminTrigger, cartCount, onCartClick, onMenuOpen, onProfileClick, user }) => {
  const [tapCount, setTapCount] = useState(0);

  const handleLogoTap = () => {
    const newCount = tapCount + 1;
    setTapCount(newCount);
    if (newCount === 6) {
      onAdminTrigger?.();
      setTapCount(0);
    }
    setTimeout(() => setTapCount(0), 3000);
  };

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-[#0A2419]/95 backdrop-blur-2xl z-[60] flex items-center justify-between px-6 border-b border-[#F7E7CE]/10 shadow-lg">
      <div className="flex items-center gap-3 cursor-pointer group active:scale-95 transition-transform" onClick={handleLogoTap}>
        <div className="flex flex-col items-start">
          <Logo size="sm" />
        </div>
      </div>

      <div className="flex items-center gap-3">
        {/* Member Profile Button */}
        <button 
          onClick={onProfileClick}
          className={`w-10 h-10 rounded-full flex items-center justify-center transition-all active:scale-90 border shadow-md ${user ? 'bg-[#F7E7CE]/10 border-[#F7E7CE]/30 text-[#F7E7CE]' : 'bg-white/5 border-white/10 text-white/60'}`}
        >
          {user ? (
            <div className="text-[10px] font-black uppercase">{user.name.charAt(0)}</div>
          ) : (
            <UserIcon size={18} strokeWidth={1.5} />
          )}
        </button>

        <button 
          onClick={onCartClick}
          className="text-[#F3F3F3] hover:text-[#F7E7CE] transition-all active:scale-90 relative p-2"
        >
          <ShoppingBag size={20} strokeWidth={1.5} />
          {cartCount > 0 && (
            <span className="absolute top-1 right-1 w-3.5 h-3.5 bg-[#F7E7CE] text-[#0A2419] rounded-full text-[8px] font-bold flex items-center justify-center border border-[#0A2419]">
              {cartCount}
            </span>
          )}
        </button>

        <button 
          onClick={onMenuOpen}
          className="w-10 h-10 rounded-full gold-gradient text-[#0A2419] flex items-center justify-center shadow-lg active:scale-90 transition-transform"
        >
          <MenuIcon size={18} strokeWidth={2.5} />
        </button>
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import LuxuryMenu from './components/LuxuryMenu';
import Logo from './components/Logo';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import ServiceDetailScreen from './screens/ServiceDetailScreen';
import ProductDetailScreen from './screens/ProductDetailScreen';
import CourseDetailScreen from './screens/CourseDetailScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import FeedbackScreen from './screens/FeedbackScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import LoginScreen from './screens/LoginScreen';
import { MOCK_SERVICES, MOCK_PRODUCTS, MOCK_COURSES, MOCK_VIDEOS, MOCK_GALLERY } from './constants';
import { CartItem, Service, Product, Course, VideoItem, GalleryItem, Appointment, Order, Feedback } from './types';
import { MessageCircle, CloudSync } from 'lucide-react';
import { sendNotification } from './services/notificationService';
import { fetchData, saveData } from './services/firebaseService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [user, setUser] = useState<any>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<CartItem[] | null>(null);
  const [bookingService, setBookingService] = useState<Service | null>(null);
  const [selectedServiceDetail, setSelectedServiceDetail] = useState<Service | null>(null);
  const [selectedProductDetail, setSelectedProductDetail] = useState<Product | null>(null);
  const [selectedCourseDetail, setSelectedCourseDetail] = useState<Course | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  // Business Data State
  const [services, setServices] = useState<Service[]>(MOCK_SERVICES);
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [courses, setCourses] = useState<Course[]>(MOCK_COURSES);
  const [videos, setVideos] = useState<VideoItem[]>(MOCK_VIDEOS);
  const [gallery, setGallery] = useState<GalleryItem[]>(MOCK_GALLERY);
  const [bookings, setBookings] = useState<Appointment[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [feedbacks, setFeedbacks] = useState<Feedback[]>([]);

  // Initial Data Sync from Firebase
  useEffect(() => {
    const syncAllData = async () => {
      setSyncing(true);
      try {
        const cloudServices = await fetchData('services');
        if (cloudServices.length > 0) setServices(cloudServices as any);

        const cloudProducts = await fetchData('products');
        if (cloudProducts.length > 0) setProducts(cloudProducts as any);

        const cloudBookings = await fetchData('bookings');
        setBookings(cloudBookings as any);

        const cloudOrders = await fetchData('orders');
        setOrders(cloudOrders as any);

        const cloudFeedbacks = await fetchData('feedbacks');
        setFeedbacks(cloudFeedbacks as any);
      } catch (e) {
        console.warn("Database sync limited. Using local defaults.");
      }
      setLoading(false);
      setSyncing(false);
    };

    syncAllData();
  }, []);

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const handleLogin = (userData: any) => {
    setUser(userData);
    setShowLogin(false);
    sendNotification("Welcome to the Lounge ✨", `Welcome back, ${userData.name}. Your session has been authorized.`);
  };

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
  };

  const handleBookingConfirm = async (appointment: Appointment) => {
    setBookings(prev => [appointment, ...prev]);
    await saveData('bookings', appointment.id, appointment);
    sendNotification(
      "Reservation Confirmed ✨",
      `Your session for ${appointment.serviceName} is secured for ${appointment.date} at ${appointment.time}.`
    );
  };

  const handleOrderConfirm = async (order: Order) => {
    setOrders(prev => [order, ...prev]);
    setCartItems([]);
    await saveData('orders', order.id, order);
    sendNotification(
      "Luxury Order Placed 🛍️",
      `Thank you ${order.clientName}! Your order #${order.id.slice(-6)} is being prepared for perfection.`
    );
  };

  const handleFeedbackSubmit = async (fb: Feedback) => {
    setFeedbacks(prev => [fb, ...prev]);
    await saveData('feedbacks', fb.id, fb);
  };

  const openWhatsApp = () => {
    window.open('https://wa.me/923134528585', '_blank');
  };

  if (loading) {
    return (
      <div className="h-screen w-screen bg-[#0A2419] flex flex-col items-center justify-center relative overflow-hidden">
        <div className="absolute inset-0 opacity-20">
          <div className="absolute top-[-20%] left-[-20%] w-[60%] h-[60%] bg-[#F7E7CE] rounded-full blur-[150px] animate-pulse"></div>
          <div className="absolute bottom-[-20%] right-[-20%] w-[60%] h-[60%] bg-[#F7E7CE] rounded-full blur-[150px] animate-pulse delay-1000"></div>
        </div>
        <div className="relative z-10 transform scale-125 animate-royal text-center">
           <Logo size="xl" />
           <p className="mt-8 text-[10px] text-[#F7E7CE]/60 uppercase tracking-[0.5em] animate-pulse">Establishing Cloud Link...</p>
        </div>
        <div className="mt-24 w-64 h-0.5 bg-white/5 rounded-full overflow-hidden relative">
          <div className="absolute top-0 left-0 h-full gold-gradient" style={{ width: '100%' }}></div>
        </div>
      </div>
    );
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return (
      <AdminPanel 
        isFullPanel 
        onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }}
        data={{ services, products, courses, videos, gallery, bookings, orders, feedbacks }}
        setters={{ setServices, setProducts, setCourses, setVideos, setGallery, setBookings, setOrders, setFeedbacks }}
      />
    );
  }

  const renderScreen = () => {
    if (showLogin) return <LoginScreen onLogin={handleLogin} onBack={() => setShowLogin(false)} />;
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={(id) => setCartItems(p => p.filter(i => i.id !== id))} onUpdateQty={(id, d) => setCartItems(p => p.map(i => i.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={handleOrderConfirm} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} onConfirm={handleBookingConfirm} />;
    if (showFeedback) return <FeedbackScreen onBack={() => setShowFeedback(false)} onSubmit={handleFeedbackSubmit} />;
    if (selectedServiceDetail) return <ServiceDetailScreen service={selectedServiceDetail} onBack={() => setSelectedServiceDetail(null)} onBook={(s) => { setSelectedServiceDetail(null); setBookingService(s); }} />;
    if (selectedProductDetail) return <ProductDetailScreen product={selectedProductDetail} onBack={() => setSelectedProductDetail(null)} onAddToCart={addToCart} />;
    if (selectedCourseDetail) return <CourseDetailScreen course={selectedCourseDetail} onBack={() => setSelectedCourseDetail(null)} onEnroll={addToCart} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} onOpenFeedback={() => setShowFeedback(true)} />;
      case 'services': return <ServicesScreen services={services} onBook={(s) => setBookingService(s)} onViewDetails={(s) => setSelectedServiceDetail(s)} />;
      case 'store': return <StoreScreen products={products} courses={courses} onAddToCart={addToCart} onViewProduct={setSelectedProductDetail} onViewCourse={setSelectedCourseDetail} />;
      case 'viral': return <ViralScreen videos={videos} onBook={(sId) => {
        const found = services.find(s => s.id === sId);
        if (found) setBookingService(found);
      }} />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen gallery={gallery} />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} onOpenFeedback={() => setShowFeedback(true)} />;
    }
  };

  const showGlobalUI = !checkoutItem && !bookingService && !showCart && !selectedServiceDetail && !selectedProductDetail && !selectedCourseDetail && !showFeedback && !showLogin;
  const isViralTab = activeTab === 'viral' && showGlobalUI;

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      {!isViralTab && !showLogin && (
        <Header 
          onAdminTrigger={handleAdminTrigger} 
          cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} 
          onCartClick={() => setShowCart(true)} 
          onMenuOpen={() => setIsMenuOpen(true)}
          onProfileClick={() => setShowLogin(true)}
          user={user}
        />
      )}

      {syncing && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] bg-[#F7E7CE] text-[#0A2419] px-4 py-1.5 rounded-full text-[8px] font-black uppercase flex items-center gap-2 shadow-2xl animate-bounce">
          <CloudSync size={12} className="animate-spin" /> Syncing Cloud Data
        </div>
      )}

      <main className={`flex-1 ${isViralTab ? 'p-0 pt-0' : 'pt-20 px-4'} max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal`}>
        {renderScreen()}
        {!isViralTab && showGlobalUI && <div className="h-20" />}
      </main>

      {showGlobalUI && (
        <>
          <LuxuryMenu 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            isOpen={isMenuOpen} 
            setIsOpen={setIsMenuOpen} 
            services={services}
            products={products}
            onServiceSelect={(s) => setSelectedServiceDetail(s)}
            onProductSelect={(p) => setSelectedProductDetail(p)}
          />
          {!isViralTab && (
            <button 
              onClick={openWhatsApp}
              className="fixed bottom-10 right-6 z-[50] w-14 h-14 bg-white/5 border border-white/10 text-[#F7E7CE] rounded-full flex items-center justify-center shadow-2xl backdrop-blur-md active:scale-90 transition-all hover:scale-110"
              aria-label="Connect on WhatsApp"
            >
              <MessageCircle size={28} />
            </button>
          )}
        </>
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import Logo from './Logo';
import { Crown } from 'lucide-react';

interface SplashScreenProps {
  onFinish: () => void;
}

const SplashScreen: React.FC<SplashScreenProps> = ({ onFinish }) => {
  const [stage, setStage] = useState(0);

  useEffect(() => {
    // Stage 1: Fade in logo (0.5s)
    const t1 = setTimeout(() => setStage(1), 500);
    // Stage 2: Reveal tagline (1.5s)
    const t2 = setTimeout(() => setStage(2), 1500);
    // Stage 3: Start exit transition (3.0s)
    const t3 = setTimeout(() => setStage(3), 3000);
    // Finish: Remove component (3.5s)
    const t4 = setTimeout(() => onFinish(), 3500);

    return () => {
      clearTimeout(t1);
      clearTimeout(t2);
      clearTimeout(t3);
      clearTimeout(t4);
    };
  }, [onFinish]);

  return (
    <div className={`fixed inset-0 z-[200] bg-[#0A2419] flex flex-col items-center justify-center transition-all duration-700 ease-in-out ${stage === 3 ? 'opacity-0 scale-110 pointer-events-none' : 'opacity-100 scale-100'}`}>

      {/* Background Luxury Elements */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-[#F7E7CE]/5 rounded-full blur-[120px] animate-pulse"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-[#F7E7CE]/5 rounded-full blur-[120px] animate-pulse delay-700"></div>

        {/* Subtle Shimmer Pattern */}
        <div className="absolute inset-0 opacity-[0.03] shimmer-bg"></div>
      </div>

      <div className="relative z-10 flex flex-col items-center">
        {/* Logo with Soft Glow */}
        <div className={`transition-all duration-1000 ease-out transform ${stage >= 1 ? 'opacity-100 scale-100' : 'opacity-0 scale-90'}`}>
          <div className="relative">
             {/* Glow Behind Logo */}
             <div className="absolute inset-0 bg-[#F7E7CE]/20 blur-[40px] rounded-full animate-pulse"></div>
             <Logo size="xl" />
          </div>
        </div>

        {/* App Name & Tagline */}
        <div className={`mt-8 text-center transition-all duration-1000 delay-300 transform ${stage >= 2 ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
          <div className="flex items-center justify-center gap-3 mb-3">
            <div className="h-px w-8 bg-gradient-to-r from-transparent to-[#F7E7CE]/30"></div>
            <Crown size={14} className="text-[#F7E7CE] animate-bounce duration-[3000ms]" />
            <div className="h-px w-8 bg-gradient-to-l from-transparent to-[#F7E7CE]/30"></div>
          </div>
          <p className="text-[11px] text-[#F7E7CE] font-bold uppercase tracking-[0.6em] shimmer-text">
            Your Beauty, Our Passion
          </p>
        </div>
      </div>

      {/* Loading Bar at bottom */}
      <div className="absolute bottom-20 w-48 h-0.5 bg-white/5 rounded-full overflow-hidden">
        <div 
          className="h-full gold-gradient transition-all duration-[3000ms] ease-linear"
          style={{ width: stage >= 3 ? '100%' : '0%' }}
        ></div>
      </div>

      <style>{`
        .shimmer-text {
          background: linear-gradient(90deg, #F7E7CE 0%, #FFFFFF 50%, #F7E7CE 100%);
          background-size: 200% auto;
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          animation: shimmer-anim 4s linear infinite;
        }
        @keyframes shimmer-anim {
          to { background-position: 200% center; }
        }
        .shimmer-bg {
          background-image: radial-gradient(circle at 2px 2px, rgba(247, 231, 206, 0.1) 1px, transparent 0);
          background-size: 40px 40px;
        }
      `}</style>
    </div>
  );
};

export default SplashScreen;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import LuxuryMenu from './components/LuxuryMenu';
import Logo from './components/Logo';
import SplashScreen from './components/SplashScreen';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import ServiceDetailScreen from './screens/ServiceDetailScreen';
import ProductDetailScreen from './screens/ProductDetailScreen';
import CourseDetailScreen from './screens/CourseDetailScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import FeedbackScreen from './screens/FeedbackScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import LoginScreen from './screens/LoginScreen';
import { MOCK_SERVICES, MOCK_PRODUCTS, MOCK_COURSES, MOCK_VIDEOS, MOCK_GALLERY } from './constants';
import { CartItem, Service, Product, Course, VideoItem, GalleryItem, Appointment, Order, Feedback } from './types';
import { MessageCircle, CloudSync } from 'lucide-react';
import { sendNotification } from './services/notificationService';
import { fetchData, saveData } from './services/firebaseService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isSplashing, setIsSplashing] = useState(true);
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [user, setUser] = useState<any>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<CartItem[] | null>(null);
  const [bookingService, setBookingService] = useState<Service | null>(null);
  const [selectedServiceDetail, setSelectedServiceDetail] = useState<Service | null>(null);
  const [selectedProductDetail, setSelectedProductDetail] = useState<Product | null>(null);
  const [selectedCourseDetail, setSelectedCourseDetail] = useState<Course | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  // Business Data State
  const [services, setServices] = useState<Service[]>(MOCK_SERVICES);
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [courses, setCourses] = useState<Course[]>(MOCK_COURSES);
  const [videos, setVideos] = useState<VideoItem[]>(MOCK_VIDEOS);
  const [gallery, setGallery] = useState<GalleryItem[]>(MOCK_GALLERY);
  const [bookings, setBookings] = useState<Appointment[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [feedbacks, setFeedbacks] = useState<Feedback[]>([]);

  // Initial Data Sync from Firebase
  useEffect(() => {
    const syncAllData = async () => {
      setSyncing(true);
      try {
        const cloudServices = await fetchData('services');
        if (cloudServices.length > 0) setServices(cloudServices as any);

        const cloudProducts = await fetchData('products');
        if (cloudProducts.length > 0) setProducts(cloudProducts as any);

        const cloudBookings = await fetchData('bookings');
        setBookings(cloudBookings as any);

        const cloudOrders = await fetchData('orders');
        setOrders(cloudOrders as any);

        const cloudFeedbacks = await fetchData('feedbacks');
        setFeedbacks(cloudFeedbacks as any);
      } catch (e) {
        console.warn("Database sync limited. Using local defaults.");
      }
      setLoading(false);
      setSyncing(false);
    };

    syncAllData();
  }, []);

  const handleSplashFinish = () => {
    setIsSplashing(false);
    // Automatically suggest login for new sessions if not logged in
    if (!user) {
      setShowLogin(true);
    }
  };

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const handleLogin = (userData: any) => {
    setUser(userData);
    setShowLogin(false);
    sendNotification("Welcome to the Lounge ✨", `Welcome back, ${userData.name}. Your session has been authorized.`);
  };

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
  };

  const handleBookingConfirm = async (appointment: Appointment) => {
    setBookings(prev => [appointment, ...prev]);
    await saveData('bookings', appointment.id, appointment);
    sendNotification(
      "Reservation Confirmed ✨",
      `Your session for ${appointment.serviceName} is secured for ${appointment.date} at ${appointment.time}.`
    );
  };

  const handleOrderConfirm = async (order: Order) => {
    setOrders(prev => [order, ...prev]);
    setCartItems([]);
    await saveData('orders', order.id, order);
    sendNotification(
      "Luxury Order Placed 🛍️",
      `Thank you ${order.clientName}! Your order #${order.id.slice(-6)} is being prepared for perfection.`
    );
  };

  const handleFeedbackSubmit = async (fb: Feedback) => {
    setFeedbacks(prev => [fb, ...prev]);
    await saveData('feedbacks', fb.id, fb);
  };

  const openWhatsApp = () => {
    window.open('https://wa.me/923134528585', '_blank');
  };

  // 1. Show Splash Screen first
  if (isSplashing) {
    return <SplashScreen onFinish={handleSplashFinish} />;
  }

  // 2. Handle Admin Login
  if (showAdminLogin && !isAdmin) {
    return <AdminPanel onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  // 3. Handle Admin Panel
  if (isAdmin) {
    return (
      <AdminPanel 
        isFullPanel 
        onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }}
        data={{ services, products, courses, videos, gallery, bookings, orders, feedbacks }}
        setters={{ setServices, setProducts, setCourses, setVideos, setGallery, setBookings, setOrders, setFeedbacks }}
      />
    );
  }

  const renderScreen = () => {
    if (showLogin) return <LoginScreen onLogin={handleLogin} onBack={() => setShowLogin(false)} />;
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={(id) => setCartItems(p => p.filter(i => i.id !== id))} onUpdateQty={(id, d) => setCartItems(p => p.map(i => i.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={handleOrderConfirm} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} onConfirm={handleBookingConfirm} />;
    if (showFeedback) return <FeedbackScreen onBack={() => setShowFeedback(false)} onSubmit={handleFeedbackSubmit} />;
    if (selectedServiceDetail) return <ServiceDetailScreen service={selectedServiceDetail} onBack={() => setSelectedServiceDetail(null)} onBook={(s) => { setSelectedServiceDetail(null); setBookingService(s); }} />;
    if (selectedProductDetail) return <ProductDetailScreen product={selectedProductDetail} onBack={() => setSelectedProductDetail(null)} onAddToCart={addToCart} />;
    if (selectedCourseDetail) return <CourseDetailScreen course={selectedCourseDetail} onBack={() => setSelectedCourseDetail(null)} onEnroll={addToCart} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} onOpenFeedback={() => setShowFeedback(true)} />;
      case 'services': return <ServicesScreen services={services} onBook={(s) => setBookingService(s)} onViewDetails={(s) => setSelectedServiceDetail(s)} />;
      case 'store': return <StoreScreen products={products} courses={courses} onAddToCart={addToCart} onViewProduct={setSelectedProductDetail} onViewCourse={setSelectedCourseDetail} />;
      case 'viral': return <ViralScreen videos={videos} onBook={(sId) => {
        const found = services.find(s => s.id === sId);
        if (found) setBookingService(found);
      }} />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen gallery={gallery} />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} onOpenFeedback={() => setShowFeedback(true)} />;
    }
  };

  const showGlobalUI = !checkoutItem && !bookingService && !showCart && !selectedServiceDetail && !selectedProductDetail && !selectedCourseDetail && !showFeedback && !showLogin;
  const isViralTab = activeTab === 'viral' && showGlobalUI;

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      {!isViralTab && !showLogin && (
        <Header 
          onAdminTrigger={handleAdminTrigger} 
          cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} 
          onCartClick={() => setShowCart(true)} 
          onMenuOpen={() => setIsMenuOpen(true)}
          onProfileClick={() => setShowLogin(true)}
          user={user}
        />
      )}

      {syncing && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] bg-[#F7E7CE] text-[#0A2419] px-4 py-1.5 rounded-full text-[8px] font-black uppercase flex items-center gap-2 shadow-2xl animate-bounce">
          <CloudSync size={12} className="animate-spin" /> Syncing Cloud Data
        </div>
      )}

      <main className={`flex-1 ${isViralTab ? 'p-0 pt-0' : 'pt-20 px-4'} max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal`}>
        {renderScreen()}
        {!isViralTab && showGlobalUI && <div className="h-20" />}
      </main>

      {showGlobalUI && (
        <>
          <LuxuryMenu 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            isOpen={isMenuOpen} 
            setIsOpen={setIsMenuOpen} 
            services={services}
            products={products}
            onServiceSelect={(s) => setSelectedServiceDetail(s)}
            onProductSelect={(p) => setSelectedProductDetail(p)}
          />
          {!isViralTab && (
            <button 
              onClick={openWhatsApp}
              className="fixed bottom-10 right-6 z-[50] w-14 h-14 bg-white/5 border border-white/10 text-[#F7E7CE] rounded-full flex items-center justify-center shadow-2xl backdrop-blur-md active:scale-90 transition-all hover:scale-110"
              aria-label="Connect on WhatsApp"
            >
              <MessageCircle size={28} />
            </button>
          )}
        </>
      )}
    </div>
  );
};

