  phone: string;
  address: string;
  total: number;
  paymentMethod: string;
  status: 'Pending' | 'Shipped' | 'Delivered' | 'Cancelled';
  date: string;
}

export interface Feedback {
  id: string;
  userName: string;
  userPhone: string;
  message: string;
  date: string;
  rating: number;
  approved?: boolean;
}

