        <Crown size={400} className="absolute -top-20 -right-20 text-[#F7E7CE]" />
        <Crown size={300} className="absolute -bottom-20 -left-20 text-[#F7E7CE]" />
      </div>

      {/* Close Button - Optimized positioning for visibility and reach */}
      <div className="absolute top-12 right-6 z-[130]">
        <button 
          onClick={handleClose}
          className="w-12 h-12 rounded-full border border-[#F7E7CE]/40 flex items-center justify-center text-[#F7E7CE] bg-[#124C34]/80 backdrop-blur-xl active:scale-90 transition-all hover:bg-[#F7E7CE] hover:text-[#0A2419] shadow-2xl border-2"
        >
          <X size={24} strokeWidth={2.5} />
        </button>
      </div>

      <div className="relative h-full flex flex-col items-center justify-start px-8 z-[125] pt-28">
        {/* Search Bar inside Menu */}
        <div className={`w-full max-w-xs mb-8 transition-all duration-300 ${isOpen ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
          <div className="relative group">
            <Search className={`absolute left-5 top-1/2 -translate-y-1/2 transition-colors ${searchQuery ? 'text-[#F7E7CE]' : 'text-[#F7E7CE]/40'}`} size={20} />
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search perfection..." 
              className="w-full bg-white/5 border border-white/20 rounded-2xl py-5 pl-14 pr-12 text-sm text-white placeholder:text-[#F7E7CE]/20 outline-none focus:border-[#F7E7CE]/50 transition-all shadow-inner focus:bg-white/[0.08]"
            />
            {searchQuery && (
              <button 
                onClick={() => setSearchQuery('')}
                className="absolute right-4 top-1/2 -translate-y-1/2 text-[#F7E7CE]/40 hover:text-[#F7E7CE] transition-colors p-2"
              >
                <X size={16} />
              </button>
            )}
          </div>
        </div>

        {/* Scrollable Content Area */}
        <div className="w-full max-w-xs overflow-y-auto no-scrollbar max-h-[65vh] py-2 flex flex-col gap-6 pb-20">

          {/* Search Content Results */}
          {searchQuery.trim() && (searchResults.services.length > 0 || searchResults.products.length > 0) && (
            <div className="flex flex-col gap-3 animate-in fade-in slide-in-from-top-4 duration-300">
               <h4 className="text-[10px] font-black text-[#F7E7CE]/60 uppercase tracking-[0.4em] pl-2 mb-1">Matches</h4>

               {/* Service Results */}
               {searchResults.services.map(s => (
                 <button 
                   key={s.id} 
                   onClick={() => handleResultClick(s, 'service')}
                   className="flex items-center gap-4 bg-white/5 p-4 rounded-3xl border border-white/10 hover:border-[#F7E7CE]/50 transition-all text-left group/item active:scale-[0.98]"
                 >
                   <div className="w-10 h-10 rounded-xl overflow-hidden border border-white/10 shrink-0">
                    <img src={s.image} className="w-full h-full object-cover" />
                   </div>
                   <div className="flex-1 min-w-0">
                     <p className="text-[11px] font-bold text-white truncate uppercase tracking-tight">{s.name}</p>
                     <p className="text-[8px] text-[#F7E7CE]/60 font-medium uppercase tracking-widest mt-0.5">Salon</p>
                   </div>
                   <ArrowRight size={14} className="text-[#F7E7CE]/30 group-hover/item:translate-x-1 transition-all" />
                 </button>
               ))}

               {/* Product Results */}
               {searchResults.products.map(p => (
                 <button 
                   key={p.id} 
                   onClick={() => handleResultClick(p, 'product')}
                   className="flex items-center gap-4 bg-white/5 p-4 rounded-3xl border border-white/10 hover:border-[#F7E7CE]/50 transition-all text-left group/item active:scale-[0.98]"
                 >
                   <div className="w-10 h-10 rounded-xl overflow-hidden border border-white/10 shrink-0">
                    <img src={p.image} className="w-full h-full object-cover" />
                   </div>
                   <div className="flex-1 min-w-0">
                     <p className="text-[11px] font-bold text-white truncate uppercase tracking-tight">{p.name}</p>
                     <p className="text-[8px] text-[#F7E7CE]/60 font-medium uppercase tracking-widest mt-0.5">Luxury Items</p>
                   </div>
                   <ArrowRight size={14} className="text-[#F7E7CE]/30 group-hover/item:translate-x-1 transition-all" />
                 </button>
               ))}
            </div>
          )}

          {/* Navigation Links */}
          <div className="flex flex-col items-center gap-4 w-full">
            {searchQuery.trim() && searchResults.menu.length === 0 && searchResults.services.length === 0 && searchResults.products.length === 0 && (
              <div className="py-10 text-center animate-in fade-in duration-300">
                <p className="text-[10px] text-white/30 tracking-[0.2em] uppercase">No results found</p>
                <button onClick={() => setSearchQuery('')} className="mt-4 text-[9px] text-[#F7E7CE]/60 font-black uppercase underline tracking-[0.3em]">Clear Search</button>
              </div>
            )}

            {!searchQuery.trim() && <h4 className="text-[9px] font-black text-[#F7E7CE]/40 uppercase tracking-[0.4em] mb-1 w-full text-center">Navigation</h4>}

            {searchResults.menu.map((item, index) => (
              <button
                key={item.id}
                onClick={() => handleSelect(item.id)}
                className={`flex items-center gap-6 w-full group transition-all duration-300 ${isOpen ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0'}`}
                style={{ transitionDelay: `${(index + 1) * 30}ms` }}
              >
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all duration-300 ${activeTab === item.id ? 'gold-gradient text-[#0A2419] shadow-xl scale-110' : 'bg-white/5 text-[#F7E7CE]/40 group-hover:text-[#F7E7CE] group-hover:bg-white/10 shadow-md'}`}>
                  {React.cloneElement(item.icon as React.ReactElement, { size: 24 })}
                </div>
                <div className="text-left">
                  <h3 className={`text-xl font-bold serif transition-colors ${activeTab === item.id ? 'text-[#F7E7CE]' : 'text-white/80 group-hover:text-[#F7E7CE]'}`}>
                    {item.label}
                  </h3>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Branding Footer */}
      <div className="absolute bottom-10 left-0 right-0 text-center pointer-events-none opacity-20">
        <p className="text-[10px] text-[#F7E7CE] uppercase tracking-[0.5em] font-black">
          Aneela's MakeOver
        </p>
      </div>
    </div>
  );
};

export default LuxuryMenu;

import React, { useState, useRef, useEffect } from 'react';
import { Heart, Disc, Volume2, VolumeX, ShoppingBag } from 'lucide-react';
import { VideoItem } from '../types';

interface ViralScreenProps {
  videos: VideoItem[];
  onBook: (serviceId: string) => void;
}

const ViralScreen: React.FC<ViralScreenProps> = ({ videos, onBook }) => {
  const [muted, setMuted] = useState(true);
  const [likedVideos, setLikedVideos] = useState<Set<string>>(new Set());
  const [showHeartBurst, setShowHeartBurst] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleToggleLike = (id: string) => {
    setLikedVideos(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else {
        next.add(id);
        setShowHeartBurst(id);
        setTimeout(() => setShowHeartBurst(null), 800);
      }
      return next;
    });
  };

  const handleDoubleTap = (id: string) => {
    if (!likedVideos.has(id)) {
      handleToggleLike(id);
    } else {
      setShowHeartBurst(id);
      setTimeout(() => setShowHeartBurst(null), 800);
    }
  };

  return (
    <div 
      ref={containerRef}
      className="relative w-full h-full snap-y snap-mandatory overflow-y-scroll no-scrollbar bg-black"
    >
      {videos.length === 0 && (
        <div className="h-full flex flex-col items-center justify-center text-[#F7E7CE]/40 italic uppercase tracking-widest text-[10px]">
          Aneela is curating new masterpieces...
        </div>
      )}

      {videos.map((vid) => (
        <div key={vid.id} className="relative w-full h-full snap-start bg-black overflow-hidden flex flex-col justify-end">
          {/* Video Element */}
          <div 
            className="absolute inset-0 z-0"
            onClick={(e) => {
              if (e.detail === 2) handleDoubleTap(vid.id);
              else setMuted(!muted);
            }}
          >
            {vid.url ? (
              <video 
                src={vid.url}
                className="w-full h-full object-cover"
                autoPlay
                loop
                muted={muted}
                playsInline
              />
            ) : (
              <img src={vid.thumbnail} className="w-full h-full object-cover brightness-50" alt="" />
            )}

            {/* Overlay Gradient */}
            <div className="absolute inset-0 bg-gradient-to-t from-[#0A2419]/90 via-transparent to-transparent pointer-events-none"></div>

            {/* Mute Indicator */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-0 animate-pulse">
               {muted ? <VolumeX className="text-white/50" size={60} /> : <Volume2 className="text-white/50" size={60} />}
            </div>
          </div>

          {/* Heart Burst Animation */}
          {showHeartBurst === vid.id && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
              <Heart 
                size={120} 
                className="text-[#F7E7CE] animate-[ping_0.8s_ease-out_forwards] fill-[#F7E7CE] drop-shadow-[0_0_20px_rgba(247,231,206,0.6)]" 
              />
            </div>
          )}

          {/* Video Information Overlay */}
          <div className="relative p-6 z-10 w-full">
            <div className="flex flex-col mb-4">
               <h4 className="text-xl font-bold text-white serif tracking-wide drop-shadow-md mb-1">{vid.title}</h4>
               <p className="text-[11px] text-[#F7E7CE] leading-relaxed mb-3 line-clamp-2 italic drop-shadow-sm">
                 {vid.description || "Witness the perfection of every stroke."}
               </p>

               {/* Music Ticker */}
               <div className="flex items-center gap-2 overflow-hidden w-[200px]">
                 <Disc size={12} className="text-[#F7E7CE] animate-spin shrink-0" />
                 <div className="whitespace-nowrap animate-[marquee_10s_linear_infinite] text-[9px] text-[#F7E7CE]/80 font-medium uppercase tracking-[0.2em]">
                   {vid.musicTrack || "Original Sound - Aneelas Viral Studio"} &bull; {vid.musicTrack || "Original Sound - Aneelas Viral Studio"}
                 </div>
               </div>
            </div>

            <div className="flex items-center gap-3">
              {vid.linkedServiceId && (
                <button 
                  onClick={() => onBook(vid.linkedServiceId!)}
                  className="bg-[#E1B84F] text-[#0A2419] px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] shadow-2xl flex items-center gap-2 active:scale-95 transition-all"
                >
                  Book This Look <ShoppingBag size={14} />
                </button>
              )}
            </div>
          </div>

          {/* Progress Bar */}
          <div className="absolute bottom-0 left-0 h-0.5 bg-white/10 w-full z-30">
             <div className="h-full bg-[#E1B84F] shadow-[0_0_10px_#E1B84F] animate-[progress_15s_linear_infinite]"></div>
          </div>
        </div>
      ))}

      <style>{`
        @keyframes marquee {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
        @keyframes progress {
          0% { width: 0%; }
          100% { width: 100%; }
        }
        .font-montserrat {
          font-family: 'Montserrat', sans-serif;
        }
      `}</style>
    </div>
  );
};

export default ViralScreen;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import LuxuryMenu from './components/LuxuryMenu';
import Logo from './components/Logo';
import SplashScreen from './components/SplashScreen';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import ServiceDetailScreen from './screens/ServiceDetailScreen';
import ProductDetailScreen from './screens/ProductDetailScreen';
import CourseDetailScreen from './screens/CourseDetailScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import FeedbackScreen from './screens/FeedbackScreen';
import AdminPanel from './screens/AdminPanel';
import CartScreen from './screens/CartScreen';
import LoginScreen from './screens/LoginScreen';
import { MOCK_SERVICES, MOCK_PRODUCTS, MOCK_COURSES, MOCK_VIDEOS, MOCK_GALLERY, MOCK_FEEDBACKS } from './constants';
import { CartItem, Service, Product, Course, VideoItem, GalleryItem, Appointment, Order, Feedback } from './types';
import { MessageCircle, RefreshCw } from 'lucide-react';
import { sendNotification } from './services/notificationService';
import { subscribeToCollection, saveData } from './services/firebaseService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isSplashing, setIsSplashing] = useState(true);
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [user, setUser] = useState<any>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [showCart, setShowCart] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<CartItem[] | null>(null);
  const [bookingService, setBookingService] = useState<Service | null>(null);
  const [selectedServiceDetail, setSelectedServiceDetail] = useState<Service | null>(null);
  const [selectedProductDetail, setSelectedProductDetail] = useState<Product | null>(null);
  const [selectedCourseDetail, setSelectedCourseDetail] = useState<Course | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  // Business Data State
  const [services, setServices] = useState<Service[]>(MOCK_SERVICES);
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [courses, setCourses] = useState<Course[]>(MOCK_COURSES);
  const [videos, setVideos] = useState<VideoItem[]>(MOCK_VIDEOS);
  const [gallery, setGallery] = useState<GalleryItem[]>(MOCK_GALLERY);
  const [bookings, setBookings] = useState<Appointment[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [feedbacks, setFeedbacks] = useState<Feedback[]>(MOCK_FEEDBACKS);

  // Real-time Data Sync from Firebase
  useEffect(() => {
    const unsubs = [
      subscribeToCollection('services', (data) => { if(data.length > 0) setServices(data as Service[]); }),
      subscribeToCollection('products', (data) => { if(data.length > 0) setProducts(data as Product[]); }),
      subscribeToCollection('courses', (data) => { if(data.length > 0) setCourses(data as Course[]); }),
      subscribeToCollection('videos', (data) => { if(data.length > 0) setVideos(data as VideoItem[]); }),
      subscribeToCollection('gallery', (data) => { if(data.length > 0) setGallery(data as GalleryItem[]); }),

      subscribeToCollection('bookings', (data) => setBookings(data as Appointment[])),
      subscribeToCollection('orders', (data) => setOrders(data as Order[])),
      subscribeToCollection('feedbacks', (data) => { 
        if (data.length > 0) setFeedbacks(data as Feedback[]);
        else setFeedbacks(MOCK_FEEDBACKS);
      })
    ];

    setLoading(false);

    return () => {
      unsubs.forEach(unsub => unsub());
    };
  }, []);

  const handleSplashFinish = () => {
    setIsSplashing(false);
  };

  const handleAdminTrigger = () => setShowAdminLogin(true);

  const handleLogin = (userData: any) => {
    setUser(userData);
    setShowLogin(false);
    sendNotification("Welcome to the Lounge ✨", `Welcome back, ${userData.name}. Your session has been authorized.`);
  };

  const addToCart = (item: any) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { 
        id: item.id, 
        name: item.name || item.title, 
        price: item.price, 
        image: item.image, 
        quantity: 1,
        type: item.title ? 'course' : 'product'
      }];
    });
  };

  const handleBookingConfirm = async (appointment: Appointment) => {
    // Optimistic update
    setBookings(prev => [appointment, ...prev]);
    await saveData('bookings', appointment.id, appointment);
    sendNotification(
      "Reservation Confirmed ✨",
      `Your session for ${appointment.serviceName} is secured for ${appointment.date} at ${appointment.time}.`
    );
  };

  const handleOrderConfirm = async (order: Order) => {
    // Optimistic update
    setOrders(prev => [order, ...prev]);
    setCartItems([]);
    await saveData('orders', order.id, order);
    sendNotification(
      "Luxury Order Placed 🛍️",
      `Thank you ${order.clientName}! Your order #${order.id.slice(-6)} is being prepared for perfection.`
    );
  };

  const handleFeedbackSubmit = async (fb: Feedback) => {
    // Optimistic update
    setFeedbacks(prev => [fb, ...prev]);
    await saveData('feedbacks', fb.id, fb);
  };

  const openWhatsApp = () => {
    window.open('https://wa.me/923134528585', '_blank');
  };

  if (isSplashing) {
    return <SplashScreen onFinish={handleSplashFinish} />;
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return (
      <AdminPanel 
        isFullPanel 
        onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }}
        data={{ services, products, courses, videos, gallery, bookings, orders, feedbacks }}
        setters={{ setServices, setProducts, setCourses, setVideos, setGallery, setBookings, setOrders, setFeedbacks }}
      />
    );
  }

  const renderScreen = () => {
    if (showLogin) return <LoginScreen onLogin={handleLogin} onBack={() => setShowLogin(false)} />;
    if (showCart) return <CartScreen items={cartItems} onBack={() => setShowCart(false)} onRemove={(id) => setCartItems(p => p.filter(i => i.id !== id))} onUpdateQty={(id, d) => setCartItems(p => p.map(i => i.id === id ? {...i, quantity: Math.max(1, i.quantity+d)} : i))} onCheckout={() => { setShowCart(false); setCheckoutItem(cartItems); }} />;
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} onComplete={handleOrderConfirm} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} onConfirm={handleBookingConfirm} />;
    if (showFeedback) return <FeedbackScreen onBack={() => setShowFeedback(false)} onSubmit={handleFeedbackSubmit} />;
    if (selectedServiceDetail) return <ServiceDetailScreen service={selectedServiceDetail} onBack={() => setSelectedServiceDetail(null)} onBook={(s) => { setSelectedServiceDetail(null); setBookingService(s); }} />;
    if (selectedProductDetail) return <ProductDetailScreen product={selectedProductDetail} onBack={() => setSelectedProductDetail(null)} onAddToCart={addToCart} />;
    if (selectedCourseDetail) return <CourseDetailScreen course={selectedCourseDetail} onBack={() => setSelectedCourseDetail(null)} onEnroll={addToCart} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} onOpenFeedback={() => setShowFeedback(true)} feedbacks={feedbacks} />;
      case 'services': return <ServicesScreen services={services} onBook={(s) => setBookingService(s)} onViewDetails={(s) => setSelectedServiceDetail(s)} />;
      case 'store': return <StoreScreen products={products} courses={courses} onAddToCart={addToCart} onViewProduct={setSelectedProductDetail} onViewCourse={setSelectedCourseDetail} />;
      case 'viral': return <ViralScreen videos={videos} onBook={(sId) => {
        const found = services.find(s => s.id === sId);
        if (found) setBookingService(found);
      }} />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen gallery={gallery} />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} featuredServices={services} onOpenFeedback={() => setShowFeedback(true)} feedbacks={feedbacks} />;
    }
  };

  const showGlobalUI = !checkoutItem && !bookingService && !showCart && !selectedServiceDetail && !selectedProductDetail && !selectedCourseDetail && !showFeedback && !showLogin;
  const isViralTab = activeTab === 'viral' && showGlobalUI;

  return (
    <div className="min-h-screen green-gradient flex flex-col font-sans">
      {/* Show header on all main tabs including viral, only hide when logging in */}
      {!showLogin && (
        <Header 
          cartCount={cartItems.reduce((acc, i) => acc + i.quantity, 0)} 
          onCartClick={() => setShowCart(true)} 
          onMenuOpen={() => setIsMenuOpen(true)}
          onProfileClick={() => setShowLogin(true)}
          onAdminTrigger={handleAdminTrigger}
          user={user}
        />
      )}

      {syncing && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] bg-[#F7E7CE] text-[#0A2419] px-4 py-1.5 rounded-full text-[8px] font-black uppercase flex items-center gap-2 shadow-2xl animate-bounce">
          <RefreshCw size={12} className="animate-spin" /> Syncing Cloud Data
        </div>
      )}

      {/* 
        Changes:
        - If isViralTab: using 'p-0' so content starts at top (0px), behind the fixed header. 
        - Removed 'pt-16' which was pushing video down.
      */}
      <main className={`flex-1 ${isViralTab ? 'p-0 bg-black' : 'pt-20 px-4'} max-w-lg mx-auto w-full no-scrollbar overflow-y-auto animate-royal`}>
        {renderScreen()}
        {!isViralTab && showGlobalUI && <div className="h-20" />}
      </main>

      {showGlobalUI && (
        <>
          <LuxuryMenu 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            isOpen={isMenuOpen} 
            setIsOpen={setIsMenuOpen} 
            services={services}
            products={products}
            onServiceSelect={(s) => setSelectedServiceDetail(s)}
            onProductSelect={(p) => setSelectedProductDetail(p)}
          />
          {!isViralTab && (
            <button 
              onClick={openWhatsApp}
              className="fixed bottom-10 right-6 z-[50] w-14 h-14 bg-white/5 border border-white/10 text-[#F7E7CE] rounded-full flex items-center justify-center shadow-2xl backdrop-blur-md active:scale-90 transition-all hover:scale-110"
              aria-label="Connect on WhatsApp"
            >
              <MessageCircle size={28} />
            </button>
          )}
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Heart, Disc, Volume2, VolumeX, ShoppingBag } from 'lucide-react';
import { VideoItem } from '../types';

interface ViralScreenProps {
  videos: VideoItem[];
  onBook: (serviceId: string) => void;
}

const ViralScreen: React.FC<ViralScreenProps> = ({ videos, onBook }) => {
  const [muted, setMuted] = useState(true);
  const [likedVideos, setLikedVideos] = useState<Set<string>>(new Set());
  const [showHeartBurst, setShowHeartBurst] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleToggleLike = (id: string) => {
    setLikedVideos(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else {
        next.add(id);
        setShowHeartBurst(id);
        setTimeout(() => setShowHeartBurst(null), 800);
      }
      return next;
    });
  };

  const handleDoubleTap = (id: string) => {
    if (!likedVideos.has(id)) {
      handleToggleLike(id);
    } else {
      setShowHeartBurst(id);
      setTimeout(() => setShowHeartBurst(null), 800);
    }
  };

  return (
    <div 
      ref={containerRef}
      // Changed h-full to h-screen to force it to take full screen height regardless of parent padding
      className="relative w-full h-screen snap-y snap-mandatory overflow-y-scroll no-scrollbar bg-black"
    >
      {videos.length === 0 && (
        <div className="h-full flex flex-col items-center justify-center text-[#F7E7CE]/40 italic uppercase tracking-widest text-[10px]">
          Aneela is curating new masterpieces...
        </div>
      )}

      {videos.map((vid) => (
        <div key={vid.id} className="relative w-full h-full snap-start bg-black overflow-hidden flex flex-col justify-end">
          {/* Video Element */}
          <div 
            className="absolute inset-0 z-0"
            onClick={(e) => {
              if (e.detail === 2) handleDoubleTap(vid.id);
              else setMuted(!muted);
            }}
          >
            {vid.url ? (
              <video 
                src={vid.url}
                className="w-full h-full object-cover"
                autoPlay
                loop
                muted={muted}
                playsInline
              />
            ) : (
              <img src={vid.thumbnail} className="w-full h-full object-cover brightness-50" alt="" />
            )}

            {/* Overlay Gradient */}
            <div className="absolute inset-0 bg-gradient-to-t from-[#0A2419]/90 via-transparent to-transparent pointer-events-none"></div>

            {/* Mute Indicator */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-0 animate-pulse">
               {muted ? <VolumeX className="text-white/50" size={60} /> : <Volume2 className="text-white/50" size={60} />}
            </div>
          </div>

          {/* Heart Burst Animation */}
          {showHeartBurst === vid.id && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-30">
              <Heart 
                size={120} 
                className="text-[#F7E7CE] animate-[ping_0.8s_ease-out_forwards] fill-[#F7E7CE] drop-shadow-[0_0_20px_rgba(247,231,206,0.6)]" 
              />
            </div>
          )}

          {/* Video Information Overlay */}
          <div className="relative p-6 z-10 w-full">
            <div className="flex flex-col mb-4">
               <h4 className="text-xl font-bold text-white serif tracking-wide drop-shadow-md mb-1">{vid.title}</h4>
               <p className="text-[11px] text-[#F7E7CE] leading-relaxed mb-3 line-clamp-2 italic drop-shadow-sm">
                 {vid.description || "Witness the perfection of every stroke."}
               </p>

               {/* Music Ticker */}
               <div className="flex items-center gap-2 overflow-hidden w-[200px]">
                 <Disc size={12} className="text-[#F7E7CE] animate-spin shrink-0" />
                 <div className="whitespace-nowrap animate-[marquee_10s_linear_infinite] text-[9px] text-[#F7E7CE]/80 font-medium uppercase tracking-[0.2em]">
                   {vid.musicTrack || "Original Sound - Aneelas Viral Studio"} &bull; {vid.musicTrack || "Original Sound - Aneelas Viral Studio"}
                 </div>
               </div>
            </div>

            <div className="flex items-center gap-3">
              {vid.linkedServiceId && (
                <button 
                  onClick={() => onBook(vid.linkedServiceId!)}
                  className="bg-[#E1B84F] text-[#0A2419] px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] shadow-2xl flex items-center gap-2 active:scale-95 transition-all"
                >
                  Book This Look <ShoppingBag size={14} />
                </button>
              )}
            </div>
          </div>

          {/* Progress Bar */}
          <div className="absolute bottom-0 left-0 h-0.5 bg-white/10 w-full z-30">
             <div className="h-full bg-[#E1B84F] shadow-[0_0_10px_#E1B84F] animate-[progress_15s_linear_infinite]"></div>
          </div>
        </div>
      ))}

      <style>{`
        @keyframes marquee {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
        @keyframes progress {
          0% { width: 0%; }
          100% { width: 100%; }
        }
        .font-montserrat {
          font-family: 'Montserrat', sans-serif;
        }
      `}</style>
    </div>
  );
};

export default ViralScreen;

import React, { useState, useMemo } from 'react';
import { X, Home, Scissors, ShoppingBag, Zap, Image, Sparkles, Crown, Search, ArrowRight } from 'lucide-react';
import { Service, Product } from '../types';

interface LuxuryMenuProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  isOpen: boolean;
  setIsOpen: (open: boolean) => void;
  services: Service[];
  products: Product[];
  onServiceSelect: (s: Service) => void;
  onProductSelect: (p: Product) => void;
}

const LuxuryMenu: React.FC<LuxuryMenuProps> = ({ 
  activeTab, 
  setActiveTab, 
  isOpen, 
  setIsOpen, 
  services, 
  products,
  onServiceSelect,
  onProductSelect
}) => {
  const [searchQuery, setSearchQuery] = useState('');

  const menuItems = useMemo(() => [
    { id: 'home', icon: <Home size={22} />, label: 'Home Studio' },
    { id: 'services', icon: <Scissors size={22} />, label: 'Master Salon' },
    { id: 'store', icon: <ShoppingBag size={22} />, label: 'Luxury Items' },
    { id: 'viral', icon: <Zap size={22} />, label: 'Viral Studio' },
    { id: 'ai', icon: <Sparkles size={22} />, label: 'AI Concierge' },
    { id: 'gallery', icon: <Image size={22} />, label: 'The Gallery' },
  ], []);

  const searchResults = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) return { services: [], products: [], menu: menuItems };

    return {
      services: services.filter(s => 
        s.name.toLowerCase().includes(query) || 
        s.category.toLowerCase().includes(query) ||
        s.description.toLowerCase().includes(query)
      ).slice(0, 5),
      products: products.filter(p => 
        p.name.toLowerCase().includes(query) || 
        p.category.toLowerCase().includes(query)
      ).slice(0, 5),
      menu: menuItems.filter(m => m.label.toLowerCase().includes(query))
    };
  }, [searchQuery, services, products, menuItems]);

  const handleSelect = (id: string) => {
    setActiveTab(id);
    setSearchQuery('');
    setIsOpen(false);
  };

  const handleResultClick = (item: any, type: 'service' | 'product') => {
    if (type === 'service') onServiceSelect(item);
    else onProductSelect(item);
    setSearchQuery('');
    setIsOpen(false);
  };

  const handleClose = (e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    setIsOpen(false);
    setSearchQuery('');
  };

  return (
    <div className={`fixed inset-0 z-[120] transition-opacity duration-200 ${isOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
      {/* Blurred Backdrop - Click to Close */}
      <div 
        className="absolute inset-0 bg-[#0A2419]/98 backdrop-blur-3xl" 
        onClick={() => handleClose()}
      ></div>

      {/* Luxury Patterns */}
      <div className="absolute inset-0 opacity-5 pointer-events-none overflow-hidden">
        <Crown size={400} className="absolute -top-20 -right-20 text-[#F7E7CE]" />
        <Crown size={300} className="absolute -bottom-20 -left-20 text-[#F7E7CE]" />
      </div>

      {/* Close Button - Optimized positioning for visibility and reach */}
      <div className="absolute top-12 right-6 z-[130]">
        <button 
          onClick={handleClose}
          className="w-12 h-12 rounded-full border border-[#F7E7CE]/40 flex items-center justify-center text-[#F7E7CE] bg-[#124C34]/80 backdrop-blur-xl active:scale-90 transition-all hover:bg-[#F7E7CE] hover:text-[#0A2419] shadow-2xl border-2"
        >
          <X size={24} strokeWidth={2.5} />
        </button>
      </div>

      <div className="relative h-full flex flex-col items-center justify-start px-8 z-[125] pt-28">
        {/* Search Bar inside Menu */}
        <div className={`w-full max-w-xs mb-8 transition-transform duration-200 ${isOpen ? 'translate-y-0 opacity-100' : 'translate-y-5 opacity-0'}`}>
          <div className="relative group">
            <Search className={`absolute left-5 top-1/2 -translate-y-1/2 transition-colors ${searchQuery ? 'text-[#F7E7CE]' : 'text-[#F7E7CE]/40'}`} size={20} />
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search perfection..." 
              className="w-full bg-white/5 border border-white/20 rounded-2xl py-5 pl-14 pr-12 text-sm text-white placeholder:text-[#F7E7CE]/20 outline-none focus:border-[#F7E7CE]/50 transition-all shadow-inner focus:bg-white/[0.08]"
            />
            {searchQuery && (
              <button 
                onClick={() => setSearchQuery('')}
                className="absolute right-4 top-1/2 -translate-y-1/2 text-[#F7E7CE]/40 hover:text-[#F7E7CE] transition-colors p-2"
              >
                <X size={16} />
              </button>
            )}
          </div>
        </div>

        {/* Scrollable Content Area */}
        <div className="w-full max-w-xs overflow-y-auto no-scrollbar max-h-[65vh] py-2 flex flex-col gap-6 pb-20">

          {/* Search Content Results */}
          {searchQuery.trim() && (searchResults.services.length > 0 || searchResults.products.length > 0) && (
            <div className="flex flex-col gap-3 animate-in fade-in slide-in-from-top-4 duration-200">
               <h4 className="text-[10px] font-black text-[#F7E7CE]/60 uppercase tracking-[0.4em] pl-2 mb-1">Matches</h4>

               {/* Service Results */}
               {searchResults.services.map(s => (
                 <button 
                   key={s.id} 
                   onClick={() => handleResultClick(s, 'service')}
                   className="flex items-center gap-4 bg-white/5 p-4 rounded-3xl border border-white/10 hover:border-[#F7E7CE]/50 transition-all text-left group/item active:scale-[0.98]"
                 >
                   <div className="w-10 h-10 rounded-xl overflow-hidden border border-white/10 shrink-0">
                    <img src={s.image} className="w-full h-full object-cover" />
                   </div>
                   <div className="flex-1 min-w-0">
                     <p className="text-[11px] font-bold text-white truncate uppercase tracking-tight">{s.name}</p>
                     <p className="text-[8px] text-[#F7E7CE]/60 font-medium uppercase tracking-widest mt-0.5">Salon</p>
                   </div>
                   <ArrowRight size={14} className="text-[#F7E7CE]/30 group-hover/item:translate-x-1 transition-all" />
                 </button>
               ))}

               {/* Product Results */}
               {searchResults.products.map(p => (
                 <button 
                   key={p.id} 
                   onClick={() => handleResultClick(p, 'product')}
                   className="flex items-center gap-4 bg-white/5 p-4 rounded-3xl border border-white/10 hover:border-[#F7E7CE]/50 transition-all text-left group/item active:scale-[0.98]"
                 >
                   <div className="w-10 h-10 rounded-xl overflow-hidden border border-white/10 shrink-0">
                    <img src={p.image} className="w-full h-full object-cover" />
                   </div>
                   <div className="flex-1 min-w-0">
                     <p className="text-[11px] font-bold text-white truncate uppercase tracking-tight">{p.name}</p>
                     <p className="text-[8px] text-[#F7E7CE]/60 font-medium uppercase tracking-widest mt-0.5">Luxury Items</p>
                   </div>
                   <ArrowRight size={14} className="text-[#F7E7CE]/30 group-hover/item:translate-x-1 transition-all" />
                 </button>
               ))}
            </div>
          )}

          {/* Navigation Links */}
          <div className="flex flex-col items-center gap-4 w-full">
            {searchQuery.trim() && searchResults.menu.length === 0 && searchResults.services.length === 0 && searchResults.products.length === 0 && (
              <div className="py-10 text-center animate-in fade-in duration-200">
                <p className="text-[10px] text-white/30 tracking-[0.2em] uppercase">No results found</p>
                <button onClick={() => setSearchQuery('')} className="mt-4 text-[9px] text-[#F7E7CE]/60 font-black uppercase underline tracking-[0.3em]">Clear Search</button>
              </div>
            )}

            {!searchQuery.trim() && <h4 className="text-[9px] font-black text-[#F7E7CE]/40 uppercase tracking-[0.4em] mb-1 w-full text-center">Navigation</h4>}

            {searchResults.menu.map((item, index) => (
              <button
                key={item.id}
                onClick={() => handleSelect(item.id)}
                className={`flex items-center gap-6 w-full group transition-all duration-200 ${isOpen ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0'}`}
                style={{ transitionDelay: `${index * 50}ms` }}
              >
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all duration-200 ${activeTab === item.id ? 'gold-gradient text-[#0A2419] shadow-xl scale-110' : 'bg-white/5 text-[#F7E7CE]/40 group-hover:text-[#F7E7CE] group-hover:bg-white/10 shadow-md'}`}>
                  {React.cloneElement(item.icon as React.ReactElement, { size: 24 })}
                </div>
                <div className="text-left">
                  <h3 className={`text-xl font-bold serif transition-colors ${activeTab === item.id ? 'text-[#F7E7CE]' : 'text-white/80 group-hover:text-[#F7E7CE]'}`}>
                    {item.label}
                  </h3>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Branding Footer */}
      <div className="absolute bottom-10 left-0 right-0 text-center pointer-events-none opacity-20">
        <p className="text-[10px] text-[#F7E7CE] uppercase tracking-[0.5em] font-black">
          Aneela's MakeOver
        </p>
      </div>
    </div>
  );
};

export default LuxuryMenu;

